const GRADE_TITLES={
  A:['Market Dominator','The Legend','Top Dog','Untouchable'],
  B:['Strong Performer','Solid Operator','Market Player','The Pro'],
  C:['Middling Manager','Surviving','Holding On','In the Pack'],
  D:['Struggling Broadcaster','Barely Afloat','On the Bubble','Under Pressure'],
  F:['Station Failure','Going Dark','Distress Sale','Bankrupt'],
};
const DECADE_NAMES={1979:'THE SEVENTIES',1989:'THE EIGHTIES',1999:'THE NINETIES',2009:'THE 2000s',2019:'THE 2010s',2020:'THE FULL ERA'};

// ── TALENT & GENERATION ───────────────────────────────────────────
/** Free-agent ask ranges by daypart × tier ($/yr, pre-inflation). Wider bands = more “shopping” feel; still ordered star > mid > entry. */
const SAL={morningDrive:{entry:[9500,24000],mid:[19000,42000],star:[32000,75000]},afternoonDrive:{entry:[7500,20000],mid:[14000,34000],star:[24000,58000]},midday:{entry:[6000,16000],mid:[11000,28000],star:[18000,42000]},evening:{entry:[5000,13000],mid:[8500,24000],star:[15000,34000]},overnight:{entry:[4000,10000],mid:[6500,18000],star:[11000,26000]}};
/** True on-air quality bands (scouting noise layered on top; pool skews middling vs legacy). */
const QRG={entry:[24,52],mid:[36,66],star:[50,82]};
/** Periods on-air (~4 calendar years at 2 periods/yr) to fold hidden performance into slot quality. */
const TALENT_REVEAL_PERIODS=8;
function clampTalentFit01(v){
  return Math.max(0.08,Math.min(0.98,typeof v==='number'&&!Number.isNaN(v)?v:0.3));
}
/** Actual ability (internal ratings / salary merit); falls back to visible scout rating for legacy saves. */
function talentTrueQuality(t){
  if(t&&typeof t._trueQuality==='number'&&!Number.isNaN(t._trueQuality))return Math.round(t._trueQuality);
  return Math.round(t?.quality||0);
}
function talentTrueFormatFit(t,fmt){
  if(!t||!fmt)return clampTalentFit01(undefined);
  const read=(key)=>{
    const m=t._trueFormatFit;
    if(m&&typeof m[key]==='number'&&!Number.isNaN(m[key]))return m[key];
    const f=t.formatFit;
    if(f&&typeof f[key]==='number'&&!Number.isNaN(f[key]))return f[key];
    return undefined;
  };
  let v=read(fmt);
  if(v==null&&isHitsFormatLineage(fmt)){
    const alt=fmt==='CHR'?'TOP40':fmt==='TOP40'?'CHR':null;
    if(alt)v=read(alt);
  }
  return clampTalentFit01(v);
}
/** Scout `formatFit` vs station format — CHR/TOP40 save drift won’t zero out fit in hire UI / doHire. */
function talentScoutFormatFit01(t,stationFormat){
  if(!t?.formatFit||!stationFormat)return 0.3;
  let v=t.formatFit[stationFormat];
  if(typeof v!=='number'||Number.isNaN(v)){
    const alt=canonicalHitsFormatKey(stationFormat);
    if(alt!==stationFormat)v=t.formatFit[alt];
  }
  if(typeof v!=='number'||Number.isNaN(v))return 0.3;
  return clampTalentFit01(v);
}
/** Rounded delta (slot quality points) between true vs scouted contribution for this station format. */
function talentPerformanceRevealDeltaForStation(fmt,t,kind){
  const sq=Math.round(t.quality||0), tq=talentTrueQuality(t);
  const sf=clampTalentFit01(t.formatFit?.[fmt]), tf=talentTrueFormatFit(t,fmt);
  if(kind==='xfer'){
    const scout=(sq/100)*sf*0.35*18, tru=(tq/100)*tf*0.35*18;
    return Math.round(tru-scout);
  }
  const scout=(sq/100)*sf*35, tru=(tq/100)*tf*35;
  return Math.round(tru-scout);
}
/** After hire / shuffle / xfer, schedule gradual slot-quality drift toward true performance. */
function initTalentPerformanceReveal(sd,t,fmt,kind){
  if(!sd||!t)return;
  const d=talentPerformanceRevealDeltaForStation(fmt,t,kind);
  if(!d){
    t._perfRevealStepsLeft=0;
    t._perfRevealDeltaRemaining=0;
    t._talentPerfRevealed=true;
    return;
  }
  t._perfRevealStepsLeft=TALENT_REVEAL_PERIODS;
  t._perfRevealDeltaRemaining=d;
  t._talentPerfRevealed=false;
}
function applyTalentPerformanceRevealDecayStep(sd,vtStress){
  const t=sd?.talent;
  if(!t)return;
  const left=t._perfRevealStepsLeft|0;
  if(left<1)return;
  const rem=t._perfRevealDeltaRemaining|0;
  if(!rem)return;
  const vt=Math.max(0,Math.min(1,Number(vtStress)||0));
  const vtK=1-0.072*vt;
  let step=Math.round((rem/left)*vtK);
  if(step===0)step=rem>0?1:(rem<0?-1:0);
  if(step===0)return;
  t._perfRevealDeltaRemaining=rem-step;
  t._perfRevealStepsLeft=left-1;
  if(t._perfRevealStepsLeft===0)t._talentPerfRevealed=true;
  sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)+step)));
}
/** Optional co-host: chemistry-led pairing (morning + afternoon drive only). */
const COHOST_CHEM_REVEAL_PERIODS=8;
const COHOST_SLOT_STRENGTH={morningDrive:1,afternoonDrive:0.42,midday:0,evening:0,overnight:0};
function daypartAllowsCoHostModel(sl){
  return(sl==='morningDrive'||sl==='afternoonDrive');
}
/** Second on-air talent in a dual daypart (`talentB`). Legacy saves may still use `coHost`. */
function slotTalentB(sd){
  if(!sd)return null;
  return sd.talentB!=null?sd.talentB:(sd.coHost||null);
}
function setSlotTalentB(sd,t){
  if(!sd)return;
  if(t){ sd.talentB=t; delete sd.coHost; }
  else { delete sd.talentB; delete sd.coHost; }
}
/** When chair A is cleared but chair B remains, promote B into `talent` so slots stay consistent. */
function promoteSlotChairBtoAIfNeeded(sd,sl){
  if(!sd||sd.talent)return;
  const b=slotTalentB(sd);
  if(!b)return;
  if(sl&&!daypartAllowsCoHostModel(sl)){setSlotTalentB(sd,null);return;}
  setSlotTalentB(sd,null);
  sd.talent=b;
  clearPairingChemistryOnly(sd);
}
/** Canonical order for pairing chemistry / scout hash so chair assignment does not flip the model. */
function pairingChemTalentOrder(ta,tb){
  if(!ta||!tb)return[ta,tb];
  const ka=String(ta.id||'')+'\t'+normTalentNameKey(ta.name||'');
  const kb=String(tb.id||'')+'\t'+normTalentNameKey(tb.name||'');
  return ka<=kb?[ta,tb]:[tb,ta];
}
function migrateLegacyCoHostKeysToTalentB(G){
  (G.stations||[]).forEach(s=>{
    if(!s?.prog)return;
    DAYPART_SLOTS.forEach(sl=>{
      const sd=s.prog[sl];
      if(!sd)return;
      const leg=sd.coHost;
      if(leg&&!sd.talentB){ sd.talentB=leg; delete sd.coHost; }
      if(!daypartAllowsCoHostModel(sl)&&(sd.talentB||sd.coHost)){
        setSlotTalentB(sd,null);
        clearPairingChemistryOnly(sd);
      }
    });
  });
}
/** Revert slot-quality estimate from pairing + delete chemistry metadata only (does not remove on-air talent). */
function clearPairingChemistryOnly(sd){
  if(!sd)return;
  const adj=sd._cohostSlotAdjApplied|0;
  if(adj){
    sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)-adj)));
    delete sd._cohostSlotAdjApplied;
  }
  delete sd._cohostChemActual;
  delete sd._cohostChemEstimate;
  delete sd._cohostChemRevealStepsLeft;
  delete sd._cohostChemRevealRem;
  delete sd._cohostChemRevealed;
}
function cohostPersonalityFormatMult(fmt){
  if(TALK_FMTS.includes(fmt)||fmt==='ALL_NEWS')return 1.08;
  return 0.86;
}
function daypartCoHostModelStrength(sl,fmt){
  const w=COHOST_SLOT_STRENGTH[sl]||0;
  if(w<=0)return 0;
  return w*cohostPersonalityFormatMult(fmt);
}
function talentChemEff01(t,fmt){
  if(!t||!fmt)return 0.35;
  return Math.max(0.08,Math.min(1,(talentTrueQuality(t)/100)*talentTrueFormatFit(t,fmt)));
}
function rollCoHostChemistryPair(primary,cohost,fmt){
  const [p,c]=pairingChemTalentOrder(primary,cohost);
  const ep=talentChemEff01(p,fmt);
  const ec=talentChemEff01(c,fmt);
  const sim=1-Math.min(1,Math.abs(ep-ec)/0.82);
  const style=(ep+ec)*0.5;
  const noise=(Math.random()*2-1)*0.26;
  const base=sim*0.52+style*0.26-0.20+noise;
  const actual=Math.max(-1,Math.min(1,base));
  const estNoise=(Math.random()*2-1)*0.19;
  const estimate=Math.max(-1,Math.min(1,actual+estNoise));
  return{actual,estimate};
}
/** Deterministic chemistry preview for hire UI (stable; actual pairing still rolled at hire). */
function cohostChemistryScoutPreview01(primary,cohost,fmt){
  const [a,b]=pairingChemTalentOrder(primary,cohost);
  const ep=talentChemEff01(a,fmt);
  const ec=talentChemEff01(b,fmt);
  const sim=1-Math.min(1,Math.abs(ep-ec)/0.82);
  const style=(ep+ec)*0.5;
  const idLo=String(Math.min(Number(a.id)||0,Number(b.id)||0));
  const idHi=String(Math.max(Number(a.id)||0,Number(b.id)||0));
  const h=wlHash32(`${idLo}|${idHi}|${normTalentNameKey(a.name||'')}|${normTalentNameKey(b.name||'')}|${fmt}|chemscout`);
  const n=(h%2001)/2000-0.5;
  const est=sim*0.52+style*0.26-0.20+n*0.24;
  return Math.max(-1,Math.min(1,est));
}
function coHostSlotQualityDeltaPts(primary,cohost,fmt,sl,chem){
  const str=daypartCoHostModelStrength(sl,fmt);
  if(str<=0||!primary||!cohost||typeof chem!=='number'||Number.isNaN(chem))return 0;
  const [p,c]=pairingChemTalentOrder(primary,cohost);
  const ep=talentChemEff01(p,fmt);
  const ec=talentChemEff01(c,fmt);
  const blend=0.5*ep+0.5*ec;
  const anchor=(blend-0.44)*2.6*str;
  const chemSwing=chem*7.0*str;
  const d=anchor+chemSwing;
  return Math.max(-13.5,Math.min(10.2,d));
}
function chemistryEstimateLabel01(est){
  if(est<-0.34)return'Weak';
  if(est<-0.07)return'Fair';
  if(est<0.20)return'Good';
  return'Great';
}
function clearCoHostPairingState(sd){
  clearPairingChemistryOnly(sd);
}
/** Bench second-chair only (no `mpIsMe` check). Used by multiplayer apply and {@link benchCoHostIfPresentInternal}. */
function benchSecondChairTalentCore(sid,slot,benchOwnerMpId){
  const s=G.stations.find(st=>st.id===sid);
  if(!s)return false;
  const sd=s.prog?.[slot];
  const b=slotTalentB(sd);
  if(!b)return false;
  ensureTalentBench(G);
  G._benchSeq=(G._benchSeq||0)+1;
  const benchId='b'+G._benchSeq;
  const owner=benchOwnerMpId|0;
  G.talentBench.push({id:benchId,talent:b,_mpOwner:owner,sid,slot});
  setSlotTalentB(sd,null);
  clearPairingChemistryOnly(sd);
  refreshStationOQ(s,G);
  return true;
}
/** Bench second-chair talent only; clears pairing chemistry on the slot. */
function benchCoHostIfPresentInternal(sid,slot){
  const s=G.stations.find(st=>st.id===sid);
  if(!s||!mpIsMe(s))return false;
  const owner=MP.mode==='live'?(s._mpOwner!=null?s._mpOwner:MP.playerId):0;
  return benchSecondChairTalentCore(sid,slot,owner);
}
function initCoHostChemistryReveal(sd,fmt,sl,primary,cohost,chemRoll){
  if(!sd||!primary||!cohost||!chemRoll)return;
  sd._cohostChemActual=chemRoll.actual;
  sd._cohostChemEstimate=chemRoll.estimate;
  const [p,c]=pairingChemTalentOrder(primary,cohost);
  const estPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,chemRoll.estimate));
  const actPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,chemRoll.actual));
  sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)+estPts)));
  sd._cohostSlotAdjApplied=estPts;
  const d=actPts-estPts;
  if(!d){
    sd._cohostChemRevealStepsLeft=0;
    sd._cohostChemRevealRem=0;
    sd._cohostChemRevealed=true;
  }else{
    sd._cohostChemRevealStepsLeft=COHOST_CHEM_REVEAL_PERIODS;
    sd._cohostChemRevealRem=d;
    sd._cohostChemRevealed=false;
  }
}
function applyCoHostChemistryRevealDecayStep(sd,vtStress){
  if(!sd?.talent||!slotTalentB(sd))return;
  const left=sd._cohostChemRevealStepsLeft|0;
  if(left<1)return;
  const rem=sd._cohostChemRevealRem|0;
  if(!rem)return;
  const vt=Math.max(0,Math.min(1,Number(vtStress)||0));
  const vtK=1-0.065*vt;
  let step=Math.round((rem/left)*vtK);
  if(step===0)step=rem>0?1:(rem<0?-1:0);
  if(step===0)return;
  sd._cohostChemRevealRem=rem-step;
  sd._cohostChemRevealStepsLeft=left-1;
  if(sd._cohostChemRevealStepsLeft===0)sd._cohostChemRevealed=true;
  sd.quality=Math.min(100,Math.max(10,Math.round((sd.quality||20)+step)));
  sd._cohostSlotAdjApplied=(sd._cohostSlotAdjApplied|0)+step;
}
/** Small station-level franchise softening when a revealed co-host pairing is toxic (personality-heavy slots). */
function stationCoHostFranchiseSoftPenalty(s){
  if(!s?.prog)return 0;
  let pen=0;
  DAYPART_SLOTS.forEach(sl=>{
    const sd=s.prog[sl];
    if(!sd?.talent||!slotTalentB(sd))return;
    if(!sd._cohostChemRevealed)return;
    const chem=sd._cohostChemActual;
    if(typeof chem!=='number'||Number.isNaN(chem)||chem>=0)return;
    const str=daypartCoHostModelStrength(sl,s.format);
    if(str<=0)return;
    pen+=-chem*0.042*str;
  });
  return Math.min(0.09,pen);
}
function payrollHalfPeriodForDaypartSlot(sd){
  let row=0;
  if(sd?.talent)row+=Math.round((sd.talent.salary||0)/2);
  const b=slotTalentB(sd);
  if(b)row+=Math.round((b.salary||0)/2);
  return row;
}
/** Sum of host + co-host annual salaries ($/yr), then rounded to nearest $500 (portfolio display / financials). */
function roundTotalAnnualTalentPay500(n){
  n=Number(n);
  if(!Number.isFinite(n))return 0;
  return Math.round(n/500)*500;
}
function sumAnnualTalentPayrollForOwnedStations(ps){
  if(!ps||!ps.length)return 0;
  let tot=0;
  for(let i=0;i<ps.length;i++){
    const s=ps[i];
    if(!s?.prog)continue;
    for(const k of Object.keys(s.prog)){
      const sd=s.prog[k];
      if(!sd)continue;
      if(sd.talent){
        const v=Number(sd.talent.salary);
        if(Number.isFinite(v))tot+=v;
      }
      const b=slotTalentB(sd);
      if(b){
        const v2=Number(b.salary);
        if(Number.isFinite(v2))tot+=v2;
      }
    }
  }
  return roundTotalAnnualTalentPay500(tot);
}
function adjustCohostSalaryForRole(t,sl,G){
  if(!t)return;
  const mult=0.74;
  t.salary=Math.max(3500,Math.round((t.salary||0)*mult/500)*500);
  const tier=talentTrueQuality(t)<42?'entry':talentTrueQuality(t)<68?'mid':'star';
  const baseFl=Math.round(salInfl((SAL[sl]?.[tier]?.[0]||5000),G.year)*0.58/500)*500;
  if(t.salary<baseFl)t.salary=baseFl;
  const slotStarMax=({morningDrive:60000,afternoonDrive:42000,midday:28000,evening:22000,overnight:16000})[sl]||42000;
  const cap=Math.round(salInfl(Math.round(slotStarMax*0.62),G.year)/500)*500;
  if(t.salary>cap)t.salary=cap;
}
function debugCoHostDaypartDiag(s,sl){
  const sd=s?.prog?.[sl];
  const c=slotTalentB(sd);
  if(!sd?.talent||!c){
    console.warn('debugCoHostDaypartDiag: need station id, co-hosted slot',{sid:s?.id,sl});
    return null;
  }
  const fmt=s.format;
  const p=sd.talent;
  const str=daypartCoHostModelStrength(sl,fmt);
  const ep=talentChemEff01(p,fmt);
  const ec=talentChemEff01(c,fmt);
  const est=sd._cohostChemEstimate;
  const act=sd._cohostChemActual;
  const estPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,typeof est==='number'?est:0));
  const actPts=Math.round(coHostSlotQualityDeltaPts(p,c,fmt,sl,typeof act==='number'?act:0));
  const slotQ=Math.round(sd.quality||0);
  const out={
    slot:sl,call:s.callLetters,format:fmt,modelStrength:Math.round(str*1000)/1000,
    primaryHost:{name:p.name,contrib01:Math.round(ep*1000)/1000},
    coHost:{name:c.name,contrib01:Math.round(ec*1000)/1000},
    expectedChemLabel:chemistryEstimateLabel01(typeof est==='number'?est:0),
    expectedChem01:typeof est==='number'?Math.round(est*1000)/1000:null,
    actualChem01:typeof act==='number'?Math.round(act*1000)/1000:null,
    slotDeltaIfEstimatePts:estPts,slotDeltaIfActualPts:actPts,slotQuality:slotQ,
    slotAdjAppliedPts:sd._cohostSlotAdjApplied|0,
    revealStepsLeft:sd._cohostChemRevealStepsLeft|0,revealed:!!sd._cohostChemRevealed,
  };
  console.log('[cohostDiag]',out);
  return out;
}
window.debugCoHostDaypartDiag=function(sid,sl){
  const s=(typeof G!=='undefined'&&G?.stations&&sid)?G.stations.find(st=>st.id===sid):null;
  return debugCoHostDaypartDiag(s,sl);
};
