function showError(msg,detail){
  document.body.innerHTML=`<div style="padding:40px;font-family:monospace;color:#f87171;background:#0a0a0a;min-height:100vh">
    <div style="font-size:20px;margin-bottom:16px;color:#f5a623">⚠ AIRWAVE EMPIRE — STARTUP ERROR</div>
    <div style="font-size:14px;margin-bottom:12px">${msg}</div>
    <pre style="font-size:15px;color:#9ca3af;white-space:pre-wrap">${detail}</pre>
    <button onclick="wlClearAutosaveAndReload()" 
      style="margin-top:24px;background:#f5a623;color:#000;border:none;padding:10px 24px;font-family:monospace;font-size:14px;cursor:pointer">
      CLEAR SAVE &amp; RESTART
    </button>
  </div>`;
}

let _pendingScenId=null; // set during scenario selection before genMarket runs
/** 'entry' = play (continue / load / start new); 'modes' = tutorial / classic / campaign; 'solo' = market + scenario list */
let _scenView='entry';
function scenSetView(v){
  if(v!=='entry'&&v!=='modes'&&v!=='solo')return;
  _scenView=v;
  if(v!=='solo')_pendingScenId=null;
  openScenSelect(_lastScenSelectLocal,{onlyRefresh:true});
}
function scenStartTutorialFromMenu(){
  if(!Array.isArray(SC))return;
  if(!SC.find(s=>s.id==='tutorial_turnaround')){
    showToast('Guided tutorial isn’t in this build.','warn');
    return;
  }
  const m=(typeof _selectedMarket==='string'&&_selectedMarket)?_selectedMarket:'atlanta';
  if(!scenarioIdsForMarket(m).includes('tutorial_turnaround')){
    showToast('Guided tutorial isn’t available in this market — try Atlanta, or use START NEW GAME → Guided Tutorial after picking a supported market.','info',9000);
    scenSetView('modes');
    return;
  }
  _pendingScenId=null;
  if(typeof cm==='function')cm('m-scen');
  openOnboarding('tutorial_turnaround');
}
if(typeof window!=='undefined'){
  window.scenSetView=scenSetView;
  window.scenStartTutorialFromMenu=scenStartTutorialFromMenu;
}

/** Solo entry waits for this when play.html requires Clerk (default meta wl-require-clerk=1; see src/main.js). */
function init(){
  /** Long-run benchmark HTML: no scenario UI / autosave resume — harness owns G. */
  if (window.__WL_AI_BENCHMARK_PAGE__) return;
  /** Headless / tooling pages (e.g. inspect-shares.html) load legacy without scenario UI. */
  if (window.__WL_SHARE_INSPECT_ONLY) return;
  if(!window.__WL_REQUIRE_CLERK){
    initCore();
    return;
  }
  if(window.__wlBetaAuthUnlocked){
    initCore();
    return;
  }
  window.addEventListener('wl-beta-auth-ok', ()=>initCore(), {once:true});
}

function initCore(){
  try{wlInstallAutosaveFlush();}catch(_e){}
  console.log('[Airwave Empire] initCore() called');
  try{
    const local=getLocalSave();
    const g=local?.G;
    console.log('[Airwave Empire] localSave:', local ? `found (year=${g?.year}, sc=${g?.sc?.id}, cash=${g?.cash}, sc.cash=${g?.sc?.cash})` : 'none');
    // If localStorage has a real solo state blob, show scenario with RESUME (browser autosave is per-origin, not per dev server).
    // Old guard rejected bankrupt players (G.cash<0), $0 scenario starts, or missing G.sc.cash — those still must offer resume.
    const hasSoloState=!!(g && g.sc && (g.stations||[]).length>0 && g.year!=null);
    if(g && hasSoloState){
      const c=Number(g.cash), scC=g.sc&&g.sc.cash;
      if(!Number.isFinite(c)||(scC!=null&&!Number.isFinite(Number(scC)))){
        console.warn('[Airwave Empire] Autosave has odd cash fields; resume may still work after migrate.',{cash:g.cash,scCash:scC});
      }
    }
    console.log('[Airwave Empire] hasSoloState:', hasSoloState);
    if(hasSoloState){
      const sm=g.marketId;
      let mid=(sm&&PHASE1_MARKET_IDS.includes(sm))?sm:'atlanta';
      if(!wlGetAllowedPhase1MarketIds().includes(mid))mid='atlanta';
      _selectedMarket=mid;
      ACTIVE_MARKET=mid;
      syncMarketPopToMarket(mid);
      openScenSelect(local);
      return;
    }
    if(local){
      console.warn('[Airwave Empire] localStorage has data but no resumable G — fresh start. keys=',Object.keys(local));
    }
    openScenSelect(null);
  }catch(err){
    showError('Failed during init: '+err.message, err.stack||'');
  }
}

/** Header logo — solo: return to scenario picker. Autosaves first and dismisses first-turn tutorial overlay. */
function wlGoToScenarioSelectFromLogo(){
  if(typeof MP!=='undefined'&&MP.mode==='live'){
    showToast('To leave multiplayer, use the lobby / room controls. Scenario select is for solo play.','info');
    return;
  }
  if(typeof G==='undefined'||!G||!G.sc){
    openScenSelect(getLocalSave());
    return;
  }
  openGameConfirm({title:'LEAVE GAME',message:'Return to scenario select? Your progress is autosaved in this browser.',confirmLabel:'CONTINUE'},(ok)=>{
    if(!ok)return;
    try{
      if(typeof autoSave==='function')autoSave();
    }catch(_e){}
    wlFtTutorialStop({});
    document.querySelectorAll('.ov.on').forEach(el=>{el.classList.remove('on');});
    syncModalBodyScrollLock();
    if(G?.marketId&&PHASE1_MARKET_IDS.includes(G.marketId)){
      let mid=G.marketId;
      if(!wlGetAllowedPhase1MarketIds().includes(mid))mid='atlanta';
      _selectedMarket=mid;
      ACTIVE_MARKET=mid;
      syncMarketPopToMarket(mid);
    }
    openScenSelect(getLocalSave());
  });
}

function openScenSelect(localSave, opts){
  const _onlyRefresh=!!(opts&&opts.onlyRefresh);
  if(!_onlyRefresh) _scenView='entry';
  _pendingScenId=null;
  _lastScenSelectLocal=localSave||null;
  if(!_selectedMarket||!PHASE1_MARKET_IDS.includes(_selectedMarket)){
    _selectedMarket='atlanta';
    ACTIVE_MARKET='atlanta';
    syncMarketPopToMarket('atlanta');
  }
  const _allowMkt=wlGetAllowedPhase1MarketIds();
  const _allowMktSet=new Set(_allowMkt);
  if(_selectedMarket&&!_allowMktSet.has(_selectedMarket)){
    _selectedMarket='atlanta';
    ACTIVE_MARKET='atlanta';
    syncMarketPopToMarket('atlanta');
  }
  const hasSave=!!(localSave?.G?.year);
  const saveYear=localSave?.G?.year||null;
  const savePeriod=localSave?.G?.period===1?'Spring':'Fall';
  const saveLabel=localSave?.label||'';
  const saveScen=SC.find(s=>s.id===localSave?.G?.sc?.id);
  const rawSaveMkt=localSave?.G?.marketId;
  const saveMarketId=(rawSaveMkt&&PHASE1_MARKET_IDS.includes(rawSaveMkt))?rawSaveMkt:'atlanta';

  const allowed=new Set(scenarioIdsForMarket(_selectedMarket));
  const mktLabel=(MARKETS[_selectedMarket]||MARKETS.atlanta).label;
  const tutSc=SC.find(s=>s.id==='tutorial_turnaround');

  const eraGroups=[
    {label:'1970 — THE BEGINNING', ids:['under','gm_under','cntry','soul','stack','fmpn','wsb']},
    {label:'1978 — FM REVOLUTION', ids:['fmrev','acrise']},
    {label:'1985 — FORMAT WARS',   ids:['chrwar','amtalk']},
  ];
  const eraGroupsFiltered=eraGroups.map(era=>({...era,ids:era.ids.filter(id=>allowed.has(id))})).filter(era=>era.ids.length>0);

  const _allowGmScen=wlClerkPlanAllowsGmScenario();
  const _allowGmCamp=wlClerkPlanAllowsGmCampaign();
  const _planSlugScen=wlClerkPlanSlug();
  const diffHints={under:'Survival mode. Thin cash — morning slot empty; hire fast.',gm_under:'Same start as Underdog — plus General Manager job reviews on margin, revenue trend, and talent/franchise. Miss expectations too often and you are dismissed.',soul:'Strong cume; under-monetized. Grind sales and CPM.',fmpn:'Lean years 1970–72. Survive them and FM makes you wealthy.',cntry:'Profitable now. Erosion will catch up.',stack:'AM/FM combo. High ceiling, high overhead.',wsb:'Dominant now, eroding fast. Every format decision has a cost.',tutorial_turnaround:'Walkthrough — follow on-screen steps; finish anytime by playing normally after the last lesson.',fmrev:'Thin margins until 1980. Album Rock will make you rich if you survive.',acrise:'AC gets crowded fast. Brand loyalty is everything.',chrwar:'Three viable format bets. Only one will dominate.',amtalk:'Revenue cliff is coming. Move fast or move on.'};
  const makeCard=sc=>{
    const gmLocked=sc.id==='gm_under'&&!_allowGmScen;
    const diff=sc.diff||(sc.id==='under'||sc.id==='gm_under'||sc.id==='soul'||sc.id==='fmpn'||sc.id==='amtalk'||sc.id==='fmrev'?'HARD':sc.id==='cntry'||sc.id==='stack'||sc.id==='acrise'||sc.id==='chrwar'?'MEDIUM':'EASY');
    const diffCls=diff==='HARD'?'hard':diff==='MEDIUM'?'med':'easy';
    const stnInfo=sc.idx.length===2?'AM/FM Combo':'Single Station';
    const cashFmt=`${f$(scaledScenarioCash(sc.cash,_selectedMarket))} starting cash`;
    const hint=sc.hint||diffHints[sc.id]||'';
    const span=`${sc.startYear||1970}–2020`;
    const lockBadge=gmLocked?`<div style="font-size:12px;color:var(--amb);letter-spacing:1px;margin-bottom:4px">🔒 SUBSCRIBERS — Starter, Pro, or free trial</div>`:'';
    const cardClick=gmLocked?`onclick="event.preventDefault();wlLockedGmScenarioToast();return false;"`:`onclick="pickScen('${sc.id}')"`;
    const cardStyle=gmLocked?' style="opacity:0.55;cursor:not-allowed"':'';
    return `<div class="scn-card${gmLocked?' scn-card--locked':''}" id="scn-${sc.id}" ${cardClick}${cardStyle}>
      ${lockBadge}
      <div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:4px">
        <div class="scn-diff ${diffCls}">${diff}</div>
        <div style="font-family:var(--ft);font-size:15px;color:var(--mut);letter-spacing:1px;padding-top:2px">${span}</div>
      </div>
      <div class="scn-title">${sc.l.toUpperCase()}</div>
      <div class="scn-sub">${stnInfo} · ${mktLabel}, ${sc.startYear||1970}</div>
      <div class="scn-desc">${sc.d}</div>
      <div class="scn-stat">${cashFmt}</div>
      ${hint?`<div class="scn-stat" style="color:var(--amb);margin-top:5px;font-size:14px;font-style:italic">▶ ${hint}</div>`:''}
    </div>`;
  };
  const cards=eraGroupsFiltered.map(era=>{
    const eraCards=SC.filter(sc=>era.ids.includes(sc.id)).map(makeCard).join('');
    return `<div style="margin-bottom:24px">
      <div class="scen-era-header">${era.label}</div>
      <div style="display:flex;flex-direction:column;gap:12px">${eraCards}</div>
    </div>`;
  }).join('');

  const marketPicker=PHASE1_MARKET_IDS.map(id=>{
    const sel=_selectedMarket===id?' scen-mkt-on':'';
    const m=MARKETS[id];
    if(_allowMktSet.has(id))
      return `<button type="button" class="abt${sel}" style="font-size:13px;padding:6px 12px;letter-spacing:1px" onclick="pickMarketPhase1('${id}')">${m.label}</button>`;
    let lockTitle='Upgrade in Account to play this market.';
    if(_planSlugScen==='free_user')lockTitle='Upgrade in Account to play markets beyond Atlanta.';
    else if(_planSlugScen==='starter'&&(id==='seattle'||id==='wichita'))lockTitle='Seattle and Wichita are Pro markets — open Account to upgrade.';
    else if(id==='seattle')lockTitle='Seattle is included with Pro.';
    return `<button type="button" class="abt${sel} scen-mkt-locked" disabled title="${lockTitle}" style="font-size:13px;padding:6px 12px;letter-spacing:1px;opacity:0.5;cursor:not-allowed" aria-disabled="true">${m.label} <span style="font-size:11px" aria-hidden="true">🔒</span></button>`;
  }).join('');
  const blurb=(MARKETS[_selectedMarket]||MARKETS.atlanta).selectBlurb||'';
  const saveMktLbl=(MARKETS[saveMarketId]||MARKETS.atlanta).label;
  const mismatchNote=hasSave&&_selectedMarket!==saveMarketId
    ?`<div style="font-size:14px;color:var(--amb);margin:0 0 16px;line-height:1.5">Autosave is for <strong>${saveMktLbl}</strong> — RESUME loads that game. The market you pick below applies to <strong>new</strong> games.</div>`
    :'';

  const wlSiteFooterEmbed=`<div class="site-footer site-footer--embed" role="contentinfo"><div class="site-footer-inner"><span class="site-footer-copy">© 2026 Airwave Empire. All rights reserved.</span><nav class="site-footer-links" aria-label="Legal and social"><a href="/legal/terms.html" target="_blank" rel="noopener">Terms</a><span class="site-footer-dot" aria-hidden="true">·</span><a href="/legal/privacy.html" target="_blank" rel="noopener">Privacy</a><span class="site-footer-dot" aria-hidden="true">·</span><a href="/legal/contact.html" target="_blank" rel="noopener">Contact</a><span class="site-footer-dot" aria-hidden="true">·</span><span class="site-footer-social"><a href="https://www.facebook.com/profile.php?id=61575347974985" target="_blank" rel="noopener noreferrer">Facebook</a><span class="site-footer-dot" aria-hidden="true">·</span><a href="https://x.com/airwaveempire" target="_blank" rel="noopener noreferrer">X</a><span class="site-footer-dot" aria-hidden="true">·</span><a href="https://www.instagram.com/airwaveempire" target="_blank" rel="noopener noreferrer">Instagram</a></span></nav><p class="site-footer-sim">Fictional simulation — not affiliated with real stations or broadcasters.</p></div></div>`;

  const _camp=localSave?.campaign;
  const _hasCampMeta=!!(_camp&&(_camp.active||(_camp.completedAssignments|0)>0||_camp.campaignWon));
  const campaignIntroOk=`<p style="margin:0 0 12px;font-size:15px;color:var(--off);line-height:1.55">A large radio company has put you in charge of a struggling station in one of their smaller markets. Can you turn the station into a winner and get a promotion to a bigger market? A full General Manager career arc typically spans about eight completed station assignments — see how far up the ladder you go!</p>
    <div style="display:flex;flex-wrap:wrap;gap:8px">
      <button type="button" class="cfm" style="padding:10px 18px;font-size:14px;letter-spacing:1px" onclick="wlCampaignStartFromMenu()">▶ START GENERAL MANAGER CAREER</button>
      ${_hasCampMeta?`<button type="button" class="abt" style="padding:10px 18px;font-size:14px;letter-spacing:1px" onclick="wlCampaignOpenBriefing()">📋 CAREER BRIEFING</button>`:''}
    </div>`;
  const campaignLockedNote=_planSlugScen==='starter'
    ?`<p style="margin:0 0 10px;font-size:14px;color:var(--amb);line-height:1.5">The multi-market <strong>General Manager career</strong> is included with <strong>Pro</strong> (and your signup free trial). Your Starter plan includes the General Manager classic scenario in <strong>Solo — Classic Run</strong> below.</p>`
    :`<p style="margin:0 0 10px;font-size:14px;color:var(--amb);line-height:1.5">The full <strong>General Manager career</strong> unlocks on <strong>Pro</strong> or during your <strong>signup free trial</strong>. Subscribe to play the career ladder across markets.</p>`;
  const campaignInner=_allowGmCamp?campaignIntroOk:`<p style="margin:0 0 12px;font-size:15px;color:var(--off);line-height:1.55;opacity:0.92">Climb from a small market to the flagship: corporate assigns stations, reviews your results, and moves you up (or down) the ladder.</p>
    ${campaignLockedNote}
    <div style="display:flex;flex-wrap:wrap;gap:8px">
      <button type="button" class="cfm" style="padding:10px 18px;font-size:14px;letter-spacing:1px;opacity:0.9" onclick="wlLockedGmCampaignToast()">▶ START GENERAL MANAGER CAREER — UPGRADE</button>
      ${_hasCampMeta?`<button type="button" class="abt" style="padding:10px 18px;font-size:14px;letter-spacing:1px" onclick="wlCampaignOpenBriefing()">📋 CAREER BRIEFING</button>`:''}
    </div>`;

  const saveResumeRow=hasSave
    ?`<div class="scen-save-resume">
      <span style="font-size:15px;color:var(--off)">💾 <strong style="color:var(--grn)">${saveLabel||'Autosave'}</strong> — ${saveScen?.l||''} · ${saveMktLbl} · ${saveYear} ${savePeriod}</span>
      <button type="button" class="cfm" style="padding:6px 18px;font-size:14px" onclick="loadLocalSave()">▶ RESUME</button>
    </div>`
    :'';
  const noSaveNote=hasSave
    ?''
    :`<p style="margin:0 0 10px;font-size:14px;color:var(--mut);line-height:1.5">No browser autosave yet — use <strong style="color:var(--off)">Load game</strong> for a file or cloud slot, or <strong style="color:var(--off)">start a new game</strong> below.</p>`;
  const entrySection=`<div class="scen-pick-section scen-pick-section--entry">
    ${hasSave?saveResumeRow:noSaveNote}
    <div class="scen-entry-start-wrap">
      <button type="button" class="cfm scen-entry-start-btn" onclick="scenSetView('modes')">▶ START NEW GAME</button>
    </div>
    <div class="scen-entry-load-wrap">
      <button type="button" class="abt scen-entry-load-btn" title="Load from a cloud slot, import a file, or this browser" onclick="cm('m-scen');openSaveLoad()">LOAD GAME</button>
      <p class="scen-entry-load-hint">Load from cloud or file</p>
    </div>
    <div class="scen-entry-link-row" role="group" aria-label="More options">
      <button type="button" class="abt scen-entry-aux-btn" onclick="cm('m-scen');mpOpenLobby()">🎙 MULTIPLAYER</button>
      <button type="button" class="abt scen-entry-aux-btn" onclick="scenStartTutorialFromMenu()" title="Start the guided walkthrough (Turnaround station)">TUTORIAL</button>
    </div>
  </div>`;
  const tutBlock=tutSc&&allowed.has('tutorial_turnaround')
    ?`<div class="scn-mode scn-mode--tut" role="button" tabindex="0" title="Start guided walkthrough" onclick="scenStartTutorialFromMenu()" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();scenStartTutorialFromMenu();}"><div class="scn-mode-ribbon">GUIDED TUTORIAL</div><h3 class="scn-mode-title" style="font-family:var(--fd);font-size:20px;letter-spacing:0.12em;color:var(--wht);margin:0 0 6px">${(tutSc.l||'').toUpperCase()}</h3>
    <p style="font-family:var(--ft);font-size:15px;color:var(--amb);margin:0 0 8px;">${mktLabel} · ${tutSc.startYear||1970} · <strong style="color:var(--wht)">${f$(scaledScenarioCash(tutSc.cash,_selectedMarket))}</strong> starting</p>
    <p style="font-size:15px;color:var(--off);line-height:1.5;margin:0 0 12px;">On-screen walkthrough. Finish the lessons and keep playing, or exit and play on your own.</p>
    <div><span class="cfm" style="display:inline-block;padding:8px 16px;pointer-events:none" aria-hidden="true">▶ PLAY</span></div></div>`
    :'';
  const modesSection=`<div class="scen-modes">
    <button type="button" class="abt scen-modes-back" style="margin:0 0 12px" onclick="scenSetView('entry')">← BACK</button>
    <div style="text-align:center;margin-bottom:18px">
      <div style="font-family:var(--fd);font-size:18px;letter-spacing:0.18em;color:var(--wht)">START NEW GAME</div>
      <p style="font-size:14px;color:var(--mut);margin:8px 0 0;line-height:1.5">Choose how you want to start.</p>
    </div>
    ${tutBlock}
    <div class="scn-mode scn-mode--solo" style="margin-top:12px" role="button" tabindex="0" title="Choose market, then a historical scenario" onclick="scenSetView('solo')" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();scenSetView('solo');}">
    <div class="scn-mode-ribbon">SOLO — CLASSIC RUN</div>
    <h3 class="scn-mode-title" style="font-family:var(--fd);font-size:20px;letter-spacing:0.1em;color:var(--wht);margin:0 0 6px">1970 &rarr; 2020</h3>
    <p style="font-size:15px;color:var(--off);line-height:1.5;margin:0 0 12px;">Pick a market, then a starting scenario, and play the long arc. Same as the old solo list.</p>
    <div><span class="cfm" style="display:inline-block;padding:8px 16px;pointer-events:none" aria-hidden="true">▶ CHOOSE MARKET &amp; SCENARIO</span></div></div>
    <div class="scn-mode scn-mode--gm" style="margin-top:12px${_allowGmCamp?'':';opacity:0.72'}">
    <div class="scn-mode-ribbon">CAMPAIGN</div>
    <h3 class="scn-mode-title" style="font-family:var(--fd);font-size:20px;letter-spacing:0.1em;color:var(--wht);margin:0 0 8px">GENERAL MANAGER &mdash; CAREER</h3>
    ${campaignInner}</div>
    <div class="scn-mode scn-mode--soon" style="margin-top:12px;opacity:0.6">
    <div class="scn-mode-ribbon">COMING SOON</div>
    <h3 class="scn-mode-title" style="font-family:var(--fd);font-size:17px;color:var(--mut);margin:0 0 4px">CHALLENGE SCENARIOS</h3>
    <p style="font-size:14px;color:var(--mut);margin:0">Short, focused runs with extra constraints — not in this build yet.</p>
    </div>
  </div>`;
  const soloSection=`<div class="scen-pick-section scen-pick-section--solo">
    <button type="button" class="abt" style="margin-bottom:8px" onclick="scenSetView('modes')">← BACK</button>
    <div class="scen-pick-section__label scen-pick-section__label--solo-head">CLASSIC SOLO</div>
    <p class="scen-pick-solo-sub">You are a radio station owner. Pick a market, then choose a scenario.</p>
    <div style="font-family:var(--ft);font-size:12px;color:var(--mut);letter-spacing:2px;margin-bottom:8px">YOUR MARKET</div>
    <div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:12px">${marketPicker}</div>
    ${blurb?`<div style="font-size:15px;color:var(--off);line-height:1.55;margin-bottom:14px;border-left:3px solid rgba(245,166,35,.35);padding-left:12px">${blurb}</div>`:''}
    ${mismatchNote}
    <div class="scen-pick-solo-hd">
      <div style="font-family:var(--ft);font-size:15px;color:var(--mut);letter-spacing:2px">SCENARIOS</div>
      <button type="button" onclick="cm('m-scen');mpOpenLobby()" class="abt" style="font-size:15px;letter-spacing:2px;padding:8px 20px">🎙 MULTIPLAYER</button>
    </div>
    <div style="display:flex;flex-direction:column;gap:12px">${cards}</div>
    <button class="cfm" id="scn-start-btn" disabled onclick="confirmScen()" style="width:100%;margin-top:16px;padding:14px;font-size:14px;letter-spacing:3px">SELECT A SCENARIO TO BEGIN</button>
  </div>`;
  const mainPick=_scenView==='entry'?entrySection:_scenView==='modes'?modesSection:soloSection;

  document.getElementById('scenb').innerHTML=`
    <div style="padding:18px 20px 20px;max-width:760px;margin:0 auto">
    <div class="scn-hero">
      <div class="scn-hero__brand">
        <div class="scn-logo">AIRWAVE EMPIRE</div>
        <a href="/account.html" target="_blank" rel="noopener noreferrer" class="wl-hdr-account" title="Account, subscription, and billing">ACCOUNT</a>
      </div>
      <div class="scn-tagline" id="scn-tagline">A RADIO MANAGEMENT GAME</div>
    </div>
    ${wlTrialFirstGameBannerHtml()}
    ${wlFreeTierUpgradeBannerHtml()}
    <div class="scen-pick-stack">
      ${mainPick}
    </div>
    ${wlSiteFooterEmbed}
    </div>`;
  om('m-scen');
}

function pickScen(id){
  if(id==='gm_under'&&(typeof wlClerkPlanAllowsGmScenario!=='function'||!wlClerkPlanAllowsGmScenario())){
    wlLockedGmScenarioToast();
    return;
  }
  _pendingScenId=id;
  document.querySelectorAll('.scn-card').forEach(el=>el.classList.remove('sel'));
  document.getElementById('scn-'+id)?.classList.add('sel');
  const btn=document.getElementById('scn-start-btn');
  const sc=SC.find(s=>s.id===id);
  if(btn&&sc){
    btn.disabled=false;btn.textContent=`BEGIN — ${sc.l.toUpperCase()} →`;
    const tl=document.getElementById('scn-tagline');
    if(tl){
      const yr=sc.startYear||1970;
      const eraLbl=yr===1985?'FORMAT WARS ERA':yr===1978?'FM REVOLUTION ERA':'THE BEGINNING';
      const marketTag=((typeof _selectedMarket!=='undefined'&&_selectedMarket&&MARKETS[_selectedMarket]?.label)||'Atlanta').toUpperCase();
      tl.textContent=`${marketTag} RADIO · ${yr}–2020 · ${eraLbl}`;
    }
  }
}

function confirmScen(){
  if(!_pendingScenId)return;
  if(_pendingScenId==='gm_under'&&(typeof wlClerkPlanAllowsGmScenario!=='function'||!wlClerkPlanAllowsGmScenario())){
    wlLockedGmScenarioToast();
    return;
  }
  cm('m-scen');
  openOnboarding(_pendingScenId);
}

function openOnboarding(scenId){
  const sc=SC.find(s=>s.id===scenId)||SC[0];
  /* #m-onboard header button calls startPlay(_pendingScenId) — must match this scenario (tutorial path cleared it to null, which caused pick(SC) = random). */
  _pendingScenId=sc.id;
  const yr=sc.startYear||1970;
  const span=2020-yr;
  const mktGoal=(MARKETS[_selectedMarket]||MARKETS.atlanta).label;
  const goalText=sc.gmMode
    ?`As General Manager, keep your job through ${span} years (${yr}–2020). Ownership reviews profit margin, revenue trend, and talent/franchise health on a rolling schedule — miss expectations too often and you are dismissed. (Cash bankruptcy is separate.)`
    :`Dominate the ${mktGoal} market over ${span} years — ${yr} to 2020. Score is based on average ratings share, revenue growth, and surviving the industry's upheavals. Decade checkpoints grade your performance.`;

  // Era-specific strategic tips shown as the KEY WATCH section
  const eraTips={
    under:[
      {k:'MORNING DRIVE',v:`Your first hire matters most. A strong morning host can lift ratings 2-3 points on its own.`},
      {k:'AM EROSION',v:`FM penetration rises every period starting in the mid-70s. Have an FM plan before 1978 or you will bleed out slowly.`},
      {k:'CASH',v:`Thin margins early. Keep spot load high, spend carefully on talent. Survive long enough to matter.`},
    ],
    cntry:[
      {k:'FM TRANSITION',v:`Country AM works fine through 1978-80. After that, FM Country pulls your audience. Buy or build an FM before 1982.`},
      {k:'TALENT',v:`Country audiences follow personalities. A loyal morning host is worth every dollar — and their contract is your insurance.`},
      {k:'RIVALS',v:`A second Country station entering the market is an existential threat. Differentiate your brand before they arrive.`},
    ],
    soul:[
      {k:'CPM GAP',v:`Urban formats are undervalued by Madison Avenue. You'll need 50% more audience than a CHR to earn the same revenue. Fight for every advertiser relationship.`},
      {k:'COMMUNITY',v:`Your competitive moat is loyalty. Protect your Loyal listeners — rivals will try to poach them constantly.`},
      {k:'FM',v:`Soul and R&B move to FM by the mid-80s. Urban Contemporary is the evolved format — transition when the time is right.`},
    ],
    stack:[
      {k:'SIMULCAST',v:`Use the AM to fund the FM's growth. Simulcast the same format to build FM cume, then differentiate when you're ready.`},
      {k:'OVERHEAD',v:`Two stations means two upkeep bills. Stay cash-positive or the combo becomes a liability.`},
      {k:'TIMING',v:`The FM is your long-term asset. Don't wait too long to cut the AM loose — erosion compounds.`},
    ],
    fmpn:[
      {k:'LEAN YEARS',v:`Advertisers don't understand FM yet. Revenue will be thin through 1972-74. Cut costs, not quality.`},
      {k:'AUDIENCE FIRST',v:`Build ratings now, monetize later. FM listenership is growing 20% a year — be the station they find.`},
      {k:'FORMAT LOCK',v:`Album Rock works. Resist the urge to chase pop formats — your credibility is the product.`},
    ],
    wsb:[
      {k:'FORMAT CRISIS',v:`MOR's broad appeal is becoming a liability. Every new FM format eats a slice of your audience. Specialize before the erosion compounds.`},
      {k:'NEWS/TALK',v:`A pivot to News/Talk was the classic MOR survival play — but the window closes once a rival claims the format.`},
      {k:'DOMINANCE',v:`You open with a strong book — that leadership is the ceiling to defend, not a floor to build from. Rivals are targeting you.`},
    ],
    fmrev:[
      {k:'THE MOMENT',v:`FM just crossed AM in total audience. The ad market hasn't caught up yet — but it will. You have 2-3 years to build before CPMs spike.`},
      {k:'ALBUM ROCK',v:`Low spot load is the format's identity. Programmers who pack the clock with ads destroy the brand. Stay under 12 min/hr.`},
      {k:'COMPETITION',v:`Classic Rock and CHR will both emerge by 1980-82. Claim your niche before the format wars begin.`},
    ],
    acrise:[
      {k:'AC WINDOW',v:`Adult Contemporary is underserved in 1978. You have roughly 4 years before it gets crowded. Use them to build unassailable audience loyalty.`},
      {k:'25-49 WOMEN',v:`This is your target demo and it's the most valuable in radio. Every programming decision should serve them.`},
      {k:'BRAND',v:`AC stations win or lose on brand perception. Hire a great morning host and don't change the music clock every 6 months.`},
    ],
    chrwar:[
      {k:'THREE PATHS',v:`CHR peaks around 1988 then fragments. Classic Rock has 15 good years ahead. AC is steady but never dominant. Pick the format that fits your market position.`},
      {k:'RATINGS RACE',v:`You're starting with mediocre ratings. The first 4 periods are critical — hire well, keep spot load tight, and build momentum.`},
      {k:'CONSOLIDATION',v:`Corporate buyers arrive after 1996. A strong ratings position makes you an acquisition target — or gives you the cash to be the buyer.`},
    ],
    amtalk:[
      {k:'THE CLIFF',v:`Your AM music revenue will fall roughly 35-40% between now and 1990. The question is whether you pivot before or after it hurts.`},
      {k:'NEWS/TALK',v:`Rush Limbaugh launches nationally in 1988. The Talk format explodes. Get there early or pay a premium to follow.`},
      {k:'CASH',v:`Thin runway. Every period without a pivot is a period of compounding damage. Move fast.`},
    ],
    gm_under:[
      {k:'BOARD REVIEWS',v:`Every two years (four periods), ownership scores your margin, revenue trend, and talent/franchise health. Job security drops on sustained misses — recovery is possible if you fix fundamentals.`},
      {k:'NO CUTS TO WIN',v:`Slashing talent may lift margin short term but erodes franchise; the board notices revenue and franchise decay, not just this quarter.`},
      {k:'CASH VS CAREER',v:`Negative cash can still bankrupt you; General Manager job security is separate — you can be fired while solvent or survive a soft quarter if the trend is right.`},
    ],
  };

  const tips=eraTips[sc.id]||eraTips.under;
  const tipsHtml=tips.map(t=>`<div class="ob-row"><span class="ob-key">${t.k}</span><span>${t.v}</span></div>`).join('');
  const mktLbl=(typeof _selectedMarket!=='undefined'&&_selectedMarket&&MARKETS[_selectedMarket]?.label)||MARKETS.atlanta.label;
  const defCompany=`${mktLbl} Broadcasting Group`;
  const escCo=defCompany.replace(/"/g,'&quot;');

  // Generic mechanics — slightly adjusted by era
  const amMechanicRow=yr<=1978
    ?`<div class="ob-row"><span class="ob-key">AM EROSION</span><span>AM music formats lose audience every period as FM penetration grows. The erosion accelerates through the early 80s. Options: pivot to News/Talk, buy an FM license, or install an FM translator.</span></div>`
    :`<div class="ob-row"><span class="ob-key">AM EROSION</span><span>AM music is already in decline. If you\'re on AM music, the clock is running. News/Talk and Sports are the only AM formats that hold audience long-term.</span></div>`;

  document.getElementById('onboardb').innerHTML=`
    <div style="margin-bottom:20px">
      <div style="font-family:var(--ft);font-size:14px;color:var(--mut);letter-spacing:2px;margin-bottom:4px">YOUR SCENARIO · ${mktLbl.toUpperCase()} · ${yr}</div>
      <div style="font-family:var(--fd);font-size:26px;letter-spacing:4px;color:var(--amb)">${sc.l.toUpperCase()}</div>
      <div style="font-size:15px;color:var(--off);margin-top:8px;line-height:1.6">${sc.d}</div>
    </div>
    <div class="ob-sec">
      <div class="ob-hd">YOUR COMPANY</div>
      <div class="ob-row"><span class="ob-key">NAME</span><span style="flex:1;min-width:0">
        <input type="text" id="company-name-input" maxlength="48" value="${escCo}" placeholder="${escCo}"
          style="width:100%;box-sizing:border-box;background:var(--crd);border:1px solid var(--bdh);color:var(--wht);font-family:var(--ft);font-size:15px;padding:10px 12px;outline:none;border-radius:2px"/>
      </span></div>
      <div style="font-size:13px;color:var(--mut);margin-top:6px;line-height:1.45">Shown in the header like multiplayer company names. Leave default or enter your own.</div>
    </div>
    <div class="ob-sec">
      <div class="ob-hd">THE GOAL</div>
      <div class="ob-row"><span class="ob-key">WIN</span><span>${goalText}</span></div>
    </div>
    <div class="ob-sec">
      <div class="ob-hd">WATCH THIS SCENARIO</div>
      ${tipsHtml}
    </div>
    <div class="ob-sec">
      <div class="ob-hd">EACH PERIOD (SPRING / FALL)</div>
      <div class="ob-row"><span class="ob-key">HIRE</span><span>Morning Drive talent has the biggest ratings impact. Always fill it — a strong host can move the needle 2-3 points on its own.</span></div>
      <div class="ob-row"><span class="ob-key">SPOTS</span><span>Spot load is your ad minutes per hour. More spots = more revenue but hurts TSL. 14 min/hr is standard. Rock formats want fewer; Talk can run more.</span></div>
      <div class="ob-row"><span class="ob-key">ADVANCE</span><span>Hit NEXT PERIOD to run the simulation. Rivals react, the market shifts, and your revenue is collected.</span></div>
    </div>
    <div class="ob-sec">
      <div class="ob-hd">KEY MECHANICS</div>
      ${amMechanicRow}
      <div class="ob-row"><span class="ob-key">SIMULCAST</span><span>Own an AM and FM? Run them as one format to build an FM audience, then cut the AM loose when the time is right.</span></div>
      <div class="ob-row"><span class="ob-key">ACQUIRE</span><span>Buy rival stations to absorb a format and eliminate competition. Expect 20–35% listener churn — keep the format and talent stable to hold them.</span></div>
      <div class="ob-row"><span class="ob-key">CONSOLIDATION</span><span>After 1996, corporate groups start buying everything. Strong ratings make you a target — or give you the cash to be the buyer.</span></div>
    </div>
    <button class="cfm" onclick="cm('m-onboard');startPlay('${sc.id}')" style="width:100%;padding:14px;font-size:14px;letter-spacing:3px">ON AIR — ${yr} →</button>`;
  om('m-onboard');
}

function startPlay(scenId){
  try{
    if(scenId==='gm_under'&&(typeof wlClerkPlanAllowsGmScenario!=='function'||!wlClerkPlanAllowsGmScenario())){
      wlLockedGmScenarioToast();
      return;
    }
    _pendingScenId=null;
    if(!globalThis._wlCampaignStarting&&typeof wlCampaignDeactivate==='function')wlCampaignDeactivate();
    ACTIVE_MARKET=_selectedMarket;
    syncMarketPopToMarket(ACTIVE_MARKET);
    let companyName=(document.getElementById('company-name-input')?.value||'').trim();
    if(!companyName){
      const mktLbl=(typeof _selectedMarket!=='undefined'&&_selectedMarket&&MARKETS[_selectedMarket]?.label)||MARKETS.atlanta.label;
      companyName=`${mktLbl} Broadcasting Group`;
    }
    G=genMarket(scenId);
    try{
      const slug=typeof window!=='undefined'?String(window.__WL_CLERK_PLAN_SLUG||'').trim():'';
      const camp=!!globalThis._wlCampaignStarting;
      G.wlSignupTrial=!!(slug==='trial_user'&&MP.mode!=='live'&&!camp&&!G.tutorialMode);
    }catch(_e){
      G.wlSignupTrial=false;
    }
    G.companyName=companyName;
    G.ps=(G.stations||[]).filter(s=>s&&s.isPlayer);
    G._portraitSessionId=(typeof crypto!=='undefined'&&crypto.randomUUID)?crypto.randomUUID():`${Date.now()}-${Math.random().toString(36).slice(2,11)}`;
    initSportsRights(G);
    initFranchiseRights(G);
    normalizeSimulcastLinksInPlace(G);
    enforceFmNonDupConstraints(G);
    refreshAllStationOQ(G);
    if(G.tutorialMode&&G.sc?.id==='tutorial_turnaround'){
      recalc(G.stations,G);
      seedRev(G.stations,G);
      updateAllStationsBudgetStress(G);
    }
    snapMarketRankBookDisplay(G);
    renderAll();
    queuePlayerTalentPortraits();
    queueAutoLogosForPlayerStations();
    setTimeout(()=>{
      if(G?.tutorialMode&&G.sc?.id==='tutorial_turnaround')tutorialTurnaroundShowIntroModal();
      else wlFtTutorialMaybeStartAfterNewGame();
    },0);
    wlTrackSoloSession({
      source:'new_game',
      scenarioId:scenId,
      marketId:ACTIVE_MARKET||_selectedMarket||'atlanta',
    });
    if(typeof wlGmMode!=='undefined'&&wlGmMode.initGmStateForGame)wlGmMode.initGmStateForGame(G);
    try{if(typeof autoSave==='function')autoSave();}catch(_e){}
  }catch(err){
    showError('Failed during genMarket: '+err.message, err.stack||String(err));
  }
}

function startNewGame(){
  // Legacy path — called from some places, routes to scenario select
  openScenSelect(null);
}

/** Campaign Mode — solo GM career ladder (see campaignMode.js). */
function wlCampaignStartFromMenu(){
  try{if(typeof autoSave==='function')autoSave();}catch(_e){}
  if(typeof wlClerkPlanAllowsGmCampaign==='function'&&!wlClerkPlanAllowsGmCampaign()){
    wlLockedGmCampaignToast();
    return;
  }
  if(typeof wlCampaignOpenStartModal==='function'){
    wlCampaignOpenStartModal();
    return;
  }
  if(typeof wlCampaign==='undefined'||!wlCampaign.openStartModal){
    showToast('Campaign mode is not loaded. Refresh the page.','warn');
    return;
  }
  wlCampaign.openStartModal();
}

function wlCampaignOpenBriefing(){
  try{
    const local=getLocalSave();
    if(typeof wlCampaignLoadFromSave==='function')wlCampaignLoadFromSave(local?.campaign);
    if(typeof G!=='undefined'&&G&&typeof wlCampaignSyncFromGame==='function')wlCampaignSyncFromGame(G);
    if(typeof wlCampaign.renderCampaignModal==='function')wlCampaign.renderCampaignModal();
    if(typeof om==='function')om('m-campaign-brief');
  }catch(e){
    showToast('Could not open career briefing.','warn');
  }
}
function loadLocalSaveAndClose(el){
  el?.remove();
  loadLocalSave();
}

// ── SIMULCAST HELPERS ─────────────────────────────────────────────
// Star model: one programming source (`_simulcastSource`) + N receivers (`simulcastSourceStationId` → source).
// Legacy bidirectional `simulcastWith` pairs are migrated on load via `migrateSimulcastLegacyPairsToStar`.
function simulcastGroupReceivers(sourceId,G){
  return(G.stations||[]).filter(t=>t&&!t._bpSlotDeferred&&t.simulcastSourceStationId===sourceId);
}
/** True if this station is part of any simulcast group (legacy pair or star). */
function stationHasSimulcastLeg(s,G){
  if(!s)return false;
  if(s.simulcastWith)return true;
  if(s.simulcastSourceStationId)return true;
  if(s._simulcastSource===true&&simulcastGroupReceivers(s.id,G).length>0)return true;
  return false;
}
/** All station ids in the same simulcast cluster as `s` (including `s`). */
function simulcastGroupStationIds(s,G){
  if(!s)return new Set();
  const out=new Set([s.id]);
  if(s._simulcastSource===true){
    simulcastGroupReceivers(s.id,G).forEach(r=>{if(r)out.add(r.id);});
    return out;
  }
  if(s.simulcastSourceStationId){
    out.add(s.simulcastSourceStationId);
    const lead=(G.stations||[]).find(t=>t.id===s.simulcastSourceStationId);
    if(lead)simulcastGroupReceivers(lead.id,G).forEach(r=>{if(r)out.add(r.id);});
    return out;
  }
  if(s.simulcastWith)out.add(s.simulcastWith);
  return out;
}
function clearSimulcastReceiverFields(st){
  if(!st)return;
  st.simulcastSourceStationId=null;
  st.simulcastWith=null;
  delete st._simulcastSource;
  delete st._prevRank;
  if(st.sig?.type==='FM'&&!st.fmBooster){
    delete st.fmSimulcastDupPct;
    delete st.fmRemainderFormat;
    delete st._aiFmDupTuned;
  }
}
function clearSimulcastSourceFields(st){
  if(!st)return;
  st.simulcastWith=null;
  delete st._simulcastSource;
  delete st._prevRank;
}
/**
 * Before linking a new simulcast receiver: any station still pointing at `src` via mutual `simulcastWith`
 * (legacy AM/FM pair) must become a star receiver. Otherwise clearing `src.simulcastWith` orphans the FM —
 * it never gets `simulcastSourceStationId`, so "break this leg" / economics do not run correctly.
 */
function migrateLegacyPartnersToStarReceiversForSource(G, src){
  if(!src)return;
  (G.stations||[]).forEach(st=>{
    if(!st||st._bpSlotDeferred||st.id===src.id)return;
    if(st.simulcastWith===src.id){
      st.simulcastSourceStationId=src.id;
      st._simulcastSource=false;
      st.simulcastWith=null;
    }
  });
  src._simulcastSource=true;
  delete src.simulcastSourceStationId;
  src.simulcastWith=null;
}
/** Repair saves broken by older "add Nth receiver" logic: one-way `simulcastWith` to source with no back-pointer. */
function repairOrphanSimulcastLegPointers(G){
  (G.stations||[]).forEach(st=>{
    if(!st||st._bpSlotDeferred||!st.simulcastWith||st.simulcastSourceStationId)return;
    const p=G.stations.find(t=>t.id===st.simulcastWith);
    if(!p||p.simulcastWith===st.id)return;
    if(p._simulcastSource===true){
      st.simulcastSourceStationId=p.id;
      st._simulcastSource=false;
      st.simulcastWith=null;
    }
  });
}
/** Convert legacy `simulcastWith` pairs to star model (source + simulcastSourceStationId receivers). */
function migrateSimulcastLegacyPairsToStar(G){
  if(!G||!G.stations)return;
  const done=new Set();
  G.stations.forEach(s=>{
    if(!s||s._bpSlotDeferred||!s.simulcastWith||done.has(s.id))return;
    const p=G.stations.find(t=>t.id===s.simulcastWith);
    if(!p||p.simulcastWith!==s.id){s.simulcastWith=null;return;}
    if(s.simulcastSourceStationId||p.simulcastSourceStationId)return;
    done.add(s.id);done.add(p.id);
    const {lead,rcv}=simulcastPairLeadReceiver(s,p);
    lead._simulcastSource=true;
    rcv._simulcastSource=false;
    rcv.simulcastSourceStationId=lead.id;
    lead.simulcastWith=null;
    rcv.simulcastWith=null;
    delete lead.simulcastSourceStationId;
  });
}
function breakSimulcast(G,stnId){
  const s=G.stations.find(st=>st.id===stnId);
  if(!s)return;
  if(s._simulcastSource===true){
    simulcastGroupReceivers(s.id,G).forEach(r=>clearSimulcastReceiverFields(r));
    clearSimulcastSourceFields(s);
    return;
  }
  if(s.simulcastSourceStationId){
    clearSimulcastReceiverFields(s);
    return;
  }
  const partner=s.simulcastWith?G.stations.find(st=>st.id===s.simulcastWith):null;
  if(s){
    s.simulcastWith=null;
    delete s._simulcastSource;
    delete s._prevRank;
    if(s.sig?.type==='FM'&&!s.fmBooster){
      delete s.fmSimulcastDupPct;
      delete s.fmRemainderFormat;
      delete s._aiFmDupTuned;
    }
  }
  if(partner){
    partner.simulcastWith=null;
    delete partner._simulcastSource;
    delete partner._prevRank;
    if(partner.sig?.type==='FM'&&!partner.fmBooster){
      delete partner.fmSimulcastDupPct;
      delete partner.fmRemainderFormat;
      delete partner._aiFmDupTuned;
    }
  }
  (G.stations||[]).forEach(st=>{
    if(st&&st.simulcastWith===stnId){
      st.simulcastWith=null;
      delete st._simulcastSource;
      delete st._prevRank;
      if(st.sig?.type==='FM'&&!st.fmBooster){
        delete st.fmSimulcastDupPct;
        delete st.fmRemainderFormat;
        delete st._aiFmDupTuned;
      }
    }
  });
}
/** Drop one-way or broken simulcast pointers (e.g. after distress sale / MP desync) so ranker shows one row per surviving leg. */
function normalizeSimulcastLinksInPlace(G){
  let pass=0;
  let changed=true;
  while(changed&&pass<8){
    changed=false;
    pass++;
    (G.stations||[]).forEach(s=>{
      if(!s||s._bpSlotDeferred)return;
      if(s.simulcastSourceStationId){
        const src=G.stations.find(st=>st.id===s.simulcastSourceStationId);
        if(!src||src._simulcastSource!==true||src._bpSlotDeferred){
          clearSimulcastReceiverFields(s);
          changed=true;
        }
      }
    });
    (G.stations||[]).forEach(s=>{
      if(!s||s._bpSlotDeferred||!s.simulcastWith)return;
      const p=G.stations.find(st=>st.id===s.simulcastWith);
      if(!p||p.simulcastWith!==s.id){
        s.simulcastWith=null;
        delete s._simulcastSource;
        delete s._prevRank;
        changed=true;
      }
    });
  }
}
function stationEligibleSimulcastReceiver(s){
  return s&&!s._bpSlotDeferred&&!s.simulcastWith&&!s.simulcastSourceStationId&&s._simulcastSource!==true;
}
function canSimulcast(G,s1,s2){
  // Source leg must not be someone else's receiver; target must be a free leg (formats may diverge — receiver adopts source).
  if(!s1||!s2||!s1.isPlayer||!s2.isPlayer||s1.id===s2.id)return false;
  if(!stationEligibleSimulcastReceiver(s2))return false;
  const src1=simulcastProgrammingSourceStation(s1,G);
  if(src1&&src1.id!==s1.id)return false;
  return true;
}
/** Upstream programming leg when `s` is a simulcast receiver; null when `s` is the source or not in a simulcast. */
function simulcastProgrammingSource(s){
  const src=simulcastProgrammingSourceStation(s,G);
  if(!src||src.id===s.id)return null;
  return src;
}
/** Receiver echoes partner's on-air content for this slot (no local talent object on receiver). */
function slotCoveredBySimulcast(s,slot){
  const src=simulcastProgrammingSource(s);
  if(!src)return false;
  return !s.prog[slot]?.talent&&!!src.prog[slot]?.talent;
}
/** Programming-side station for UI: simulcast receiver inherits from the source leg. */
function simulcastOperationalSource(st){
  if(!st)return st;
  const src=simulcastProgrammingSource(st);
  return src||st;
}
function ensureOpsSourceSid(sid){
  const s=G.stations.find(st=>st.id===sid);
  if(!s)return sid;
  return simulcastOperationalSource(s).id;
}
// Determine which station leads a simulcast pair (higher signal power / revenue)
function simLead(a,b){
  // FM (incl. fmBooster) beats AM; among same type, higher power wins; tiebreak by revenue
  const isFA=a.sig.type==='FM'||a.fmBooster, isFB=b.sig.type==='FM'||b.fmBooster;
  if(isFA!==isFB) return isFA?a:b;
  const pwRank={['100kw']:4,['50kw']:3,['25kw']:2,['10kw']:1,['5kw']:1,['1kw']:0,['DA']:2,['translator']:0};
  const pa=pwRank[a.sig.pw]||0, pb=pwRank[b.sig.pw]||0;
  if(pa!==pb) return pa>pb?a:b;
  return (a.fin?.rev||0)>=(b.fin?.rev||0)?a:b;
}
/** One “other” leg for pair UIs: legacy partner, programming source if `s` is a receiver, or first receiver if `s` is the source. */
function simulcastPartnerStation(s){
  if(!s)return null;
  if(s.simulcastSourceStationId){
    return G.stations.find(st=>st.id===s.simulcastSourceStationId)||null;
  }
  if(s._simulcastSource===true){
    const rec=simulcastGroupReceivers(s.id,G);
    return rec[0]||null;
  }
  if(!s.simulcastWith)return null;
  const p=G.stations.find(st=>st.id===s.simulcastWith);
  if(!p||p.simulcastWith!==s.id)return null;
  return p;
}
/** Mirror promo / prog budget / community identity budget to every simulcast receiver (one UI surface). */
function syncOwnedSimulcastSpendFromSource(src){
  if(!src||!src._simulcastSource)return;
  const receivers=simulcastGroupReceivers(src.id,G);
  receivers.forEach(partner=>{
    if(!partner||!src.isPlayer||!partner.isPlayer)return;
    if(MP.mode==='live'&&(src._mpOwner!==partner._mpOwner))return;
    if(!partner.ops)partner.ops={spots:14,sell:0.65,promo:0,progBudget:0};
    if(!src.ops)src.ops={spots:14,sell:0.65,promo:0,progBudget:0};
    partner.ops.promo=src.ops.promo;
    partner.ops.progBudget=src.ops.progBudget;
    partner.identityBudget=src.identityBudget||0;
    calcRev(partner,G);
    if(MP.mode==='live'){
      MP.action('promo',{sid:partner.id,promo:partner.ops.promo});
      MP.action('prog',{sid:partner.id,progBudget:partner.ops.progBudget});
      MP.action('ident',{sid:partner.id,budget:partner.identityBudget});
    }
  });
  if(src.simulcastWith){
    const partner=G.stations.find(st=>st.id===src.simulcastWith);
    if(partner&&partner.simulcastWith===src.id&&src.isPlayer&&partner.isPlayer){
      if(MP.mode==='live'&&(src._mpOwner!==partner._mpOwner))return;
      if(!partner.ops)partner.ops={spots:14,sell:0.65,promo:0,progBudget:0};
      if(!src.ops)src.ops={spots:14,sell:0.65,promo:0,progBudget:0};
      partner.ops.promo=src.ops.promo;
      partner.ops.progBudget=src.ops.progBudget;
      partner.identityBudget=src.identityBudget||0;
      calcRev(partner,G);
      if(MP.mode==='live'){
        MP.action('promo',{sid:partner.id,promo:partner.ops.promo});
        MP.action('prog',{sid:partner.id,progBudget:partner.ops.progBudget});
        MP.action('ident',{sid:partner.id,budget:partner.identityBudget});
      }
    }
  }
}
/** Programming source (lead) and receiver for a simulcast pair. */
function simulcastPairLeadReceiver(a,b){
  if(a._simulcastSource===true&&!b._simulcastSource)return{lead:a,rcv:b};
  if(b._simulcastSource===true&&!a._simulcastSource)return{lead:b,rcv:a};
  const L=simLead(a,b);
  return {lead:L,rcv:L.id===a.id?b:a};
}
/** Which leg owns the single combined player card — strict booleans only for source, then signal tiebreak (symmetric). */
function simulcastPairStationCardAnchor(a,b){
  const at=a._simulcastSource===true, bt=b._simulcastSource===true;
  if(at&&!bt)return a;
  if(bt&&!at)return b;
  return simulcastPairLeadReceiver(a,b).lead;
}
/** One row per station or combined simulcast group, sorted by total share (desc). */
function buildSimulcastCombinedRankRows(allStations){
  const seen=new Set();
  const rows=[];
  const active=allStations.filter(s=>s&&!s._bpSlotDeferred&&s.rat);
  const sorted=[...active].sort((a,b)=>b.rat.share-a.rat.share);
  sorted.forEach(s=>{
    if(seen.has(s.id))return;
    if(s.simulcastSourceStationId)return;
    if(s._simulcastSource===true){
      const recv=simulcastGroupReceivers(s.id,G).filter(r=>allStations.some(st=>st.id===r.id));
      if(recv.length){
        recv.forEach(r=>seen.add(r.id));
        seen.add(s.id);
        const share=s.rat.share+recv.reduce((sum,r)=>sum+r.rat.share,0);
        const rev=s.fin.rev+recv.reduce((sum,r)=>sum+r.fin.rev,0);
        rows.push({pair:true,lead:s,rcv:recv[0],receivers:recv,share,rev});
        return;
      }
      if(s.simulcastWith){
        const p=allStations.find(st=>st.id===s.simulcastWith);
        if(p&&p.simulcastWith===s.id){
          seen.add(s.id);seen.add(p.id);
          const {lead,rcv}=simulcastPairLeadReceiver(s,p);
          rows.push({pair:true,lead,rcv,receivers:[rcv],share:lead.rat.share+rcv.rat.share,rev:lead.fin.rev+rcv.fin.rev});
          return;
        }
      }
      seen.add(s.id);
      rows.push({pair:false,st:s,share:s.rat.share,rev:s.fin.rev});
      return;
    }
    const p=s.simulcastWith?G.stations.find(st=>st.id===s.simulcastWith):null;
    if(p&&allStations.some(st=>st.id===p.id)&&p.simulcastWith===s.id){
      seen.add(s.id);seen.add(p.id);
      const {lead,rcv}=simulcastPairLeadReceiver(s,p);
      rows.push({pair:true,lead,rcv,receivers:[rcv],share:lead.rat.share+rcv.rat.share,rev:lead.fin.rev+rcv.fin.rev});
    }else{
      seen.add(s.id);
      rows.push({pair:false,st:s,share:s.rat.share,rev:s.fin.rev});
    }
  });
  rows.sort((a,b)=>b.share-a.share);
  return rows;
}
/** Commercial-only — same universe as rank milestones (excludes public / deferred). */
function buildCommercialCombinedRankRows(G){
  return buildSimulcastCombinedRankRows([...G.stations].filter(st=>st&&!st._bpSlotDeferred&&!st.isPublic));
}
/** Stable key for book / display row matching (simulcast pair or solo). */
function marketRankRowKey(row){
  if(row.pair){
    const rec=row.receivers||[row.rcv];
    const ids=[row.lead.id,...rec.map(r=>r.id)].map(String).sort();
    return 'p:'+ids.join(':');
  }
  return `s:${row.st.id}`;
}
/**
 * Snapshot for the main market table (# and SHARE): updated when a period ends (advTurn),
 * not on mid-period recalc (logo/van/talent still update the live model for revenue/sim).
 */
function snapMarketRankBookDisplay(G){
  if(!G?.stations?.length)return;
  const rows=buildSimulcastCombinedRankRows(G.stations);
  G._mktRankBookSnap={
    year:G.year,
    period:G.period,
    turn:G.turn,
    rows:rows.map((row,i)=>({key:marketRankRowKey(row),rank:i+1,share:row.share})),
  };
  snapStationCardShareDisplay(G);
}
/** Per-leg audience share + book trend (cp) shown on player station cards — frozen at each book until Next Period (live model still updates for sim/revenue). */
function snapStationCardShareDisplay(G){
  if(!G?.stations?.length)return;
  const byId=Object.create(null);
  const cpById=Object.create(null);
  G.stations.forEach(st=>{
    if(!st||st._bpSlotDeferred||st.id==null)return;
    const sh=st.rat&&typeof st.rat.share==='number'&&!Number.isNaN(st.rat.share)?st.rat.share:0;
    byId[st.id]=Math.round(sh*1e8)/1e8;
    const cp=st.cp;
    if(cp&&typeof cp==='object'){
      cpById[st.id]={
        dq:typeof cp.dq==='number'?cp.dq:0,
        d2:typeof cp.d2==='number'?cp.d2:0,
        under:!!cp.under,
        col:!!cp.col,
        sur:!!cp.sur,
      };
    }
  });
  G._stationCardShareSnap={
    year:G.year,
    period:G.period,
    turn:G.turn,
    byId,
    cpById,
  };
}
function stationCardDisplayShare01(s){
  if(!s||s._bpSlotDeferred)return 0;
  const snap=G._stationCardShareSnap&&G._stationCardShareSnap.byId;
  if(snap&&Object.prototype.hasOwnProperty.call(snap,s.id)){
    const v=snap[s.id];
    return typeof v==='number'&&!Number.isNaN(v)?v:(s.rat&&s.rat.share)||0;
  }
  return(s.rat&&s.rat.share)||0;
}
/** Book trend flags for station cards — same snap as share; avoids intra-period recalc rewriting `s.cp` from last tick vs last book. */
function stationCardDisplayCp(s){
  if(!s||s._bpSlotDeferred)return null;
  const snap=G._stationCardShareSnap;
  const cpBy=snap&&snap.cpById;
  if(cpBy&&Object.prototype.hasOwnProperty.call(cpBy,s.id)){
    const o=cpBy[s.id];
    if(o&&typeof o==='object')return o;
  }
  return s.cp||null;
}
/** Rows for rMkt: book rank/share when snap exists; new stations append at bottom by live share. */
function buildMarketRankRowsForDisplay(G){
  const liveRows=buildSimulcastCombinedRankRows(G.stations);
  const snap=G._mktRankBookSnap;
  if(!snap||!Array.isArray(snap.rows)||!snap.rows.length){
    return liveRows.map((row,i)=>({row,displayRank:i+1,displayShare:row.share}));
  }
  const liveByKey=new Map(liveRows.map(r=>[marketRankRowKey(r),r]));
  const out=[];
  const used=new Set();
  for(const sr of snap.rows){
    const live=liveByKey.get(sr.key);
    if(live){
      out.push({row:live,displayRank:sr.rank,displayShare:sr.share});
      used.add(sr.key);
    }
  }
  const orphans=liveRows.filter(r=>!used.has(marketRankRowKey(r))).sort((a,b)=>b.share-a.share);
  let nextRank=out.length?Math.max(...out.map(o=>o.displayRank)):0;
  for(const row of orphans){
    nextRank++;
    out.push({row,displayRank:nextRank,displayShare:row.share});
  }
  out.sort((a,b)=>a.displayRank-b.displayRank);
  return out;
}
/** Market rank (1-based) using combined simulcast rows; one rank per simulcast group. */
function combinedMarketRankForStation(s, combinedRows){
  const idx=combinedRows.findIndex(r=>{
    if(!r.pair)return r.st&&r.st.id===s.id;
    if(r.lead.id===s.id)return true;
    const rec=r.receivers||[r.rcv];
    return rec.some(t=>t&&t.id===s.id);
  });
  return idx>=0?idx+1:0;
}
/** Milestone / ticker label: one simulcast group reads as a single unit. */
function milestoneRankLabelHtml(s){
  if(s._simulcastSource===true){
    const rec=simulcastGroupReceivers(s.id,G);
    if(rec.length){
      return[s,...rec].map(l=>'<strong>'+callDisplay(l)+'</strong>').join(' & ');
    }
  }
  if(s.simulcastSourceStationId){
    const lead=G.stations.find(t=>t.id===s.simulcastSourceStationId);
    if(lead){
      const rec=simulcastGroupReceivers(lead.id,G);
      return[lead,...rec].map(l=>'<strong>'+callDisplay(l)+'</strong>').join(' & ');
    }
  }
  const p=simulcastPartnerStation(s);
  if(!p)return '<strong>'+s.callLetters+'</strong>';
  const {lead,rcv}=simulcastPairLeadReceiver(s,p);
  return '<strong>'+callDisplay(lead)+'</strong> & <strong>'+callDisplay(rcv)+'</strong>';
}
/** Combined share for messaging when simulcast; else this leg’s share. */
function milestoneRankSharePct(s){
  if(s._simulcastSource===true){
    const rec=simulcastGroupReceivers(s.id,G);
    if(rec.length){
      return shn(s.rat.share+rec.reduce((sum,r)=>sum+r.rat.share,0));
    }
  }
  if(s.simulcastSourceStationId){
    const lead=G.stations.find(t=>t.id===s.simulcastSourceStationId);
    if(lead){
      const rec=simulcastGroupReceivers(lead.id,G);
      return shn(lead.rat.share+rec.reduce((sum,r)=>sum+r.rat.share,0));
    }
  }
  const p=simulcastPartnerStation(s);
  if(!p)return shn(s.rat.share);
  const {lead,rcv}=simulcastPairLeadReceiver(s,p);
  return shn(lead.rat.share+rcv.rat.share);
}
function scrollModalContentToTop(overlayId){
  const ov=document.getElementById(overlayId);
  if(!ov)return;
  const mo=ov.querySelector('.mo');
  if(!mo)return;
  mo.scrollTop=0;
  requestAnimationFrame(()=>{mo.scrollTop=0;});
  setTimeout(()=>{mo.scrollTop=0;},0);
}

// ── STATION RESEARCH CONSULTANT + LISTENER FEEDBACK ───────────────
const RESEARCH_CONSULTANT_BASE = 40000;
/** Scales consultant report fee with inflation, market billing depth, tier, and portfolio size. */
function researchConsultantReportCost(s,G){
  const mkt=MARKETS[G?.marketId||ACTIVE_MARKET]||MARKETS.atlanta;
  const rs=Math.max(0.42,Math.min(8,Number(mkt.revScale)||1));
  const revPow=Math.pow(rs,0.38);
  const tier=mkt.rankTier||'medium';
  const tierX=tier==='mega'?1.10:tier==='large'?1.04:0.96;
  const nOwn=Math.max(1,(G.ps||[]).filter(st=>st&&st.isPlayer).length);
  const cluster=1+0.028*Math.max(0,nOwn-1);
  const raw=RESEARCH_CONSULTANT_BASE*salInflMultiplier(G?.year||1970)*revPow*tierX*cluster;
  return Math.max(12000,Math.round(raw/500)*500);
}
function _lfsHash32(str){
  let h=0;
  const s=String(str||'');
  for(let i=0;i<s.length;i++)h=Math.imul(31,h)+s.charCodeAt(i)|0;
  return h>>>0;
}
function _lfsMulberry32(seed){
  let a=seed>>>0;
  return function(){
    a+=0x6d2b79f5;
    let t=a;
    t=Math.imul(t^t>>>15,t|1);
    t^=t+Math.imul(t^t>>>7,t|61);
    return((t^t>>>14)>>>0)/4294967296;
  };
}
/**
 * Free, noisy “street” lines — grounded in sim state, not raw stats. 3–6 lines; mix of categories.
 * @param {number} [nonce] — change to reshuffle (e.g. Date.now()).
 */
function buildListenerFeedbackLines(s,G,nonce){
  if(!s||!G)return[];
  if(isTutorialTurnaroundScen()&&s.isPlayer&&(G.tutorialAct===2||G.tutorialAct===3)&&MP.mode!=='live'){
    return[
      '“Sounds old — like something my parents had on in the kitchen.”',
      '“Midday is dull; I only really listen in the morning.”',
      '“Everyone at the office talks about the FM stations now.”',
    ];
  }
  const rng=_lfsMulberry32(_lfsHash32(`${s.id}|${G.turn||0}|${G.period||1}|${nonce||0}|${G.marketId||''}`));
  const pick=a=>a[Math.floor(rng()*a.length)];
  const maybeFlip=p=>rng()<p;
  const call=callDisplay(s);
  const fmtLab=fmtLabel(s.format,G.year);
  const musicHeavy=!s.isPublic&&!TALK_FMTS.includes(s.format)&&s.format!=='ALL_NEWS';
  const buckets=[];
  const push=(tag,line)=>{if(line&&String(line).trim())buckets.push({tag,line:String(line).trim()});};

  const share=s.rat?.share||0;
  const hist=s.rat?.hist||[];
  const prev=hist.length>=2?hist[hist.length-2]?.share??share:share;
  const dq=(s.cp&&typeof s.cp.dq==='number')?s.cp.dq:0;
  const momUp=dq>0.003||share>prev*1.025;
  const momDn=dq<-0.003||share<prev*0.975;

  if(momUp&&!maybeFlip(0.12))push('station',pick([
    `Coffee-shop take: ${call} sounds like it’s got a little wind in the sails lately.`,
    `Listeners mention ${call} more often this book — not scientific, but the buzz is up.`,
    `Street-level read: people think ${call} is punching above where it was a few months ago.`,
  ]));
  else if(momDn&&!maybeFlip(0.12))push('station',pick([
    `Some regulars say ${call} doesn’t feel as “must-listen” as it used to.`,
    `You hear grumbling that ${call} has lost a step — could be noise, could be real.`,
    `A few callers said they’re sampling other buttons more than ${call} lately.`,
  ]));
  else push('station',pick([
    `Mixed bag on ${call} — half the room says “fine,” half wants something to change.`,
    `${call} still has fans; nobody agrees whether it’s hot, cold, or just there.`,
  ]));

  const fmd=FM[canonicalHitsFormatKey(s.format)]||{};
  const spotN=fmd.sp||14;
  const rv=(s.ops?.spots||spotN)/spotN;
  if(rv>1.18&&!maybeFlip(0.18))push('sound',pick(musicHeavy?[
    `Complaint line: “Too many spots back-to-back.” (Then they sat through six minutes of ads.)`,
    `Some say ${call} feels cluttered — like a sales meeting with music between.`,
  ]:[
    `Complaint line: “Too many spots back-to-back.” (Then they sat through six minutes of ads.)`,
    `Some say ${call} feels clogged — long stop-sets eating the show.`,
  ]));
  else if(rv<0.88&&!maybeFlip(0.2))push('sound',pick([
    `Odd compliment: “Doesn’t feel as greedy as the other guys.”`,
    `A listener said ${call} “breathes” more than the competition — make of that what you will.`,
  ]));
  else if(!maybeFlip(0.35))push('format',pick(musicHeavy?[
    `The ${fmtLab} crowd is opinionated — a few swear the mix got sharper; others want the old clock back.`,
    `PD gossip: ${fmtLab} on ${call} is either “finally clicking” or “stuck in a rut,” depending who you ask.`,
  ]:[
    `The ${fmtLab} crowd is opinionated — some say the lineup “found its voice”; others miss what it used to be.`,
    `Water-cooler take: ${fmtLab} on ${call} is either “must-listen” or “background noise,” depending who you ask.`,
  ]));

  const fmtAge=s._formatAge||0;
  if(fmtAge>0&&fmtAge<5&&!maybeFlip(0.25))push('format',pick([
    `Reaction to the recent format move is still all over the map — too early for a verdict.`,
    `Some love the new direction; others ask “what happened to my station?”`,
  ]));

  const talentOpts=[];
  const slotsShuf=[...DAYPART_SLOTS];
  for(let i=slotsShuf.length-1;i>0;i--){
    const j=Math.floor(rng()*(i+1));
    const t=slotsShuf[i];slotsShuf[i]=slotsShuf[j];slotsShuf[j]=t;
  }
  slotsShuf.forEach(sl=>{
    const t=s.prog?.[sl]?.talent;
    if(!t)return;
    const scout=Math.round(t.quality||0);
    const tru=talentTrueQuality(t);
    const gap=scout-tru;
    const ten=t.periodsAtStation||0;
    const nm=t.name.split(/\s+/)[0]||'the host';
    let line=null;
    if(ten<4){
      if(Math.abs(gap)>5){
        if(gap>5&&!maybeFlip(0.22))line=pick([
          `${nm} gets talked about — not everyone’s convinced yet.`,
          `Early word on ${nm}: sounds confident on the air; jury’s out with listeners.`,
        ]);
        else if(gap<-5&&!maybeFlip(0.2))line=pick([
          `Whisper chain: ${nm} might be outperforming what people expected.`,
          `Some listeners are surprised how quickly ${nm} is growing on them.`,
        ]);
      }
      if(!line&&!maybeFlip(0.3))line=pick([
        `Mixed calls on ${nm} — half the board loves the energy, half wants the old voice back.`,
        `It’s too soon to know if ${nm} is a hit; the phones are noisy either way.`,
      ]);
    }else{
      if(scout>72&&tru>68&&!maybeFlip(0.15))line=pick([
        `${nm} has that “people actually like them” energy lately.`,
        `Afternoon coffee consensus: ${nm} is one of the stronger voices on the dial.`,
      ]);
      else if(tru<52&&!maybeFlip(0.12))line=pick([
        `Honest chatter: a few loyal listeners are tiring of ${nm}’s act.`,
        `Someone said ${nm} “means well” — which is never entirely a compliment.`,
      ]);
      else if(!maybeFlip(0.35))line=pick([
        `${nm} is a known quantity now — fans defend them; haters dial anyway.`,
      ]);
    }
    if(line)talentOpts.push(line);
  });
  if(talentOpts.length)push('talent',pick(talentOpts));

  const comm=G.stations.filter(o=>o&&!o._bpSlotDeferred&&!o.isPublic&&o.rat&&o.id!==s.id)
    .sort((a,b)=>(b.rat.share||0)-(a.rat.share||0));
  const rival=comm[0];
  if(rival&&(rival.rat?.share||0)>(share*1.08)&&!maybeFlip(0.28)){
    const rc=callDisplay(rival);
    push('competitor',pick([
      `Water-cooler line: “Everyone’s sampling ${rc} this month.”`,
      `${rc} is the name that keeps coming up when people talk “who’s winning.”`,
      `Your rival ${rc} still owns a lot of the conversation — fair or not.`,
    ]));
  }else if(rival&&!maybeFlip(0.4)){
    push('competitor',pick([
      `${callDisplay(rival)} gets mentioned — sometimes as threat, sometimes as punchline.`,
      `Competitive dial: listeners compare you to ${callDisplay(rival)} whether you want them to or not.`,
    ]));
  }

  const isAM=s.sig?.type==='AM'&&!s.fmBooster;
  const fmp=G.fmp||0.5;
  if(isAM&&fmp>0.55&&G.year>=1978&&!maybeFlip(0.3))
    push('market',pick([
      `Younger ears keep saying “I only use AM for games/traffic” — FM is where music lives.`,
      `Car talk: more dashboards on FM; AM loyalists swear by habit, not trend.`,
    ]));
  if(s.simulcastWith){
    const p=G.stations.find(st=>st.id===s.simulcastWith);
    if(p&&p.isPlayer){
      const am=s.sig.type==='AM'?s:p;
      const fm=s.sig.type==='FM'||s.fmBooster?s:p;
      if(am&&fm&&(fm.rat?.share||0)>(am.rat?.share||0)*1.15&&!maybeFlip(0.25))
        push('market',pick([
          `Listeners gravitate to the FM leg — the AM still matters to some, but FM feels “main.”`,
          `Street read: the FM side is picking up buzz; AM is the heritage anchor.`,
        ]));
    }
  }
  if(G.year>=1995&&!maybeFlip(0.45))
    push('market',pick([
      `Satellite and streams get name-dropped more — terrestrial still argues it’s “real radio.”`,
      `Market mood: consolidation chatter everywhere; listeners mostly want fewer commercials.`,
    ]));

  if(!maybeFlip(0.55)){
    const flavorMusic=[
      `One caller said your DJ talks too much — then talked for four straight minutes.`,
      `Someone insisted you play the same songs daily. They sang along to prove it.`,
    ];
    const flavorSpoken=[
      `One caller said the host talks too much — then talked for four straight minutes.`,
      `Someone keeps calling in about “the old show” — nobody agrees which old show.`,
    ];
    const flavorAny=[
      `“Pretty good, actually,” one listener said about mornings. High praise from that guy.`,
      `A complaint ended with “still better than the other station.” Radio love is complicated.`,
      `PD gut: the phones are liars, but they’re your liars.`,
    ];
    push('flavor',pick([...(musicHeavy?flavorMusic:flavorSpoken),...flavorAny]));
  }

  for(let i=buckets.length-1;i>0;i--){
    const j=Math.floor(rng()*(i+1));
    const t=buckets[i];buckets[i]=buckets[j];buckets[j]=t;
  }
  const want=4+Math.floor(rng()*3);
  const used=new Set();
  const out=[];
  const preferOrder=['station','talent','format','sound','competitor','market','flavor'];
  preferOrder.forEach(tag=>{
    if(out.length>=want)return;
    const b=buckets.find(x=>x.tag===tag&&!used.has(x.line));
    if(b){used.add(b.line);out.push(b.line);}
  });
  buckets.forEach(b=>{
    if(out.length>=want)return;
    if(!used.has(b.line)){used.add(b.line);out.push(b.line);}
  });
  return out.slice(0,want);
}
function _listenerFeedbackHtml(lines){
  if(!lines||!lines.length)return'<p class="di" style="color:var(--mut)">No buzz right now — check back next period.</p>';
  return'<ul id="listener-feedback-list" style="margin:0;padding-left:18px;line-height:1.55;font-size:14px;color:var(--off)">'+
    lines.map(l=>'<li style="margin-bottom:10px">'+wlEscapeHtml(l)+'</li>').join('')+'</ul>';
}
/** Book line for consultant report header (year + Arbitron-style season). */
function consultantReportBookLabel(year,period){
  return `${year||1970} ${PERIODS[(period||1)-1]}`;
}
function renderResearchModalBody(sid,listenerNonce){
  const s=G.stations.find(st=>st.id===sid);
  if(!s)return'';
  let cost=researchConsultantReportCost(s,G);
  const tutorialFree=isTutorialTurnaroundScen()&&G.tutorialAct===2&&!G._tutorialConsultantDone&&MP.mode!=='live';
  if(tutorialFree)cost=0;
  const lines=buildListenerFeedbackLines(s,G,listenerNonce);
  const canAfford=G.cash>=cost;
  const cache=s._consultantReportCache;
  const cacheLabel=cache&&typeof cache.year==='number'?consultantReportBookLabel(cache.year,cache.period):'';
  const hasCache=cache&&cache.html&&cacheLabel;
  return`<div class="ibox" id="wl-tu-tr-research-feedback-block" style="margin-bottom:16px;text-align:left;border-color:rgba(245,166,35,.25)">
    <div style="font-size:12px;color:var(--amb);letter-spacing:.12em;margin-bottom:6px">FREE — LISTENER FEEDBACK</div>
    <p class="di" style="margin:0 0 10px">Here&apos;s a taste of some of the feedback we&apos;re getting from listeners, focus groups and people in the business.</p>
    ${_listenerFeedbackHtml(lines)}
  </div>
  <div style="border-top:1px solid var(--bdh);margin:16px 0;padding-top:14px"></div>
  <div id="wl-tu-tr-research-consultant-block">
  <div style="font-size:12px;color:var(--grn);letter-spacing:.12em;margin-bottom:6px">PAID — CONSULTANT REPORT</div>
  <p class="di">Structured analysis for <strong>${s.callLetters}</strong> — signal, competition, quality, format health, and recommendations. Clearer than the rumor mill.</p>
  ${hasCache?`<div class="ibox" style="margin-bottom:14px;text-align:left;border-color:rgba(52,211,153,.35)">
    <div style="font-size:12px;color:var(--grn);letter-spacing:.08em;margin-bottom:6px">SAVED REPORT</div>
    <p class="di" style="margin:0 0 10px">Last consultant memo: <strong>${cacheLabel}</strong>. Read it again for free until you commission a new one.</p>
    <button type="button" class="cfm" onclick="viewCachedConsultantReport('${s.id}')" style="margin-bottom:0">READ SAVED REPORT</button>
  </div>`:''}
  <div class="ibox">Report fee: <strong>${f$(cost)}</strong>${tutorialFree?' <span style="color:var(--grn);font-size:13px">(waived — tutorial)</span>':''}<br/>Cash on hand: <strong>${f$(G.cash)}</strong>${!canAfford?' <span style="color:var(--red)">— insufficient funds</span>':''}${hasCache?'<br/><span style="font-size:12px;color:var(--mut)">A new report replaces the saved memo.</span>':''}</div>
  <button type="button" class="cfm" id="wl-tu-tr-research-consultant" onclick="doResearch('${s.id}')" ${!canAfford?'disabled':''}>${hasCache?'COMMISSION NEW REPORT':'COMMISSION CONSULTANT REPORT'} — ${f$(cost)}</button>
  <button class="cnl" onclick="cm('m-research')">CANCEL</button>
  </div>`;
}
function openResearch(sid){
  sid=ensureOpsSourceSid(sid);
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  document.getElementById('research-title').textContent=`📊 RESEARCH — ${s.callLetters}`;
  const rb=document.getElementById('researchb');
  rb.innerHTML=renderResearchModalBody(sid,Date.now());
  om('m-research');
  tutorialTurnaroundOnResearchOpened();
  wlFtTutorialNotifyResearchOpen();
  if(isTutorialTurnaroundScen()&&G?.tutorialMode&&MP.mode!=='live'&&(G.tutorialAct|0)===2&&!G._tutorialConsultantDone&&(G._tutorialResearchCoachStep|0)===0)
    G._tutorialResearchCoachStep=1;
  if(isTutorialTurnaroundScen()&&G?.tutorialMode&&MP.mode!=='live'&&(G.tutorialAct|0)===2)
    requestAnimationFrame(()=>tutorialTurnaroundCoachAfterRender());
}
/** Re-display last purchased consultant HTML for this station (no charge). */
function viewCachedConsultantReport(sid){
  sid=ensureOpsSourceSid(sid);
  const s=G.stations.find(st=>st.id===sid);
  const c=s?._consultantReportCache;
  if(!s||!c||!c.html)return;
  const label=typeof c.year==='number'?consultantReportBookLabel(c.year,c.period):'';
  document.getElementById('researchb').innerHTML=
    `<div class="ibox" style="margin-bottom:14px;font-size:13px;color:var(--mut);border-color:rgba(52,211,153,.35)">Consultant report · <strong style="color:var(--off)">${label}</strong></div>`+
    c.html+
    `<div style="margin-top:18px;padding-top:12px;border-top:1px solid var(--bdh)"><button type="button" class="cnl" onclick="openResearch('${s.id}')">← BACK TO RESEARCH</button></div>`+
    `<button class="cnl" style="margin-top:12px" onclick="cm('m-research')">CLOSE</button>`;
}
function doResearch(sid){
  sid=ensureOpsSourceSid(sid);
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  let cost=researchConsultantReportCost(s,G);
  if(isTutorialTurnaroundScen()&&G.tutorialAct===2&&!G._tutorialConsultantDone&&MP.mode!=='live')cost=0;
  if(G.cash<cost)return;
  G.cash-=cost;
  if(MP.mode==='live') MP.emit('player_cash_update',{playerId:MP.playerId,cash:G.cash});
  const report=buildResearchReport(s,G);
  s._consultantReportCache={html:report,year:G.year,period:G.period};
  const bookLbl=consultantReportBookLabel(G.year,G.period);
  document.getElementById('researchb').innerHTML=
    `<div class="ibox" style="margin-bottom:14px;font-size:13px;color:var(--mut);border-color:rgba(245,166,35,.25)">Consultant report · <strong style="color:var(--off)">${bookLbl}</strong></div>`+
    report+
    `<div style="margin-top:18px;padding-top:12px;border-top:1px solid var(--bdh)"><button type="button" class="cnl" onclick="openResearch('${s.id}')">← BACK TO RESEARCH</button></div>`+
    `<button class="cnl" style="margin-top:12px" onclick="cm('m-research')">CLOSE</button>`;
  if(isTutorialTurnaroundScen()&&G.tutorialAct===2&&!G._tutorialConsultantDone&&MP.mode!=='live')tutorialTurnaroundOnConsultantDone();
  renderAll();
}

// ── TRADE PRESS RATINGS DIGEST (server: ShortAPI and/or OpenAI) ─────────
function wlEscapeHtml(str){
  return String(str).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
const WL_DIGEST_SEASON={SPR:'Spring',FAL:'Fall'};
function wlRatingsDigestSeasonWord(period){
  const code=PERIODS[(period||1)-1];
  return WL_DIGEST_SEASON[code]||code||'';
}
/** Modal headline, e.g. "Los Angeles: Fall 1989" */
function wlRatingsDigestHeadline(payload){
  return `${payload.market}: ${wlRatingsDigestSeasonWord(payload.period)} ${payload.year}`;
}
function wlRatingsDigestBookSig(book){
  const s=book.map(r=>String(r.rank)+','+String(r.call)+','+String(r.brand||'')+','+String(r.sharePct)).join('|');
  let h=0;
  for(let i=0;i<s.length;i++)h=Math.imul(31,h)+s.charCodeAt(i)|0;
  return String(h);
}
function wlRatingsDigestContextSig(lines){
  const s=(lines||[]).join('\f');
  let h=0;
  for(let i=0;i<s.length;i++)h=Math.imul(31,h)+s.charCodeAt(i)|0;
  return String(h);
}
/**
 * Explicit sports broadcast-rights facts for the ratings digest (OpenRouter payload `marketContext`).
 * Ensures the model can tie share moves to rights + season standing, not only incidental news lines.
 */
function wlCollectRatingsDigestSportsContext(G){
  if(!G?.sportsRights||!G.teamRecords)return[];
  const mkt=MARKETS[G.marketId||ACTIVE_MARKET]||MARKETS.atlanta;
  const teams=mkt.teams||[];
  const out=[];
  for(let ti=0;ti<teams.length;ti++){
    const team=teams[ti];
    if(G.year<team.introduced)continue;
    const rights=G.sportsRights[team.id];
    if(!rights||!rights.holderId)continue;
    const holder=G.stations.find(st=>st.id===rights.holderId);
    const call=holder?callDisplay(holder):String(rights.holderName||'').trim();
    if(!call)continue;
    const rec=G.teamRecords[team.id];
    const tier=rec?sportsTierFromRecord(rec.record):'competitive';
    const recStr=rec&&Number.isFinite(rec.record)?`${rec.record}/100`:'—';
    const sportLab=SPORT_LABEL[team.sport]||String(team.sport||'');
    let line=`📋 ${team.name} (${sportLab}): broadcast rights — ${call}. Season standing ${recStr} (${tier}) — ratings model applies a sports broadcast bonus to the holder by format fit.`;
    const p=holder&&holder.simulcastWith?G.stations.find(st=>st.id===holder.simulcastWith):null;
    if(p&&!p._bpSlotDeferred)line+=` Simulcast ${callDisplay(p)} shares the halo.`;
    out.push(line.length>400?line.slice(0,397)+'…':line);
    if(out.length>=16)break;
  }
  return out;
}
/** Player simulcast groups so the digest mentions AM+FM or LMA legs, not just the book row. */
function wlCollectRatingsDigestSimulcastContext(G){
  if(!G?.stations)return[];
  const seen=new Set();
  const out=[];
  const starSrc=G.stations.filter(s=>s&&!s._bpSlotDeferred&&s.isPlayer&&s.rat&&s._simulcastSource===true);
  for(let i=0;i<starSrc.length;i++){
    const s=starSrc[i];
    if(seen.has(s.id))continue;
    const recv=simulcastGroupReceivers(s.id,G).filter(r=>r.isPlayer&&!r._bpSlotDeferred);
    if(!recv.length)continue;
    seen.add(s.id);
    recv.forEach(r=>seen.add(r.id));
    const op=simulcastOperationalSource(s);
    const comb=(s.rat.share||0)+recv.reduce((sum,r)=>sum+(r.rat.share||0),0);
    const legs=[s,...recv].map(x=>callDisplay(x)).join(' + ');
    const lmaStation=s._lmaStation?s:recv.find(r=>r._lmaStation);
    const lma=!!lmaStation;
    const feeNote=lma?` LMA fee on leased leg ~${f$(lmaFeeForStation(lmaStation,G))}/period.`:'';
    let line=`◈ Simulcast: ${legs} — combined ~${(comb*100).toFixed(1)}% share${lma?' (includes LMA-operated leg)':''}. Programming hub: ${callDisplay(op)}.${feeNote}`;
    if(line.length>400)line=line.slice(0,397)+'…';
    out.push(line);
    if(out.length>=10)break;
  }
  const playerStns=G.stations.filter(s=>s&&!s._bpSlotDeferred&&s.isPlayer&&s.rat&&s.simulcastWith);
  for(let i=0;i<playerStns.length;i++){
    const s=playerStns[i];
    const a=s.id,b=s.simulcastWith;
    const key=a<b?a+'|'+b:b+'|'+a;
    if(seen.has(key))continue;
    const p=G.stations.find(st=>st.id===s.simulcastWith);
    if(!p||p.simulcastWith!==s.id||p._bpSlotDeferred)continue;
    seen.add(key);
    const op=simulcastOperationalSource(s);
    const comb=(s.rat.share||0)+(p.rat.share||0);
    const lma=s._lmaStation||p._lmaStation;
    const feeNote=lma?` LMA fee on leased leg ~${f$(lmaFeeForStation(s._lmaStation?s:p,G))}/period.`:'';
    let line=`◈ Simulcast: ${callDisplay(s)} + ${callDisplay(p)} — combined ~${(comb*100).toFixed(1)}% share${lma?' (includes LMA-operated leg)':''}. Programming hub: ${callDisplay(op)}.${feeNote}`;
    if(line.length>400)line=line.slice(0,397)+'…';
    out.push(line);
    if(out.length>=10)break;
  }
  return out;
}
/** Headlines from this period's in-game news for the OpenRouter trade digest (not the ticker). */
function wlCollectRatingsDigestMarketContext(G, maxLines, maxChars){
  maxLines=maxLines!=null?maxLines:20;
  maxChars=maxChars!=null?maxChars:4800;
  if(!G||!G.news)return[];
  const y=G.year,p=G.period;
  const skipRe=/^📊 .* book —|^📊 .* pulse|^📊 .* pulse \(more\)|^Your book —|^📡 Host |^📡 You are|^🎙 Multiplayer|^📡 .* disconnected|^📡 .* reconnected|^📉 Spring ad market|^📈 Fall ad market/i;
  const wantRe=/📋|📻|🏢|⚡|💸|📢|⚠|📡|syndication|rights|franchise|LMA|acquires|reformat|simulcast|translator|poach|pledge drive|repositions|signs on —|Swapped |consolidation|broadcast rights|goes dark|survival|abandons|management shakeup|courting|terminal decline/i;
  const out=[];
  let chars=0;
  for(let i=0;i<G.news.length;i++){
    const n=G.news[i];
    if(!n||n.y!==y||n.p!==p||!n.t)continue;
    if(skipRe.test(n.t))continue;
    const line=String(n.t).replace(/\s+/g,' ').trim();
    if(line.length<14)continue;
    if(!wantRe.test(line))continue;
    if(out.indexOf(line)>=0)continue;
    const slice=line.length>340?line.slice(0,337)+'…':line;
    out.push(slice);
    chars+=slice.length;
    if(out.length>=maxLines||chars>=maxChars)break;
  }
  return out;
}
/** Aligns with server digest tier. Used for cache keys + UI. */
function wlRatingsDigestInsightsTier(){
  const slug=wlClerkPlanSlug();
  if(slug==='pro')return 'elite';
  if(slug==='trial_user'||slug==='starter')return 'advanced';
  return 'standard';
}
function wlRatingsDigestCacheKey(payload){
  const ctxSig=wlRatingsDigestContextSig(payload.marketContext||[]);
  const tier=wlRatingsDigestInsightsTier();
  return `${payload.market}\t${payload.year}\t${payload.period}\t${wlRatingsDigestBookSig(payload.book)}\t${ctxSig}\t${tier}`;
}
function wlRatingsDigestCache(){
  if(typeof window==='undefined')return null;
  if(!window.__WL_RATINGS_DIGEST_CACHE)window.__WL_RATINGS_DIGEST_CACHE=Object.create(null);
  return window.__WL_RATINGS_DIGEST_CACHE;
}
function wlSanitizeDigestFilenamePart(s){
  const t=String(s||'market').replace(/[^\w\u00C0-\u024F]+/g,'-').replace(/^-|-$/g,'').slice(0,44);
  return t||'market';
}
function wlRenderRatingsDigestBody(body,payload,articleText,insightsTier){
  const headline=wlRatingsDigestHeadline(payload);
  const tier=
    insightsTier==='elite'?'elite':insightsTier==='advanced'?'advanced':'standard';
  if(typeof window!=='undefined'){
    window.__wlDigestModal={payload,article:String(articleText||''),headline,insightsTier:tier};
  }
  const paras=String(articleText||'').split(/\n\s*\n+/).map(p=>p.trim()).filter(Boolean);
  const bodyHtml=paras.length
    ? paras.map(p=>'<p style="margin:0 0 14px;font-size:15px;line-height:1.55;color:var(--off);text-align:left">'+wlEscapeHtml(p).replace(/\n/g,'<br/>')+'</p>').join('')
    : '<p class="enote">Empty response.</p>';
  const tierNote=
    tier==='elite'
      ? ' · Pro insights — extended Desk notes &amp; competitive snapshot'
      : tier==='advanced'
        ? ' · Advanced insights (trial / Starter)'
        : ' · Standard column (free tier or not signed in)';
  body.innerHTML=
    '<div style="font-family:var(--fd);font-size:22px;color:var(--amb);letter-spacing:.06em;text-align:center;margin:0 0 10px;line-height:1.25">'+wlEscapeHtml(headline)+'</div>'+
    '<div class="ibox" style="margin-bottom:14px;font-family:var(--ft);font-size:12px;color:var(--mut);line-height:1.45;text-align:center">'+wlEscapeHtml(payload.periodLabel+' · '+payload.market)+' · AI flavor text from simulation data only'+tierNote+'</div>'+
    bodyHtml+
    '<div style="display:flex;flex-wrap:wrap;gap:10px;margin-top:18px;align-items:center;justify-content:flex-start">'+
    '<button type="button" class="cnl" onclick="wlExportRatingsDigestFromModal()">EXPORT .TXT</button>'+
    '<button type="button" class="cnl" style="opacity:.9" onclick="wlRegenerateRatingsDigest()">NEW COLUMN</button>'+
    '<button type="button" class="cnl" onclick="cm(\'m-ratings-digest\')">CLOSE</button></div>';
}
function wlExportRatingsDigestFromModal(){
  const st=typeof window!=='undefined'&&window.__wlDigestModal;
  if(!st||!st.payload||st.article==null){showToast('Nothing to export.','warn');return;}
  const p=st.payload;
  const headline=st.headline||wlRatingsDigestHeadline(p);
  const bom='\uFEFF';
  const footer='— Airwave Empire · ratings digest from simulation data only · exported '+new Date().toISOString().slice(0,10);
  const text=[headline,'',String(st.article).trim(),'',footer].join('\n');
  const blob=new Blob([bom+text],{type:'text/plain;charset=utf-8'});
  const a=document.createElement('a');
  const fn='Ratings-Digest-'+wlSanitizeDigestFilenamePart(p.market)+'-'+p.year+'-'+wlSanitizeDigestFilenamePart(wlRatingsDigestSeasonWord(p.period))+'.txt';
  a.href=URL.createObjectURL(blob);
  a.download=fn;
  a.rel='noopener';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(a.href);
  showToast('Download started.','info');
}
function wlRegenerateRatingsDigest(){
  openRatingsDigestTradeSheet({regenerate:true});
}
function wlBuildRatingsDigestPayload(){
  if(!G||!G.stations)return null;
  const mkt=MARKETS[G.marketId||ACTIVE_MARKET]?.label||'Market';
  const periodLabel=`${G.year} ${PERIODS[(G.period||1)-1]}`;
  const comm=G.stations.filter(s=>s&&!s._bpSlotDeferred&&!s.isPublic&&s.rat)
    .sort((a,b)=>stationCardDisplayShare01(b)-stationCardDisplayShare01(a));
  const book=comm.map((s,i)=>{
    const call=callDisplay(s);
    const br=(typeof s.brand==='string'&&s.brand.trim())?s.brand.trim():defaultPlayerStationBrand(s);
    const brand=String(br||'').trim().slice(0,72);
    const sh01=stationCardDisplayShare01(s);
    return{
      rank:i+1,
      call,
      brand,
      format:fmtLabel(s.format,G.year),
      sharePct:Math.round(sh01*1000)/10,
      deltaPts:(()=>{
        const h=s.rat?.hist;
        if(h&&h.length>=2){
          const cur=h[h.length-1]?.share,prev=h[h.length-2]?.share;
          if(typeof cur==='number'&&typeof prev==='number'&&!Number.isNaN(cur)&&!Number.isNaN(prev))
            return Math.round((cur-prev)*1000)/10;
        }
        const dpc=stationCardDisplayCp(s);
        return dpc&&typeof dpc.dq==='number'?Math.round(dpc.dq*1000)/10:null;
      })(),
      band:(s.sig?.type==='FM'||s.fmBooster)?'FM':'AM',
    };
  });
  const sportsCtx=wlCollectRatingsDigestSportsContext(G);
  const newsCtx=wlCollectRatingsDigestMarketContext(G);
  const simCtx=wlCollectRatingsDigestSimulcastContext(G);
  const marketContext=[...sportsCtx,...newsCtx,...simCtx].slice(0,24);
  return {market:mkt,periodLabel,year:G.year,period:G.period,book,marketContext};
}
async function openRatingsDigestTradeSheet(opts){
  const regenerate=opts&&opts.regenerate===true;
  const body=document.getElementById('ratings-digestb');
  const title=document.getElementById('ratings-digest-title');
  if(!body||!title)return;
  title.textContent='📰 TRADE PRESS — RATINGS DIGEST';
  const payload=wlBuildRatingsDigestPayload();
  if(!payload||!payload.book.length){
    showToast('No ratings data yet.','warn');
    return;
  }
  const cacheKey=wlRatingsDigestCacheKey(payload);
  const cache=wlRatingsDigestCache();
  const cached=cache&&cache[cacheKey];
  if(!regenerate&&cached&&typeof cached.article==='string'&&cached.article.length>20){
    const ct=cached.insightsTier===undefined?wlRatingsDigestInsightsTier():cached.insightsTier;
    wlRenderRatingsDigestBody(body,payload,cached.article,ct);
    om('m-ratings-digest');
    scrollModalContentToTop('m-ratings-digest');
    return;
  }
  if(regenerate&&cache)delete cache[cacheKey];
  body.innerHTML='<p class="di" style="color:var(--mut)">Commissioning column from the trade desk…</p>';
  om('m-ratings-digest');
  scrollModalContentToTop('m-ratings-digest');
  try{
    const res=await fetch(wlGameApiUrl('/api/ratings-digest'),{
      method:'POST',
      headers:await wlGameApiAuthJsonHeaders(),
      body:JSON.stringify({payload}),
    });
    const data=await res.json().catch(()=>({}));
    if(!res.ok||!data.ok){
      const err=data.error||data.message||('HTTP '+res.status);
      const hint404='<p class="enote" style="margin-top:12px;line-height:1.5"><strong>HTTP 404</strong> almost always means the browser called the wrong host: <code>/api/ratings-digest</code> only exists on the <strong>Node</strong> server. If the game HTML is on static hosting (or a different domain) than the API, set <code>VITE_GAME_SERVER_URL</code> in <code>.env</code> before <code>npm run build</code>, or add <code>&lt;meta name="wl-game-server-url" content="https://your-api-origin"&gt;</code> to <code>play.html</code> (no trailing slash). Local dev: run <code>node server.js</code> on :3000 and use <code>npm run client:dev</code> so Vite proxies <code>/api</code>, or play from <code>http://localhost:3000</code> after a build.</p>';
      const hint429='<p class="enote" style="margin-top:12px;line-height:1.5"><strong>HTTP 429</strong> = too many requests. The <strong>game server</strong> limits digest calls per IP per hour (raise <code>RATINGS_DIGEST_MAX_PER_HOUR</code> in server <code>.env</code>, or use <code>0</code> for unlimited in local dev). If the error text mentions OpenRouter, their API is throttling you — wait, switch model, or check <a href="https://openrouter.ai/activity" target="_blank" rel="noopener">openrouter.ai</a>.</p>';
      const hintDefault='<p class="enote" style="margin-top:12px;line-height:1.5">If the API was reached: configure a digest backend on the server (see <code>.env.example</code>) — <strong>OPENROUTER_API_KEY</strong> (recommended), and/or <strong>SHORTAPI_KEY</strong> / <strong>OPENAI_API_KEY</strong>. Restart <code>server.js</code> after editing <code>.env</code>.</p>';
      const hintExtra=res.status===404?hint404:res.status===429?hint429:hintDefault;
      body.innerHTML='<p class="di" style="color:var(--red)">'+wlEscapeHtml(err)+'</p>'+hintExtra+
        '<button type="button" class="cnl" style="margin-top:14px" onclick="cm(\'m-ratings-digest\')">CLOSE</button>';
      return;
    }
    const article=String(data.article||'');
    const insightsTier=
      data.insightsTier==='elite'?'elite':data.insightsTier==='advanced'?'advanced':'standard';
    if(cache)cache[cacheKey]={article,insightsTier};
    wlRenderRatingsDigestBody(body,payload,article,insightsTier);
    scrollModalContentToTop('m-ratings-digest');
  }catch(e){
    body.innerHTML='<p class="di" style="color:var(--red)">'+wlEscapeHtml(e.message||String(e))+'</p><button type="button" class="cnl" style="margin-top:14px" onclick="cm(\'m-ratings-digest\')">CLOSE</button>';
  }
}
/** Share delta for consultant modules — prefers ratings pass `cp.dq` when present. */
function researchStationShareDelta(st){
  if(!st||!st.rat)return 0;
  if(st.cp&&typeof st.cp.dq==='number')return st.cp.dq;
  const hist=st.rat.hist||[];
  const cur=st.rat.share||0;
  const prev=hist.length>=2?hist[hist.length-2]?.share??cur:cur;
  return cur-prev;
}
/** 0–1 proxy for audience overlap between formats (not measured diary transfer). */
function researchFormatAudienceAffinity(fmtA,fmtB){
  if(!fmtA||!fmtB)return 0.12;
  if(fmtA===fmtB)return 1;
  const adj=FMT_COMPETITION[fmtA]||[];
  if(adj.includes(fmtB))return 0.78;
  const rev=FMT_COMPETITION[fmtB]||[];
  if(rev.includes(fmtA))return 0.66;
  const la=formatEcologyLaneId(fmtA);
  const lb=formatEcologyLaneId(fmtB);
  if(la===lb&&la!==String(fmtA))return 0.48;
  return 0.15;
}
function consultantMemoSection(title,bodyHtml){
  return'<div class="ms2" style="margin-top:12px"><div class="msh" style="border-bottom:1px solid var(--bdh);padding-bottom:6px;margin-bottom:10px;letter-spacing:.06em">'+title+'</div>'+
    '<div style="font-size:14px;line-height:1.55;color:var(--off)">'+bodyHtml+'</div></div>';
}
function consultantBulletList(items){
  if(!items||!items.length)return'';
  return'<ul style="margin:8px 0 0;padding-left:20px;line-height:1.5">'+items.map(x=>'<li style="margin-bottom:8px">'+x+'</li>').join('')+'</ul>';
}
function buildResearchReport(s,G){
  const fmd=FM[canonicalHitsFormatKey(s.format)]||{};
  const year=G.year;
  const fmp=G.fmp;

  // ── SIGNAL HEALTH ──
  const isAM=s.sig.type==='AM'&&!s.fmBooster;
  const isFM=s.sig.type==='FM'||s.fmBooster;
  const amMusicFmts=['TOP40','COUNTRY','SOUL_RNB','MOR','ALBUM_ROCK','BEAUTIFUL_MUSIC',
    'CLASSIC_ROCK','ADULT_CONTEMP','URBAN_CONTEMP','ALT_ROCK','RHYTHMIC','HOT_AC','CLASSIC_HITS',
    'SPANISH','GOSPEL','OLDIES','ADULT_STANDARDS'];
  const isAMMusic=isAM&&amMusicFmts.includes(s.format);
  const amViab=(()=>{
    if(year<=1975)return 1.0;
    if(year<=1978)return 1.0-(year-1975)*0.02;
    if(year<=1985)return 0.94-(year-1978)*0.06;
    if(year<=1993)return 0.52-(year-1985)*0.05;
    return Math.max(0.12,0.12-(year-1993)*0.005);
  })();
  const amPenalty=isAMMusic?Math.max(0.10,(1.0-0.60*fmp)*amViab):1.0;
  const isTalkAM=isAM&&['NEWS_TALK','ALL_NEWS','SPORTS_TALK','GOSPEL','PODCAST_TALK'].includes(s.format);

  // ── COMPETITION ──
  const compFmts=FMT_COMPETITION[s.format]||[];
  const directCompetitors=G.stations.filter(o=>o&&!o._bpSlotDeferred&&o.id!==s.id&&compFmts.includes(o.format));
  const sameFormat=G.stations.filter(o=>o&&!o._bpSlotDeferred&&o.id!==s.id&&o.format===s.format);
  const totalCompCount=directCompetitors.length;
  const competitionBleed=Math.min(0.22,COMPETITION_BLEED*(totalCompCount/5));

  // ── QUALITY ──
  const oq=s.oq||50;
  const qFactor=oq/65;

  // ── SHARE TREND ──
  const hist=s.rat.hist||[];
  const cur=s.rat.share;
  const prev=hist.length>=2?hist[hist.length-2]?.share||cur:cur;
  const two=hist.length>=3?hist[hist.length-3]?.share||cur:cur;
  const trending=cur>prev*1.03?'UP':cur<prev*0.97?'DOWN':'FLAT';
  const trendColor=trending==='UP'?'var(--grn)':trending==='DOWN'?'var(--red)':'var(--mut)';

  // ── SPOT LOAD ──
  const rv=s.ops.spots/(fmd.sp||14);
  const spotIssue=rv>1.15;
  const spotSevere=rv>1.3;

  // ── SATURATION / STREAMING ──
  const satDrag=G.satDrag||0;
  const streamDrag=G.streamDrag||0;

  // ── FORMAT SUNSET ──
  const FORMAT_SUNSET={BEAUTIFUL_MUSIC:{peak:1985,dead:1995},MOR:{peak:1982,dead:1998},FULL_SERVICE:{peak:1960,dead:1975}};
  const fs2=FORMAT_SUNSET[s.format];
  let eraViab=1.0;
  if(fs2){
    if(year>=fs2.dead)eraViab=0.02;
    else if(year>fs2.peak){const t=(year-fs2.peak)/(fs2.dead-fs2.peak);eraViab=Math.max(0.02,1-(3*t*t-2*t*t*t)*0.98);}
  }

  // ── RANK vs COMPETITION ──
  const allByShare=[...G.stations].filter(s=>s&&!s._bpSlotDeferred&&s.rat).sort((a,b)=>b.rat.share-a.rat.share);
  const rank=allByShare.findIndex(st=>st.id===s.id)+1;
  const total=allByShare.length;

  const call=callDisplay(s);
  const comm=G.stations.filter(o=>o&&!o._bpSlotDeferred&&!o.isPublic&&o.rat&&o.id!==s.id);
  const myDq=researchStationShareDelta(s);
  let memoNarrowDifferentiation=false;

  // ── CONSULTANT ANALYTIC MODULES (structured memo — not listener chatter) ──
  const leadSameFmt=sameFormat.length?[...sameFormat].sort((a,b)=>(b.rat.share||0)-(a.rat.share||0))[0]:null;
  const topOtherFmt=comm.filter(o=>o.format!==s.format).sort((a,b)=>(b.rat.share||0)-(a.rat.share||0))[0];

  const flowParas=[];
  if(myDq<-0.001){
    const scored=comm.map(o=>{
      const od=researchStationShareDelta(o);
      if(od<=0.0006)return null;
      const aff=researchFormatAudienceAffinity(s.format,o.format);
      const w=aff*(0.035+od)*(0.025+(o.rat.share||0));
      return{o,w};
    }).filter(Boolean).sort((a,b)=>b.w-a.w);
    const top=scored.slice(0,2).map(x=>x.o);
    if(top.length){
      const dest=top.map(o=>callDisplay(o)+' ('+fmtLabel(o.format,year)+')').join(', ');
      flowParas.push('<p style="margin:0 0 8px"><strong>Soft book:</strong> Share is down; the best-fitting alternate homes for some of that listening look like <strong>'+dest+'</strong>.</p>');
    }else{
      flowParas.push('<p style="margin:0 0 8px"><strong>Soft book:</strong> No single rival mirrors your loss — listening likely splitting across several stations.</p>');
    }
  }
  if(myDq>0.001){
    const losers=comm.map(o=>{
      const od=researchStationShareDelta(o);
      if(od>=-0.0008)return null;
      const aff=researchFormatAudienceAffinity(s.format,o.format);
      return{o,w:aff*Math.abs(od)};
    }).filter(Boolean).sort((a,b)=>b.w-a.w);
    if(losers.length){
      const picks=losers.slice(0,2).map(x=>callDisplay(x.o));
      flowParas.push('<p style="margin:0 0 8px"><strong>Up book:</strong> Part of your gain lines up with slippage at <strong>'+picks.join('</strong> and <strong>')+'</strong>.</p>');
    }
  }
  if(topOtherFmt&&(topOtherFmt.rat.share||0)>Math.max(0.04,cur*0.88)){
    const td=researchStationShareDelta(topOtherFmt);
    if(td>=myDq-0.001)
      flowParas.push('<p style="margin:0 0 8px"><strong>Cross-format pressure:</strong> '+callDisplay(topOtherFmt)+' ('+fmtLabel(topOtherFmt.format,year)+') pulls as much weight as many same-format rivals.</p>');
  }
  if(!flowParas.length){
    flowParas.push('<p style="margin:0">No strong flow signal — moves are incremental this book.</p>');
  }
  const audienceFlowHtml=consultantMemoSection('AUDIENCE FLOW / DEFECTION ANALYSIS',flowParas.join(''));

  let positioningHtml='';
  const gds=getDrift(s);
  const posParas=[];
  if(gds&&gds.cfg){
    const v=gds.val;
    const t=(v??50)/100;
    if(t<0.38){
      posParas.push('<p style="margin:0 0 8px"><strong>Lane:</strong> Reads <strong>'+gds.cfg.poleA.name+'</strong> — softer / broader than the format’s aggressive edge.</p>');
    }else if(t>0.62){
      posParas.push('<p style="margin:0 0 8px"><strong>Lane:</strong> Sits <strong>'+gds.cfg.poleB.name+'</strong> — harder / younger than mid-pack.</p>');
    }else{
      posParas.push('<p style="margin:0 0 8px"><strong>Lane:</strong> Mid-pack '+fmtLabel(s.format,year)+' — familiar, not sharply differentiated by sound alone.</p>');
    }
    if(sameFormat.length&&leadSameFmt){
      let sum=0,cn=0;
      sameFormat.forEach(o=>{
        const gd=getDrift(o);
        if(gd&&typeof gd.val==='number'){sum+=gd.val;cn++;}
      });
      if(cn){
        const avg=sum/cn;
        if(Math.abs(v-avg)<9){
          memoNarrowDifferentiation=true;
          posParas.push('<p style="margin:0 0 8px"><strong>Overlap:</strong> Sound profile almost matches <strong>'+callDisplay(leadSameFmt)+'</strong> — listeners won’t separate you on format alone.</p>');
        }else if(v>avg+11){
          posParas.push('<p style="margin:0 0 8px"><strong>Vs same-format pack:</strong> Hotter than average — closer to <strong>'+gds.cfg.poleB.name+'</strong>.</p>');
        }else if(v<avg-11){
          posParas.push('<p style="margin:0 0 8px"><strong>Vs same-format pack:</strong> Milder than average — closer to <strong>'+gds.cfg.poleA.name+'</strong>.</p>');
        }
      }
    }
  }else{
    posParas.push('<p style="margin:0 0 8px">No sound-axis slider for this format — image comes from brand, talent, and promotion.</p>');
  }
  const dl=s.demoLean||0;
  if(dl<-0.28)posParas.push('<p style="margin:0"><strong>Demo:</strong> Skew <strong>young</strong> — watch rhythmic / rock / urban flanks.</p>');
  else if(dl>0.28)posParas.push('<p style="margin:0"><strong>Demo:</strong> Skew <strong>old</strong> — vulnerable to younger-positioned stations.</p>');
  positioningHtml=consultantMemoSection('POSITIONING / PERCEPTION',posParas.join(''));

  let wSum=0,wTot=0;
  DAYPART_SLOTS.forEach(sl=>{const w=SW[sl]||0.1;wSum+=(s.prog?.[sl]?.quality||0)*w;wTot+=w;});
  const wAvg=wTot?wSum/wTot:50;
  const talentBullets=[];
  DAYPART_SLOTS.forEach(sl=>{
    const sd=s.prog?.[sl];
    const t=sd?.talent;
    const q=Math.round(sd?.quality||0);
    const lab=SL[sl]||sl;
    if(!t){
      talentBullets.push('<strong>'+lab+':</strong> No fixed host — compare to staffed dayparts at competitors.');
      return;
    }
    const ten=t.periodsAtStation|0;
    const settling=(t._perfRevealStepsLeft|0)>0&&!t._talentPerfRevealed;
    const first=t.name.split(/\s+/)[0]||'Host';
    let line='<strong>'+lab+':</strong> '+first+' — ';
    if(settling)line+='still settling; books can lie early — give it another trend unless phones crater.';
    else if(q>=wAvg+9)line+='<strong>Strength</strong> vs your other dayparts.';
    else if(q<=wAvg-9)line+='<strong>Weak link</strong> vs the rest of the clock.';
    else line+='Roughly in line with the rest of the schedule.';
    if(ten<4&&!settling)line+=' New to the station.';
    talentBullets.push(line);
  });
  if(isTutorialTurnaroundScen()&&MP.mode!=='live'&&s.isPlayer&&s.prog?.midday?.talent){
    const midTag='<strong>'+SL.midday+':</strong>';
    const weakPhrase='<strong>Weak link</strong> vs the rest of the clock.';
    const softPhrase='Roughly in line with the rest of the schedule.';
    for(let i=0;i<talentBullets.length;i++){
      const b=talentBullets[i];
      if(b.startsWith(midTag)){
        const t=s.prog.midday.talent;
        const first=(t.name||'Host').split(/\s+/)[0];
        talentBullets[i]=midTag+' '+first+' — '+weakPhrase;
      }else if(b.includes(weakPhrase)){
        talentBullets[i]=b.replace(weakPhrase,softPhrase);
      }
    }
  }
  const talentDaypartHtml=consultantMemoSection('TALENT / DAYPART PERFORMANCE',consultantBulletList(talentBullets));

  const prodParas=[];
  if(spotSevere)prodParas.push('<p style="margin:0 0 8px"><strong>Spots:</strong> Well over format norm — likely hurting tolerance.</p>');
  else if(spotIssue)prodParas.push('<p style="margin:0 0 8px"><strong>Spots:</strong> Above norm — first lever if trend weakens.</p>');
  else prodParas.push('<p style="margin:0 0 8px"><strong>Spots:</strong> At or under norm.</p>');
  const fa=s._formatAge|0;
  if(fa>0&&fa<6)prodParas.push('<p style="margin:0 0 8px"><strong>Format:</strong> Recent change — audience still adjusting.</p>');
  const idN=s.identity|0;
  if(idN<26)prodParas.push('<p style="margin:0 0 8px"><strong>Brand:</strong> Not yet clearly defined in-market.</p>');
  else if(idN>64)prodParas.push('<p style="margin:0 0 8px"><strong>Brand:</strong> Strong familiarity — defend before others copy the clock.</p>');
  else prodParas.push('<p style="margin:0 0 8px"><strong>Brand:</strong> Average recognition.</p>');
  if(trending==='DOWN'&&!spotIssue)prodParas.push('<p style="margin:0"><strong>Product:</strong> Spots aren’t the obvious culprit — check library depth and overlap next.</p>');
  const productHtml=consultantMemoSection('PROGRAMMING / PRODUCT',prodParas.join(''));

  let weakSlot=DAYPART_SLOTS.find(sl=>{
    const sd=s.prog?.[sl];
    return sd?.talent&&Math.round(sd.quality||0)<=wAvg-9;
  });
  if(isTutorialTurnaroundScen()&&MP.mode!=='live'&&s.isPlayer&&s.prog?.midday?.talent)
    weakSlot='midday';
  const avgCompQ=directCompetitors.length?Math.round(directCompetitors.reduce((a,c)=>a+(c.oq||50),0)/directCompetitors.length):null;
  const slotQs=DAYPART_SLOTS.map(k=>Math.round(s.prog?.[k]?.quality||0)).filter(q=>q>0);
  const maxSlotQ=slotQs.length?Math.max(...slotQs):0;
  const minSlotQ=slotQs.length?Math.min(...slotQs):99;
  const scheduleImb=slotQs.length>=2&&maxSlotQ-minSlotQ>16&&rank<=Math.ceil(total*0.65);

  const strBul=[];
  if(rank<=3)strBul.push('Top-three share in the market.');
  if(trending==='UP')strBul.push('Share up vs last book.');
  if(sameFormat.length===0)strBul.push('Sole same-format station — you own the lane.');
  if((s.identity||0)>=55)strBul.push('Solid brand familiarity for this format life.');

  const weakBul=[];
  if(weakSlot)weakBul.push(SL[weakSlot]+' underperforming vs rest of schedule');
  if(scheduleImb)weakBul.push('Large gap between strongest and weakest dayparts');
  if(memoNarrowDifferentiation&&leadSameFmt)weakBul.push('Minimal differentiation vs '+callDisplay(leadSameFmt));
  else if(sameFormat.length>=2)weakBul.push('Crowded '+fmtLabel(s.format,year)+' lane ('+sameFormat.length+' rivals)');
  if(rank>Math.ceil(total*0.55))weakBul.push('Below-median rank');
  if(trending==='DOWN')weakBul.push('Share down vs last book');
  if(spotIssue)weakBul.push('Heavy spot load');
  if(isAMMusic&&amPenalty<0.55)weakBul.push('AM music structurally weak vs FM');
  if(idN<26)weakBul.push('Weak brand definition');
  if(fa>0&&fa<6)weakBul.push('Recent format change — still bedding in');
  if(myDq<-0.001)weakBul.push('Negative share momentum this book');
  if(avgCompQ!=null&&oq<avgCompQ-6)weakBul.push('Overall quality below adjacent-format set');

  const riser=comm.filter(o=>researchStationShareDelta(o)>0.002).sort((a,b)=>researchStationShareDelta(b)-researchStationShareDelta(a))[0];
  const vulnerable=comm.filter(o=>(o.rat.share||0)>0.035&&researchStationShareDelta(o)<-0.0015).sort((a,b)=>(b.rat.share||0)-(a.rat.share||0))[0];
  const compObsPick=[];
  if(riser&&(!topOtherFmt||riser.id!==topOtherFmt.id))compObsPick.push(callDisplay(riser)+' ('+fmtLabel(riser.format,year)+') is rising fast.');
  else if(vulnerable)compObsPick.push(callDisplay(vulnerable)+' is big but leaking — possible target if formats line up.');
  const keyCompLines=[];
  if(leadSameFmt)keyCompLines.push('<strong>Same format:</strong> '+callDisplay(leadSameFmt));
  if(topOtherFmt&&(!leadSameFmt||topOtherFmt.id!==leadSameFmt.id))
    keyCompLines.push('<strong>Other format:</strong> '+callDisplay(topOtherFmt)+' ('+fmtLabel(topOtherFmt.format,year)+')');
  let compLandBody='<p style="margin:0">#'+rank+' of '+total+' · '+(cur*100).toFixed(1)+'% · Trend '+pill(trending,trendColor)+'</p>';
  if(keyCompLines.length)compLandBody+='<p style="margin:10px 0 0;font-size:14px;line-height:1.45">'+keyCompLines.slice(0,2).join('<br/>')+'</p>';
  if(compObsPick.length)compLandBody+='<p style="margin:10px 0 6px;font-size:12px;color:var(--mut)">Watch</p>'+consultantBulletList(compObsPick);
  const competitiveLandscapeHtml=consultantMemoSection('COMPETITIVE LANDSCAPE',compLandBody);

  const simPartnerR=s.simulcastWith?G.stations.find(st=>st.id===s.simulcastWith):null;
  const simPairOk=!!(simPartnerR&&simPartnerR.simulcastWith===s.id&&!simPartnerR._bpSlotDeferred);
  const simPlayerPair=simPairOk&&mpIsMe(s)&&mpIsMe(simPartnerR);
  let simulcastOverviewHtml='';
  if(simPlayerPair){
    const combinedShareOv=(s.rat.share+simPartnerR.rat.share);
    const combinedRevOv=(s.fin.rev||0)+(simPartnerR.fin.rev||0);
    const srcOv=simulcastProgrammingSource(s)||s;
    const lmaLeg=s._lmaStation?s:simPartnerR._lmaStation?simPartnerR:null;
    const lmaNote=lmaLeg?`<p style="margin:8px 0 0;font-size:12px;color:var(--mut)">LMA fee on the leased leg is <strong>${f$(lmaFeeForStation(lmaLeg,G))}</strong>/period. The follower facility can still show a large cost line — that reflects facility and fixed ops for that license, not a mis-print of the LMA fee.</p>`:'';
    simulcastOverviewHtml=consultantMemoSection('SIMULCAST PAIR',`<p style="margin:0 0 8px">Combined audience across both signals: <strong>${(combinedShareOv*100).toFixed(1)}%</strong> share · combined revenue (both licenses): <strong>${f$(combinedRevOv)}</strong>/period.</p><p style="margin:0;font-size:13px;color:var(--off)">Sections below focus on <strong>${callDisplay(s)}</strong> (this leg’s book). Programming hub: <strong>${callDisplay(srcOv)}</strong>.</p>${lmaNote}`);
  }

  const swHtml=consultantMemoSection('STRENGTHS / WEAKNESSES',
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:4px">'+
    '<div><div style="font-size:12px;color:var(--grn);letter-spacing:.08em;margin-bottom:6px">STRENGTHS</div>'+(strBul.length?consultantBulletList(strBul):'<p style="margin:0;color:var(--mut)">No standout positives — roughly average.</p>')+'</div>'+
    '<div><div style="font-size:12px;color:var(--red);letter-spacing:.08em;margin-bottom:6px">WEAKNESSES / RISKS</div>'+(weakBul.length?consultantBulletList(weakBul):'<p style="margin:0;color:var(--mut)">Nothing major flagged — still read Talent and Flow for edge cases.</p>')+'</div></div>');

  // ── BUILD SECTIONS ──
  function row(label,val,note,color){
    return `<div class="sr"><span class="lb">${label}</span><span class="vl" style="color:${color||'var(--off)'}">${val}</span>${note?`<span style="font-size:15px;color:var(--mut);margin-left:8px">${note}</span>`:''}</div>`;
  }
  function hdr(t){return `<div class="msh" style="margin-top:14px">${t}</div>`;}
  function pill(txt,col){return `<span style="background:${col}22;color:${col};border:1px solid ${col}44;padding:2px 7px;border-radius:4px;font-size:15px;font-family:var(--ft);letter-spacing:.05em">${txt}</span>`;}

  // SIGNAL section
  let sigSection=hdr('SIGNAL');
  if(isFM){
    sigSection+=row('Signal type','FM — full penetration','FM reaches all receivers in your footprint','var(--grn)');
    const pwRanks={'100kw':4,'50kw':3,'25kw':2,'10kw':1,'5kw':1,'1kw':0};
    const pw=s.fmBooster?'translator':s.sig.pw;
    if(pw==='translator')sigSection+=row('Power','FM Translator','Low-power signal. Limited reach compared to full-power FM.','var(--amb)');
    else sigSection+=row('Power',pw.toUpperCase(),'','var(--off)');
  } else if(isTalkAM){
    const amTalkPenalty = (G.year>=2007&&['NEWS_TALK','SPORTS_TALK','ALL_NEWS'].includes(s.format)&&!stationHasSimulcastLeg(s,G))
      ? Math.round((1-Math.max(0.55, 1.0-_smoothstep(2007,2015,G.year)*0.20-_smoothstep(2015,2022,G.year)*0.20))*100)
      : 0;
    const amTalkColor = amTalkPenalty>=20?'var(--red)':amTalkPenalty>=8?'var(--ylw)':'var(--grn)';
    const amTalkNote = amTalkPenalty>0
      ? `AM signal eroding: -${amTalkPenalty}% audience reach vs FM/digital. FM simulcast eliminates this.`
      : `News, Talk and Sports are the AM-native formats. Music AM erosion doesn't apply.`;
    sigSection+=row('Signal type','AM — Talk/News native', amTalkNote, amTalkColor);
    if(s.clearChannel)sigSection+=row('Clear-channel AM (Class A)','Unlimited night power','No nighttime directionality. Signal covers the full region at night, expanding your effective audience by ~18%. Revenue premium applies through 1995.','var(--amb)');
    else if(s.sig.pw==='DA')sigSection+=row('Reduced night power','50kW day · 1-5kW night','Still on air 24/7 — night power is lower and often directional to protect clear-channel co-channels. Fringe listeners lose you in evening drive. Effective reach ≈ 72% of a full-time 50kW. An FM simulcast or translator eliminates this.','var(--red)');
    else if(s.sig.pw==='50kw')sigSection+=row('50kW Directional','50kW day / reduced night','Power drops and signal rotates at night to protect clear-channel stations. Daytime market coverage only.','var(--mut)');
    sigSection+=row('AM Talk viability',`${Math.round(amViab*100)}%`,year>=1990?'AM talk still strong but FM competitors emerging.':year>=1985?'Some FM competition for News/Talk emerging.':'Full AM advantage for talk formats.','var(--grn)');
    // Even NT AM gets an FMP note — listeners in cars are increasingly on FM, even for talk
    const fmpPct=Math.round(fmp*100);
    if(year>=1995)sigSection+=row('FM penetration',`${fmpPct}%`,`${fmpPct}% of listening is FM-capable. AM talk still reaches this audience, but FM talk signals are starting to compete.`,'var(--amb)');
  } else if(isAMMusic){
    const viabPct=Math.round(amPenalty*100);
    const viabColor=amPenalty>0.7?'var(--grn)':amPenalty>0.4?'var(--amb)':'var(--red)';
    sigSection+=row('Signal type','AM — Music format','AM music stations face audience defection to FM as FM penetration rises.','var(--red)');
    if(s.clearChannel)sigSection+=row('Clear-channel AM (Class A)','Unlimited night power','No nighttime power reduction. Wider coverage buys time vs non-clear-channel AM music stations — but FM erosion still applies to all AM music formats.','var(--amb)');
    else if(s.sig.pw==='DA')sigSection+=row('Reduced night power','50kW day · 1-5kW night','Still on air 24/7 with lower night power. Fringe listeners lose the signal in evening drive — when music radio is most valuable. High incentive to get an FM signal.','var(--red)');
    else if(s.sig.pw==='50kw')sigSection+=row('50kW Directional','50kW day / reduced night','Power drops and signal rotates at night. Same erosion penalties as other AM music.','var(--mut)');
    if(s.fmBooster){
      const _tFracR=Math.min(1,(s.sig.universe||0.32)/Math.max(s._boosterOrigSig?.universe||0.85,0.01));
      const _fringePct=Math.round((1-_tFracR)*100);
      const _tColor=_tFracR>=0.8?'var(--grn)':_tFracR>=0.5?'var(--amb)':'var(--red)';
      sigSection+=row('FM translator coverage',`${Math.round(_tFracR*100)}% of AM footprint`,`${_fringePct}% of your AM audience (the fringe beyond the translator) still can't receive FM and continues eroding. A full FM license eliminates this entirely.`,_tColor);
    } else {
      sigSection+=row('AM music viability',`${viabPct}% of potential`,`FM penetration is ${Math.round(fmp*100)}%. Listeners migrate to FM music. Consider reformatting to AM-native content or acquiring an FM.`,viabColor);
    }
  }

  // QUALITY section
  let qSection=hdr('QUALITY BENCHMARK');
  const qColor=oq>=70?'var(--grn)':oq>=50?'var(--amb)':'var(--red)';
  qSection+=row('Overall quality',`${oq}/100`,'','var(--off)');
  const qNotes=[];
  if(oq>=70)qNotes.push('Quality is not your main problem.');
  else if(oq>=50)qNotes.push('Room to grow with programming spend.');
  else qNotes.push('Quality is a liability — fix soon.');
  if(avgCompQ!==null)qSection+=row('Competitor avg quality',`${avgCompQ}/100`,oq>avgCompQ?'Above adjacent-format average.':oq<avgCompQ?'Below that set — invest or upgrade talent.':'About even.',oq>=avgCompQ?'var(--grn)':'var(--red)');
  qSection+=`<div style="font-size:14px;color:var(--mut);padding:4px 0">${qNotes.join(' ')}</div>`;

  // SIMULCAST BREAKDOWN (if this station is in a simulcast)
  let simSection='';
  if(simPlayerPair){
    const amStR=s.sig.type==='AM'?s:simPartnerR;
    const fmStR=s.sig.type==='FM'||s.fmBooster?s:simPartnerR;
    const combinedShare=(s.rat.share+simPartnerR.rat.share);
    const _cs=Math.max(combinedShare,1e-9);
    const amPct=(amStR.rat.share/_cs*100).toFixed(0);
    const fmPct=(fmStR.rat.share/_cs*100).toFixed(0);
    const amAqh=Object.values(amStR.rat.cur||{}).reduce((sum,c)=>sum+(c?.aqh||0),0);
    const fmAqh=Object.values(fmStR.rat.cur||{}).reduce((sum,c)=>sum+(c?.aqh||0),0);
    simSection=hdr('SIMULCAST BREAKDOWN');
    simSection+=row('Combined share',`${(combinedShare*100).toFixed(1)}%`,'Both signals combined','var(--grn)');
    simSection+=row(`${amStR.freq} AM`,`${(amStR.rat.share*100).toFixed(1)}% · ${amPct}% of combined`,`AQH: ${amAqh.toLocaleString()} · Rev: ${f$(amStR.fin.rev)}/period · Cost: ${f$(amStR.fin.cost)}/period`,amStR.rat.share>fmStR.rat.share?'var(--amb)':'var(--mut)');
    simSection+=row(`${fmStR.freq} FM`,`${(fmStR.rat.share*100).toFixed(1)}% · ${fmPct}% of combined`,`AQH: ${fmAqh.toLocaleString()} · Rev: ${f$(fmStR.fin.rev)}/period · Cost: ${f$(fmStR.fin.cost)}/period`,fmStR.rat.share>amStR.rat.share?'var(--amb)':'var(--mut)');
    // Recommendation: if FM is growing and AM is small, suggest migration
    const amTiny=amStR.rat.share<0.02;
    const fmDominant=fmStR.rat.share>amStR.rat.share*2;
    const year2=G.year;
    if(amTiny&&year2>=1985){
      simSection+=`<div style="font-size:14px;color:var(--amb);padding:6px 0">The AM signal contributes only ${amPct}% of your combined audience. Consider whether the AM operating costs justify maintaining the simulcast — you could sell or flip the AM and consolidate on FM.</div>`;
    } else if(fmDominant){
      simSection+=`<div style="font-size:14px;color:var(--mut);padding:6px 0">FM is carrying ${fmPct}% of your audience. The AM simulcast extends your reach to older listeners and in-home/car AM receivers, but your audience gravity has shifted to FM.</div>`;
    } else {
      simSection+=`<div style="font-size:14px;color:var(--mut);padding:6px 0">Your AM and FM are both contributing meaningfully. The simulcast is working — AM brings legacy listeners, FM brings car and younger audiences.</div>`;
    }
  }

  // SPOT LOAD
  let opsSection=hdr('OPERATIONS');
  const spotPct=Math.round(rv*100);
  const spotColor=rv<=1?'var(--grn)':rv<=1.15?'var(--amb)':'var(--red)';
  opsSection+=row('Spot load',`${spotPct}% of format norm`,rv<=1?'Healthy. Not driving listeners away.':rv<=1.15?'Slightly heavy. Minor listener penalty.':rv<=1.3?'Heavy. Noticeably hurting ratings.':'Overloaded. Major ratings drag — cut spots.',spotColor);
  // Community identity row
  const idScore=Math.round(s.identity||0);
  const idLabel=idScore>=70?'Cornerstone':idScore>=45?'Embedded':idScore>=25?'Recognized':idScore>=10?'Emerging':'Unknown';
  const idColor=idScore>=70?'var(--grn)':idScore>=45?'var(--amb)':idScore>=25?'var(--off)':'var(--mut)';
  const fmtYrs=Math.round((s._formatAge||0)/2);
  opsSection+=`<div class="sr" style="cursor:pointer" onclick="openIdent('${s.id}')">
    <span class="lb">Community Identity <span style="color:var(--mut);font-size:14px">(click to manage)</span></span>
    <span class="vl" style="color:${idColor}">${idScore}/100 — ${idLabel}${fmtYrs>=2?' · '+fmtYrs+'yr':''}</span>
  </div>`;
  opsSection+=row('Promotion spend',`${f$(s.ops?.promo||0)}/period`,s.ops?.promo>=10000?'Active campaign running.':'Light or no promotion.','var(--off)');

  // FORMAT SUNSET
  let fmtSection='';
  if(fs2){
    const deadColor=eraViab<0.5?'var(--red)':'var(--amb)';
    fmtSection=hdr('FORMAT HEALTH');
    fmtSection+=row('Era viability',`${Math.round(eraViab*100)}%`,`${fmtLabel(s.format)} peaked ${fs2.peak} and is fading. Transition before ${fs2.dead}.`,deadColor);
  }

  // ── RECOMMENDATIONS ──
  const recs=[];

  if(isAMMusic&&amPenalty<0.5){
    recs.push({sev:'HIGH',txt:`AM music is ~${Math.round((1-amPenalty)*100)}% structurally eroded vs FM — get FM, flip to talk, or exit; promotion won’t fix it.`});
  } else if(isAMMusic&&amPenalty<0.75){
    recs.push({sev:'MED',txt:'AM music window is closing — line up FM, simulcast, or talk within a couple of books.'});
  }

  if(isTalkAM&&year>=1995&&sameFormat.length>0){
    const fmTalkComp=sameFormat.filter(o=>o.sig.type==='FM'||o.fmBooster);
    if(fmTalkComp.length>0){
      recs.push({sev:'MED',txt:`FM talk competitor${fmTalkComp.length>1?'s':''} in-market — keep Q high; add FM leg if you can.`});
    }
  }

  if(avgCompQ!==null&&oq<avgCompQ-10){
    recs.push({sev:'HIGH',txt:`Programming quality (${oq}) trails adjacent-format avg (~${avgCompQ}) — coach, produce, or replace weak slots; aim ~${Math.min(100,avgCompQ+5)}+.`});
  } else if(avgCompQ!==null&&oq<avgCompQ){
    recs.push({sev:'LOW',txt:'Quality slightly under the adjacent-format pack — a programming push helps.'});
  }

  if(spotSevere){
    recs.push({sev:'HIGH',txt:`Cut spots (${spotPct}% of norm) before chasing other fixes — meters notice clutter first.`});
  } else if(spotIssue){
    recs.push({sev:'MED',txt:'Spots above norm — trim if trend slips.'});
  }

  if(fs2&&eraViab<0.6){
    recs.push({sev:'HIGH',txt:`${fmtLabel(s.format)} is fading (~${Math.round(eraViab*100)}% of peak) — plan a move before ${fs2.dead}.`});
  }

  if(sameFormat.length>=2&&!memoNarrowDifferentiation){
    recs.push({sev:'MED',txt:'Crowded lane — win on talent, imaging, and demo focus; not on being louder with the same recipe.'});
  }

  if(weakSlot){
    recs.push({sev:'MED',txt:`${SL[weakSlot]} lags your other dayparts — coach, support, or replace there first.`});
  }
  if(memoNarrowDifferentiation&&leadSameFmt){
    recs.push({sev:'MED',txt:`Open perceptual space vs ${callDisplay(leadSameFmt)} — drift slider, imaging, star dayparts.`});
  }
  if(myDq<-0.002&&topOtherFmt&&(topOtherFmt.rat.share||0)>cur*0.95){
    recs.push({sev:'MED',txt:`Treat ${callDisplay(topOtherFmt)} as a head-to-head rival, not a side threat.`});
  }

  if(recs.length===0){
    recs.push({sev:'OK',txt:'No burning issues — keep investing where you’re winning; watch the next book for drift.'});
  }

  const recRank={HIGH:0,MED:1,LOW:2,OK:3};
  recs.sort((a,b)=>(recRank[a.sev]??9)-(recRank[b.sev]??9));
  const recsTop=recs.slice(0,3);

  const recColors={HIGH:'var(--red)',MED:'var(--amb)',LOW:'var(--off)',OK:'var(--grn)'};
  const recHTML=recsTop.map(r=>`<div style="margin:8px 0;padding:8px 10px;background:${recColors[r.sev]}18;border-left:3px solid ${recColors[r.sev]};font-size:14px;line-height:1.5;color:var(--off)">${pill(r.sev,recColors[r.sev])} ${r.txt}</div>`).join('');

  const tutorialMemo=isTutorialTurnaroundScen()&&G.tutorialAct<=4&&MP.mode!=='live'
    ?`<div class="ibox" style="margin-bottom:14px;border-color:rgba(245,166,35,.35)">
        <div style="font-size:12px;color:var(--amb);letter-spacing:.12em;margin-bottom:8px">TUTORIAL — READ THESE</div>
        <ul style="margin:0;padding-left:18px;line-height:1.55;font-size:14px;color:var(--off)">
          <li><strong>Sounds dated</strong> — the station’s music and imaging read older than where listening is moving.</li>
          <li><strong>Midday weak</strong> — middays trail the rest of your clock; drive times are carrying you.</li>
          <li><strong>Losing ground to FM</strong> — younger ears and music-first habits are on the FM dial.</li>
        </ul>
      </div>`
    :'';

  return `${tutorialMemo}${simulcastOverviewHtml}
    <div class="ms2">
      <div class="msh" style="display:flex;justify-content:space-between;align-items:center">
        <span>CONSULTANT REPORT — OVERVIEW</span>
        <span style="font-size:15px;color:var(--mut)">${G.city} · ${G.year}</span>
      </div>
      <p class="di" style="margin:0 0 10px;font-size:13px;color:var(--mut)">Paid memo — not Listener Feedback.</p>
      ${row('Station',call,'','var(--off)')}
      ${row('Format',fmtLabel(s.format),'','var(--off)')}
      ${row('Signal',`${s.sig.type} · ${signalPowerDisplayLabel(s.sig.pw)}`,'','var(--off)')}
      ${row('Share',`${(cur*100).toFixed(1)}%`,`Trend: ${pill(trending,trendColor)}`,'var(--off)')}
    </div>
    ${audienceFlowHtml}
    ${positioningHtml}
    ${talentDaypartHtml}
    ${productHtml}
    ${competitiveLandscapeHtml}
    ${swHtml}
    <div class="ms2" style="margin-top:12px">
      ${sigSection}
      ${qSection}
      ${simSection}
      ${opsSection}
      ${fmtSection}
    </div>
    <div class="ms2" style="margin-top:12px">
      ${hdr('RECOMMENDATIONS')}
      <p class="di" style="margin:0 0 6px;font-size:12px;color:var(--mut)">Consultant suggestions.</p>
      ${recHTML}
    </div>`;
}


// ── BRAND NAMING ──────────────────────────────────────────────────
let _brandSid=null;
/** Snapshot for BM custom brand field — log on blur if changed */
const _bmBrandSession={};
function bmBrandFocus(sid){
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  _bmBrandSession[sid]=s.brand;
}
function bmBrandBlur(sid){
  /* History + multiplayer sync happen on Apply Brand (or pill pick). */
}
function pickBrand(sid,b){
  _brandSid=sid;
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  const prev=s.brand;
  s.brand=b;
  if((prev||'').trim()!==(b||'').trim()) logHistory(s,'BRAND',`Brand: "${prev}" → "${b}"`,G);
  if(_renameSid===sid) _renameBrandAtOpen=b;
  // Update preview
  const prevEl=document.getElementById('brand-preview');
  if(prevEl)prevEl.textContent='"'+b+'"';
  // Update custom input
  const inp=document.getElementById('brand-custom');
  if(inp)inp.value=b;
  // Re-highlight pills
  document.querySelectorAll('.bp').forEach(el=>{
    el.classList.toggle('bpsel', el.textContent===b);
  });
  renderAll();
}
function updBrand(sid,v){
  _brandSid=sid;
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  s.brand=v||s.brand;
  const prev=document.getElementById('brand-preview');
  if(prev)prev.textContent='"'+(v||s.brand)+'"';
  // Deselect all pills when typing custom
  document.querySelectorAll('.bp').forEach(el=>el.classList.remove('bpsel'));
  renderAll();
}
// ── ADVANCE TURN ──────────────────────────────────────────────────

// ── TALENT EVENTS ─────────────────────────────────────────────────
/** Resolve deferred AI→player poaches (one period to match salary in contract screen). */
function resolvePendingRivalPoaches(G){
  G.ps.forEach(pStn=>{
    const pend=pStn._rivalPoachPending;
    if(!pend)return;
    const afterAnnounce=(G.year>pend.announcedY||(G.year===pend.announcedY&&G.period>pend.announcedP));
    if(!afterAnnounce)return;
    const slot=pend.slot||'morningDrive';
    const sd=pStn.prog[slot];
    const t=sd?.talent;
    const rival=G.stations.find(st=>st.id===pend.rivalId);
    if(!t||t.id!==pend.talentId){
      delete pStn._rivalPoachPending;
      return;
    }
    const nm=t.name;
    const prevCyr=typeof t.cyr==='number'&&!Number.isNaN(t.cyr)?t.cyr:0;
    const buyoutEst=prevCyr>0.1?Math.round(t.salary*prevCyr*0.60/500)*500:0;
    const sitN=wlPoachSitoutPeriodsForDepartingTalent(t);
    sd.talent=null;
    sd.quality=Math.round((sd.quality||30)*0.70);
    if(rival&&rival.prog[slot]){
      const susp0=(t._suspended|0)>0?(t._suspended|0):0;
      rival.prog[slot].talent={
        ...t,
        salary:pend.offerSalary,
        cyr:ri(1,2),
        morale:Math.min(100,(t.morale||65)+5),
        _suspended:Math.max(susp0,sitN),
      };
      rival.prog[slot].quality=Math.min(100,Math.round((rival.prog[slot].quality||30)+t.quality*0.45));
    }
    rival&&(rival._poachCooldown=WL_TALENT_POACH.AI_RIVAL_POACH_COOLDOWN_PERIODS);
    if(rival&&rival.prog[slot]&&rival.prog[slot].talent)wlMarkTalentPoachCourtingTurn(rival.prog[slot].talent,G);
    const buyoutBit=buyoutEst>0?` Rival side reportedly paid ~${f$(buyoutEst)} to unwind ${Math.round(prevCyr*10)/10} yr remaining.`:'';
    const sitBit=sitN>0?` On-air at ${rival?rival.callLetters:'rival'} delayed ~${sitN} period${sitN!==1?'s':''} (non-compete / start date).`:'';
    G.news.unshift({v:'HIGH',t:`🎙 POACHED: ${nm} leaves ${pStn.callLetters} for ${rival?rival.callLetters:'a rival'} — you didn't match their offer in time.${buyoutBit}${sitBit}`,y:G.year,p:G.period,iy:true});
    logHistory(pStn,'TALENT',`${nm} left for ${rival?callDisplay(rival):'rival'} — ${SL[slot]} (contract)`,G);
    if(rival) logHistory(rival,'TALENT',`Signed ${nm} from ${callDisplay(pStn)} — ${SL[slot]}`,G);
    delete pStn._rivalPoachPending;
  });
}

function talentEvents(G){
  const acts=[];
  resolvePendingRivalPoaches(G);
  G.ps.filter(s=>!s.isPublic).forEach(s=>{
    Object.entries(s.prog).forEach(([slot,sd])=>{
      if(!sd?.talent)return;
      const t=sd.talent;
      // Co-host: graceful non-renewal (independent of primary; process before lead leaves this slot)
      const b0=slotTalentB(sd);
      if(b0&&b0._letExpire&&(b0.cyr||0)<=0){
        const cnm=b0.name;
        clearCoHostPairingState(sd);
        setSlotTalentB(sd,null);
        refreshStationOQ(s,G);
        G.news.unshift({v:'MEDIUM',t:`${cnm} (co-host) departs ${s.callLetters} ${SL[slot]} — contract not renewed.`,y:G.year,p:G.period,iy:true});
      }
      // Tenure: single increment per period in decay() — do not mutate here (avoids double-count with talentEvents+decay).
      const age=(t.periodsAtStation||0)+1; // projected end-of-period tenure for event odds (decay runs later)
      if(!t._hireYear)t._hireYear=G.year;
      if(!t._careerStartYear)t._careerStartYear=t._hireYear;

      // GRACEFUL NON-RENEWAL: player chose not to renew
      if(t._letExpire&&(t.cyr||0)<=0){
        const name=t.name;
        sd.talent=null;
        G.news.unshift({v:'MEDIUM',t:`${name} departs ${s.callLetters} ${SL[slot]} — contract not renewed.`,y:G.year,p:G.period,iy:true});
        return;
      }

      // CONTRACT EXPIRY WARNING: give player one period heads-up
      if((t.cyr||0)<=0.5&&(t.cyr||0)>0&&!t._letExpire&&!t._warnedExpiry){
        t._warnedExpiry=true;
        G.news.unshift({v:'MEDIUM',t:`📋 ${t.name}'s contract at ${s.callLetters} expires next period — click their name to negotiate.`,y:G.year,p:G.period,iy:true});
      }
      // Reset warning flag when renewed
      if((t.cyr||0)>1)t._warnedExpiry=false;

      // MANDATORY RETIREMENT: 35-year career cap (calendar years in radio)
      const careerStartYear=Math.min(t._careerStartYear||t._hireYear||G.year,t._hireYear||G.year);
      t._careerStartYear=careerStartYear;
      const careerYears = G.year - careerStartYear;
      if(careerYears >= 35){
        const name=t.name;
        sd.talent=null;
        G.news.unshift({v:'HIGH',t:`🎙 ${name} retires after ${careerYears} years in radio — a true legend of ${s.callLetters} ${SL[slot]}.`,y:G.year,p:G.period,iy:true});
        return;
      }
      // RETIREMENT WARNING: one year heads-up at 34 years
      if(careerYears===34 && !t._retireWarned){
        t._retireWarned=true;
        G.news.unshift({v:'MEDIUM',t:`📋 ${t.name} reaches 35 years in radio next year — they'll be retiring from ${s.callLetters}. Start scouting.`,y:G.year,p:G.period,iy:true});
      }
      // Late-career retirement (calendar years in radio) — reachable during normal play, not save-migration only
      if(careerYears>=26&&careerYears<35&&Math.random()<0.02+Math.max(0,(careerYears-26))*0.018){
        const name=t.name;
        sd.talent=null;
        G.news.unshift({v:'MEDIUM',t:`🎙 ${name} retires from ${s.callLetters} ${SL[slot]} after ${careerYears} years in radio.`,y:G.year,p:G.period,iy:true});
        return;
      }
      // GRACEFUL VOLUNTARY RETIREMENT: quality talent, long tenure, probabilistic
      const retireChance=careerYears>22?0.10:careerYears>18?0.05:age>16?0.04:age>12?0.02:0;
      if(t.quality>70&&Math.random()<retireChance){
        const name=t.name;
        sd.talent=null;
        G.news.unshift({v:'MEDIUM',t:`${name} retires from ${s.callLetters} ${SL[slot]} after a legendary run.`,y:G.year,p:G.period,iy:true});
        return;
      }

      // BURNOUT: low morale — sudden quit.
      const burnoutChance=t.morale<35?0.15:t.morale<50?0.07:0;
      if(Math.random()<burnoutChance){
        const name=t.name;
        sd.talent=null;
        G.news.unshift({v:'HIGH',t:`⚠ ${name} quits ${s.callLetters} ${SL[slot]} — morale collapse. Find a replacement fast.`,y:G.year,p:G.period,iy:true});
        return;
      }

      // POACHING: rival AI stations try to steal star talent (morning drive only) — defer loss; player can match in contract modal
      if(slot==='morningDrive'&&t.quality>72&&Math.random()<WL_TALENT_POACH.TALENT_EVENTS_BASE_CHANCE){
        const rivals=G.stations.filter(st=>st&&!st._bpSlotDeferred&&!st.isPlayer&&st.rat?.share>0.05);
        if(rivals.length&&!s._rivalPoachPending&&wlTalentCanReceivePoachCourtingThisTurn(t,G)&&wlTalentMidContractPoachSeriousOfferRolls(t)){
          const rival=pick(rivals);
          const name=t.name;
          const poachResist=(t.morale/100)*0.5+Math.min(1,(t.cyr||0)/2)*0.5;
          if(Math.random()<poachResist){
            wlMarkTalentPoachCourtingTurn(t,G);
            G.news.unshift({v:'MEDIUM',t:`🎙 ${rival.callLetters} approached ${name} — they stayed loyal to ${s.callLetters}. Consider a renewal.`,y:G.year,p:G.period});
          } else {
            const newSal=Math.round(t.salary*rnd(1.22,1.48)/500)*500;
            s._rivalPoachPending={rivalId:rival.id,slot:'morningDrive',offerSalary:newSal,talentId:t.id,announcedY:G.year,announcedP:G.period,matched:false};
            rival._poachCooldown=WL_TALENT_POACH.AI_RIVAL_POACH_COOLDOWN_PERIODS;
            wlMarkTalentPoachCourtingTurn(t,G);
            G.news.unshift({v:'HIGH',t:`⚡ ${rival.callLetters} is courting ${name} with ${f$(newSal)}/yr — open their contract to match (≥${f$(Math.round(newSal*0.95/500)*500)}/yr) or they may leave next period.`,y:G.year,p:G.period,iy:true});
          }
        }
      }
    });
  });
}

// ── RIVAL REFORMAT ────────────────────────────────────────────────
function rivalReformat(G){
  // Non-commercial public stations are immune to all of this
  const commercialRivals=G.stations.filter(s=>s&&!s._bpSlotDeferred&&!s.isPlayer&&!s.isPublic);
  const ppRf=computeAiPlayerMarketPressure(G);
  const diffRf=resolveAiDifficultyTier(G);
  const pfDom=ppRf.dominantFmt;
  const pPressRf=ppRf.pressure01||0;
  // Formats unavailable after their sunset year
  // Formats unavailable after their sunset — can't reformat INTO a dead format
  const formatSunset={BEAUTIFUL_MUSIC:1995,MOR:1998,FULL_SERVICE:1975};
  const eligibleFormats=Object.keys(FM).filter(f=>
    !FM[f]?.public && f!=='FULL_SERVICE' &&
    formatUnlockedForYear(f,G) &&
    formatAllowedInMarket(f,G.marketId,G.year) &&
    (!formatSunset[f]||G.year<formatSunset[f])
  );

  // Force MOR and BEAUTIFUL_MUSIC rivals into permanent struggle post-sunset trigger year
  // so rivalReformat picks them up quickly even if they somehow still have share
  const FORMAT_FORCE_EXIT={MOR:1983,BEAUTIFUL_MUSIC:1985,FULL_SERVICE:1975};
  commercialRivals.forEach(s=>{
    const exitYear=FORMAT_FORCE_EXIT[s.format];
    if(exitYear&&G.year>=exitYear+2){
      // Been in a dead format 2+ years past trigger — override share check
      s._lowSharePeriods=(s._lowSharePeriods||0)+2; // fast-track to reformat stage
    }
  });

  commercialRivals.forEach(s=>{
    if(!s._lowSharePeriods)s._lowSharePeriods=0;
    const isStruggling=s.rat.share<0.03;
    const laneCrowd=crowdedLaneAlsoRanPressure(s,G);

    if(!isStruggling&&!laneCrowd.active){
      s._lowSharePeriods=Math.max(0,(s._lowSharePeriods||0)-1);
      return;
    }
    s._lowSharePeriods++;
    if(laneCrowd.active){
      const chrCrowded=laneCrowd.laneId==='__lane_chr__';
      if(!isStruggling||chrCrowded)s._lowSharePeriods+=laneCrowd.extraTicks;
    }
    const group=getRivalPortfolioStations(s,G);
    if(group.length>=2){
      const sortedG=group.slice().sort((a,b)=>(b.rat?.share||0)-(a.rat?.share||0));
      const anchor=sortedG[0];
      const portE=group.reduce((a,st)=>a+(st.fin?.ebitda||0),0);
      if(anchor&&s.id!==anchor.id&&portE<-45000&&(s.rat?.share||0)<0.032){
        s._lowSharePeriods++;
      }
    }

    const p=s._lowSharePeriods;
    // Reality timeline: ~2 yrs (4 periods) of patience, then escalating moves
    // Stage 1 (periods 3-5): Cost cuts — fire expensive talent, reduce spots
    if(p>=3&&p<=5&&Math.random()<0.50){
      let fired=false;
      ['morningDrive','afternoonDrive'].forEach(sl=>{
        if(fired)return;
        const sd=s.prog?.[sl];
        if(sd?.talent&&(sd.talent.salary||0)>60000){
          G.news.unshift({v:'LOW',t:`💸 ${s.callLetters} cuts costs — ${sd.talent.name} let go.`,y:G.year,p:G.period});
          sd.talent=null;fired=true;
        }
      });
      // Also reduce spot load toward format norm to improve TSL
      if(s.ops&&s.ops.spots>FM[canonicalHitsFormatKey(s.format)]?.sp){
        s.ops.spots=FM[canonicalHitsFormatKey(s.format)]?.sp||14;
      }
      return;
    }

    // Stage 2 (periods 5-8): Format drift shift — move slider toward safer pole
    if(p>=5&&p<=8&&Math.random()<0.40){
      const _gd=getDrift(s);
      if(_gd){
        const store=hitsDriftStoreKey(s.format);
        const cur=s.drift?.[store];
        if(cur!==undefined){
          const newDrift=Math.max(5,cur-20);
          if(!s.drift)s.drift={};
          s.drift[store]=newDrift;
          G.news.unshift({v:'LOW',t:`📊 ${s.callLetters} repositions toward ${_gd.cfg.poleA.name} — management shakeup.`,y:G.year,p:G.period});
          return;
        }
      }
    }

    // Stage 3 (periods 6+): Reformat — only if consistently bad (archetype + era + inertia bias flip odds)
    if(p>=6){
      ensureAiRivalArchetype(s,G);
      const arch=AI_ARCHETYPE_DEF[s.aiArchetype]||AI_ARCHETYPE_DEF.trend_chaser;
      const era=aiEraStrategicDial(G.year);
      const st=computeAiStrategicState(s,G);
      const fAge=s._formatAge||0;
      let inertiaM=fAge<4?0.32:fAge<10?0.74:1;
      if(s.aiArchetype==='legacy_slow')inertiaM*=0.58;
      if(s.aiArchetype==='trend_chaser')inertiaM*=1.1;
      let flipProb=0.20*era.churn*arch.flipEager*inertiaM;
      if(st==='dominant')flipProb*=arch.dominantFlip;
      else if(st==='desperate')flipProb*=arch.panicFlip;
      else if(st==='troubled')flipProb*=1.07;
      if((s.aiMem?.laneThreat||0)>0.85)flipProb*=s.aiArchetype==='leader_defender'?1.09:1.04;
      if(diffRf>=1&&pPressRf>0.32&&(st==='troubled'||st==='desperate'))flipProb*=1.07;
      if(diffRf>=2&&pPressRf>0.48&&(st==='troubled'||st==='desperate'))flipProb*=1.05;
      if(laneCrowd.active){
        flipProb*=1.44;
        if(laneCrowd.laneId==='__lane_chr__')flipProb*=1.52;
      }
      flipProb=Math.min(0.88,Math.max(0.035,flipProb));
      if(Math.random()>=flipProb)return;
      const candidates=eligibleFormats.filter(f=>
        f!==s.format&&(FM[f]?.unlock||1900)<=G.year&&
        !(FM[f]?.amOnly&&s.sig?.type!=='AM')
      );
      if(!candidates.length)return;
      // Weighted format selection: favor growing formats, penalize oversaturated ones
      const mktComm=G.stations.filter(st=>st&&!st._bpSlotDeferred&&!st.isPublic);
      const fmtCounts={};mktComm.forEach(st=>{fmtCounts[st.format]=(fmtCounts[st.format]||0)+1;});
      const fmtShares={};mktComm.forEach(st=>{fmtShares[st.format]=(fmtShares[st.format]||0)+st.rat.share;});
      const y=G.year||1970;
      // Score each candidate format
      const scored=candidates.map(f=>{
        let score=1.0;
        const share=fmtShares[f]||0;
        const count=fmtCounts[f]||0;
        // Formats with good share but not too crowded are best targets
        if(share>0.08)score*=1.8;
        else if(share>0.05)score*=1.3;
        if(count>=3)score*=0.4; // oversaturated
        else if(count===0)score*=0.6; // unproven in this market
        const laneN=formatEcologyLanePeerCountForFmt(G,f);
        const laneIdCand=formatEcologyLaneId(f);
        if(laneIdCand==='__lane_chr__'){
          if(laneN>=5)score*=0.05;
          else if(laneN>=4)score*=0.20;
          else if(laneN>=3)score*=0.55;
        }else if(laneIdCand==='__lane_spoken_news__'){
          if(laneN>=5)score*=0.15;
          else if(laneN>=4)score*=0.32;
          else if(laneN>=3)score*=0.55;
        }
        // Corporate rivals strongly prefer proven formats
        if(s.pers===PD.CORP_RADIO||s.pers?.ms>=0.85){
          if(['TOP40','COUNTRY','ADULT_CONTEMP','NEWS_TALK'].includes(f))score*=1.5;
        }
        // Bonus for formats completely absent from market — realistic gap-filling
        if((fmtCounts[f]||0)===0&&FM[f]?.unlock<=G.year){
          if(['NEWS_TALK','ALL_NEWS','SPORTS_TALK','COUNTRY','CLASSIC_ROCK'].includes(f))score*=2.5;
        }
        // Maverick/Scrapper more willing to bet on emerging formats
        if(s.pers?.ag>=0.70&&count===0)score*=1.4;
        // Imperfect evaluation — top choice favored, not guaranteed
        score*=1+arch.pickErr*aiSeededNoise(s.id+':'+f,G.turn||0,31);
        if(s.aiArchetype==='trend_chaser'&&y>=1976&&y<=1998){
          if(['TOP40','ADULT_CONTEMP','URBAN_CONTEMP','ALT_ROCK','HOT_AC'].includes(f))score*=1+0.11*era.fmPull;
          if(s.sig?.type==='FM'&&['ALBUM_ROCK','CLASSIC_ROCK'].includes(f))score*=1+0.05*era.fmPull;
        }
        if(s.aiArchetype==='legacy_slow'&&fAge>12&&(FADJ[s.format]||[]).includes(f))score*=1.12;
        if(s.aiArchetype==='conservative_owner')score*=(fmtCounts[f]||0)>=2?1.08:0.94;
        if(s.aiArchetype==='underdog_gambler'&&count===0&&share<0.04)score*=1.15;
        if(pfDom&&pPressRf>0.18&&diffRf>=1){
          const adjacent=(FADJ[pfDom]||[]).includes(f)&&f!==pfDom;
          if(adjacent)score*=1+(0.085+0.105*pPressRf)*(diffRf>=2?1.1:1);
          if(f===pfDom&&(fmtCounts[f]||0)>=3&&pPressRf>0.26)
            score*=0.58+0.24*(1-pPressRf);
        }
        if(diffRf<=0&&pfDom&&pPressRf>0.38&&(FADJ[pfDom]||[]).includes(f)&&f!==pfDom)score*=0.94;
        return {f, score};
      }).sort((a,b)=>b.score-a.score);
      // Weighted random pick — top 3 candidates get most weight
      const pool=scored.slice(0,Math.min(4,scored.length));
      const totalW=pool.reduce((s,x)=>s+x.score,0);
      let r=Math.random()*totalW, newFmt=pool[0].f;
      for(const {f,score} of pool){r-=score;if(r<=0){newFmt=f;break;}}
      const oldFmt=fmtLabel(s.format);
      s.format=newFmt;
      s._aiLastMajorReason='reformat:'+(fmtLabel(newFmt));
      s._lowSharePeriods=0;
      if(!s.drift)s.drift={};
      s.drift[newFmt]=DRIFT[newFmt]?.default||40;
      Object.keys(s.mom||{}).forEach(c=>s.mom[c]={tgt:0.01,cur:0.01});
      s.str='emerging'; // fresh start
      s.launchPeriod=G.turn||0;
      G.news.unshift({v:'MEDIUM',t:`📻 ${s.callLetters} abandons ${oldFmt} → relaunches as ${fmtLabel(newFmt)}.`,y:G.year,p:G.period});
      if(G._aiBench){
        aiBenchInc(G,'rivalReformatsTotal');
        if(pPressRf>=0.22)aiBenchInc(G,'rivalReformatsHighPlayerPressure');
        if(pfDom&&newFmt&&(newFmt===pfDom||(FADJ[pfDom]||[]).includes(newFmt)))
          aiBenchInc(G,'rivalReformatsVsPlayerLane');
      }
    }
  });
}

// ── CONSOLIDATION SYSTEM ──────────────────────────────────────────
// Post-1996 Telecom Act: corporate radio groups acquire independents
// Fictional consolidators (corp ids stable for save compatibility; names are parody)
const CORPS=[
  {id:'clearwave', name:'ClearWave',                 color:'#dc2626', stations:[], budget:50000000, aggression:0.85},
  {id:'cumulus2',  name:'Nimbus Media',              color:'#7c3aed', stations:[], budget:30000000, aggression:0.65},
  {id:'landmark',  name:'Keystone',                  color:'#0369a1', stations:[], budget:5000000, aggression:0.50},
];

function wlHash32(str){
  let h=2166136261>>>0;
  for(let i=0;i<str.length;i++){
    h^=str.charCodeAt(i);
    h=Math.imul(h,16777619)>>>0;
  }
  return h>>>0;
}

/** Fictional licensee for AI commercial stations (not post-1996 corp targets). AM/FM simulcast pairs share one parent. */
const RIVAL_FICTIONAL_PARENTS=[
  // Mix of suffixes — avoid overusing “-cast” so ownership lines don’t all read like parody streamers
  'Veridex Media','Pulseline Media','Redloom Media','Bannera Media','Audentix Media','Signalix Media','Voxaura Media',
  'Tuneway Media','Streamix Media','Airlink Media','Southbeam Media','Oakwave Media','Relaypoint Media','Crestline Media',
  'Blueledger Media','Presspoint Media','Inkwell Media','Ledgerline Media','Masthead Media','Typecase Media','Byline Media','Newsbeam Media','Broadsheet Media','Typeset Media',
  'Fortis Media','Meritline Media','Harborlight Media','Assurix Media','Covenant Media','Fidelis Media','Ashland Media','Whitmore Media',
  'Eastwood Media','Vanderlyn Media','Relayco Media','Trisource Media','Meridian Communications','Summit Radio Group','Prairie Radio Group','Granite Audio Partners','Redbrick Holdings',
  'Silverline Partners','Crescent Networks','Noble Syndicate','Archway Enterprises','Riverside Radio','Midland Signal Group','Falconnest Radio','Greenvalley Communications','Sterling Radio Group','Cumberland Media Group','Ironwood Partners','Lakeshore Networks',
];

function rivalFictionalParentName(s,G){
  if(!s||s.isPlayer||s.isPublic||s._bpSlotDeferred)return '';
  if(s.corpOwner)return '';
  const mkt=String((G&&G.marketId)||ACTIVE_MARKET||'');
  if(s.simulcastWith){
    const a=s.id,b=s.simulcastWith;
    const lo=a<b?a:b,hi=a<b?b:a;
    const key=`${lo}|${hi}`;
    return RIVAL_FICTIONAL_PARENTS[wlHash32(mkt+'::pair::'+key)%RIVAL_FICTIONAL_PARENTS.length];
  }
  return RIVAL_FICTIONAL_PARENTS[wlHash32(mkt+'::st::'+s.id)%RIVAL_FICTIONAL_PARENTS.length];
}

function rivalOwnershipLabel(s,G,isOwn){
  if(!s)return '—';
  if(s.corpOwner)return s.corpName||'Corporate';
  if(s.isPublic)return 'Non-commercial';
  if(s.isPlayer&&!isOwn){
    if(typeof MP!=='undefined'&&MP.mode==='live'&&s._mpOwner!=null){
      const p=(MP.players||[]).find(pl=>pl.playerId===s._mpOwner);
      const nm=p&&typeof p.name==='string'&&p.name.trim()?p.name.trim():'';
      if(nm)return nm;
    }
    return 'Independent operator';
  }
  const fic=rivalFictionalParentName(s,G);
  if(fic)return fic;
  return 'Independent';
}

function initConsolidation(G){
  if(G.corps)return; // already initialized
  G.corps=CORPS.map(c=>({...c,stations:[]}));
}

function rehydrateCorps(G){
  // After save/load, corps.stations[] may be empty even though stations have corpOwner set.
  // Walk stations and re-link them into the correct corp's stations array.
  if(!G.corps)return;
  G.corps.forEach(c=>{ c.stations=[]; });
  G.stations.forEach(s=>{
    if(s.corpOwner&&!s.isPlayer){
      const corp=G.corps.find(c=>c.id===s.corpOwner);
      if(corp&&!corp.stations.includes(s.id)) corp.stations.push(s.id);
    }
  });
}

function runConsolidation(G){
  if(G.year<1996)return[];
  // Always re-sync corps on each call — handles save/load where G.corps may be null
  // even though the 1996 consolidate event already fired.
  if(!G.corps) G.corps=CORPS.map(c=>({...c,stations:[]}));
  // Re-link stations into corp arrays (clears stale data, rebuilds from source of truth)
  G.corps.forEach(c=>{ c.stations=[]; });
  G.stations.forEach(s=>{
    if(s.corpOwner&&!s.isPlayer){
      const corp=G.corps.find(c=>c.id===s.corpOwner);
      if(corp&&!corp.stations.includes(s.id)) corp.stations.push(s.id);
    }
  });
  // Restore corp budgets if they've been zeroed (can happen on reload)
  G.corps.forEach(c=>{
    if(!c.budget||c.budget<500000) c.budget=CORPS.find(t=>t.id===c.id)?.budget||5000000;
  });
  const acts=[];
  const MIN_IND_SHARE=0.012; // ~1.2% — in fragmented markets many independents sit below a flat 2% floor
  const MAX_SPEND_FRAC=0.5; // max single deal as fraction of remaining acquisition budget

  // Each corporate group attempts acquisitions in Fall only (after revenue is known for pricing)
  if(G.period!==2)return[];

  G.corps.forEach(corp=>{
    if(corp.budget<=0)return;
    // High-aggression groups try 1–2 deals; others always attempt at least one pass (old logic gave 60% of years with zero tries)
    const acqCount=corp.aggression>0.75?(Math.random()<0.68?2:1):1;

    for(let i=0;i<acqCount;i++){
      const corpTargetsAM=G.stations.filter(s=>
        !s.isPlayer&&!s.isPublic&&!s.corpOwner&&s.rat.share>MIN_IND_SHARE&&
        (s.sig.type==='AM'||s.fmBooster)&&fccCanAcquire(corp.id,'AM',G)
      );
      const corpTargetsFM=G.stations.filter(s=>
        !s.isPlayer&&!s.isPublic&&!s.corpOwner&&s.rat.share>MIN_IND_SHARE&&
        s.sig.type==='FM'&&!s.fmBooster&&fccCanAcquire(corp.id,'FM',G)
      );
      const targets=[...corpTargetsAM,...corpTargetsFM];
      if(!targets.length)break;

      const scored=targets.map(s=>{
        let score=s.rat.share*100;
        if(s.sig.type==='FM')score*=1.4;
        if(['NEWS_TALK','ALL_NEWS','SPORTS_TALK','TOP40','COUNTRY','ADULT_CONTEMP'].includes(s.format))score*=1.2;
        const ownedFormats=corp.stations.map(id=>G.stations.find(st=>st.id===id)?.format).filter(Boolean);
        if(!ownedFormats.includes(s.format))score*=1.3;
        return {s, score};
      }).sort((a,b)=>b.score-a.score);

      let acquired=null,price=0;
      for(const {s:target} of scored){
        const annualRev=(target.fin.rev||0)*2;
        const multiple=8+Math.random()*4;
        const p=Math.round(annualRev*multiple/100000)*100000;
        if(p>corp.budget*MAX_SPEND_FRAC) continue;
        acquired=target;
        price=p;
        break;
      }
      if(!acquired)break;

      acquired.corpOwner=corp.id;
      acquired.corpName=corp.name;
      acquired.corpColor=corp.color;
      corp.stations.push(acquired.id);
      corp.budget-=price;

      acquired.pers={...PD.CORP_RADIO};
      acquired._corpAcqYear=G.year;
      acquired._qualityDecayRate=0.8;

      const shortName=corp.name.split(' ')[0];
      acts.push({v:'HIGH',
        t:`🏢 ${shortName} acquires ${acquired.callLetters} (${fmtLabel(acquired.format)}) for ~${f$(price)} — consolidation accelerates.`,
        iy:false});
    }
  });
  return acts;
}

/** Accumulate retained cash for independent operator groups (Fall-only caller). */
function accumulateIndieWarChests(G){
  if(!G)return;
  if(!G._indieWarChest)G._indieWarChest={};
  const keys=new Set();
  (G.stations||[]).forEach(s=>{
    if(!s||s._bpSlotDeferred||s.isPlayer||s.isPublic||s.corpOwner)return;
    keys.add(indieLicenseeKey(s,G));
  });
  keys.forEach(k=>{
    const sts=(G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&!s.isPlayer&&!s.isPublic&&!s.corpOwner&&indieLicenseeKey(s,G)===k);
    const flow=sts.reduce((sum,s)=>sum+Math.max(0,s.fin?.ebitda||0),0);
    const revFlow=sts.reduce((sum,s)=>sum+Math.max(0,s.fin?.rev||0),0);
    G._indieWarChest[k]=(G._indieWarChest[k]||0)+flow*3.2+revFlow*0.14;
    G._indieWarChest[k]=Math.min(85000000,G._indieWarChest[k]);
  });
}

/**
 * Independent AI operators buy rival independents when FCC caps allow (1992+; much more aggressive after 1996).
 * Uses `aiLicenseeKey` / fictional parent grouping; spends from `G._indieWarChest`.
 */
function runIndependentAcquisitions(G){
  if(!G||G.year<1992)return[];
  if(G.period!==2)return[];
  const y=G.year||1970;
  const post96=y>=1996;
  accumulateIndieWarChests(G);
  const MIN_TGT_SHARE=0.008;
  const MAX_SPEND_FRAC=0.48;
  const acts=[];
  const mkt=MARKETS[G.marketId||ACTIVE_MARKET]||MARKETS.atlanta;
  const city=mkt.label||'market';

  const licenseeKeys=[...new Set((G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&!s.isPlayer&&!s.isPublic&&!s.corpOwner).map(s=>indieLicenseeKey(s,G)))].filter(Boolean);
  if(!licenseeKeys.length)return[];

  const tryN=post96?2:1;
  const baseProb=post96?0.52:0.14;

  licenseeKeys.forEach(k=>{
    const buyers=(G.stations||[]).filter(s=>s&&!s._bpSlotDeferred&&!s.isPlayer&&!s.isPublic&&!s.corpOwner&&indieLicenseeKey(s,G)===k);
    if(!buyers.length)return;
    const lead=buyers.slice().sort((a,b)=>(b.rat?.share||0)-(a.rat?.share||0))[0];
    if(!lead)return;
    const leadShare=lead.rat?.share||0;
    const tryProb=Math.min(0.88,baseProb+(post96?0.22:0.06)*Math.min(1,leadShare/0.12)+(lead.pers?.ag||0)*0.12);
    if(Math.random()>tryProb)return;

    for(let attempt=0;attempt<tryN;attempt++){
      const owned=fccOwnedIndie(k,G);
      const lim=fccLimits(G.year,G.stations.length);
      if(lim.mode==='96'&&owned.total>=lim.total)break;
      if(lim.mode==='pre96'&&owned.am>=lim.am&&owned.fm>=lim.fm)break;

      const targets=(G.stations||[]).filter(s=>
        s&&!s._bpSlotDeferred&&!s.isPlayer&&!s.isPublic&&!s.corpOwner&&
        indieLicenseeKey(s,G)!==k&&
        (s.rat?.share||0)>MIN_TGT_SHARE
      );
      if(!targets.length)break;

      const scored=targets.map(s=>{
        let score=(s.rat?.share||0)*100;
        if(s.sig?.type==='FM'&&!s.fmBooster)score*=1.35;
        if(['NEWS_TALK','TOP40','COUNTRY','ADULT_CONTEMP'].includes(s.format))score*=1.15;
        const ownedFormats=buyers.map(b=>b.format);
        if(!ownedFormats.includes(s.format))score*=1.25;
        score*=1+(s.pers?.ag||0)*0.08;
        return {s, score};
      }).sort((a,b)=>b.score-a.score);

      let acquired=null,price=0;
      const chest=G._indieWarChest?.[k]||0;
      for(const {s:target} of scored){
        const sigType=target.sig?.type==='AM'||target.fmBooster?'AM':'FM';
        if(!fccCanIndieAcquire(k,sigType,G))continue;
        const annualRev=(target.fin?.rev||0)*2;
        const multiple=6.5+Math.random()*4.5;
        let p=Math.round(annualRev*multiple/100000)*100000;
        if(!Number.isFinite(p)||p<=0)continue;
        p=Math.max(380000,p);
        if(p>chest*MAX_SPEND_FRAC)continue;
        acquired=target;
        price=p;
        break;
      }
      if(!acquired)break;

      const parentName=rivalFictionalParentName(lead,G)||k.slice(0,24);
      acquired.aiLicenseeKey=k;
      if(acquired.simulcastWith){
        const p=G.stations.find(st=>st.id===acquired.simulcastWith);
        if(p)p.aiLicenseeKey=k;
      }
      G._indieWarChest[k]=Math.max(0,(G._indieWarChest[k]||0)-price);
      const churnFrac=0.18;
      Object.keys(acquired.mom||{}).forEach(coh=>{
        const m=acquired.mom[coh];
        if(m){
          m.tgt=Math.max(0.002,m.tgt*(1-churnFrac));
          m.cur=Math.max(0.002,m.cur*(1-churnFrac*0.5));
        }
      });
      acts.push({v:'MEDIUM',
        t:`📻 ${parentName} acquires ${acquired.callLetters} (${fmtLabel(acquired.format)}) in ${city} — independent group grows (${f$(price)}).`,
        iy:false});
    }
  });
  return acts;
}

// Corporate station quality decay — voicetracking, cost-cutting kills local feel
function corporateDecay(G){
  if(!G.corps)return;
  G.stations.filter(s=>s.corpOwner&&!s.isPlayer).forEach(s=>{
    const rate=s._qualityDecayRate||0.5;
    // Quality declines slowly — listeners eventually notice the generic voicetracked feel.
    // Floor: 22 (not 35) — corporate radio genuinely hollows out quality.
    // Cluster penalty: corps owning 3+ stations get faster decay (economies of scale = less local)
    const corp=G.corps?.find(c=>c.id===s.corpOwner);
    const clusterSize=corp?corp.stations.length:1;
    const clusterPenalty=clusterSize>=4?1.5:clusterSize>=3?1.25:1.0;
    if(s.oq>22)s.oq=Math.max(22,s.oq-rate*clusterPenalty);
    // BUT: corporate stations have better cost efficiency — handled in calcRev
  });
}

// Get acquisition price for a station (player buying from corp costs more)
function acqPrice(s,G){
  const annualRev=(s.fin?.rev||50000)*2;
  const base=Math.max(625000,annualRev*10);
  const corpPremium=s.corpOwner?1.6:1.0; // corps don't sell cheap
  const sharePrem=1+s.rat.share*4;
  return Math.round(base*corpPremium*sharePrem/100000)*100000;
}

// ── LOCAL MARKETING AGREEMENT (LMA) SYSTEM ──────────────────────
// Era model: unavailable pre-1990; 1990–1995 workaround (cap, fee friction); 1996+ counts toward FCC cap
// in sim and is de-emphasized vs outright acquisition. See lmaRegulatoryEra / lmaCountsAgainstLimit.
//
// Fee economics (2026): lease-style, not a flat % of revenue. See docs/lma-fee-model.md
// SYNC: implementation mirrored in scripts/lmaFeeModelShared.mjs (search LMA_FEE_MODEL_SYNC).
//
// LESSOR (you own, they operate): guaranteed license / time-brokerage payment.
// LESSEE (you operate, they own): pay fee from operating cash; station P&L stays visible.
//
// Corp AI: Corps can propose LMAs to players as lessees of corp-owned stations.

// LMA_FEE_MODEL_SYNC_START — fee kernel (keep in sync with scripts/lmaFeeModelShared.mjs)
// Tuned so raw fees usually clear EBITDA cap (~10–24% of seed EBITDA typical); caps remain safety rails.
const LMA_K_BASE = { mega: 0.0022, large: 0.00165, medium: 0.00072, small: 0.00055 };
const LMA_K_PERF = 0.0185;
/** Applied to FM lease fee after cap-min (full-fee bump; re-clamped to caps). AM unchanged. */
const LMA_FM_FEE_SIGNAL_MULT = 1.22;
/**
 * Minimum half-period LMA fee for FM (rounded later to $1k) — weak FMs must not read “nearly free”.
 * Tier table: aggressive market-size scaling (major-market dial value); AM has no floor.
 */
function lmaFmMinimumFeeHalfPeriod(rankTier) {
  const t = rankTier || 'large';
  if (t === 'mega') return 48000;
  if (t === 'large') return 18000;
  if (t === 'medium') return 9000;
  return 4000;
}

/** Era weight: pre-1990 weak → 1990s ramp → 1996–2003 peak → fade post-mid-2000s. */
function lmaEraFactor(year) {
  const y = year;
  if (y < 1988) return 0.34;
  if (y < 1990) return 0.38 + (y - 1988) * 0.02;
  if (y <= 1995) return 0.46 + ((y - 1990) / 5) * 0.44;
  if (y <= 2003) return 0.9 + ((y - 1995) / 8) * 0.12;
  if (y <= 2012) return 1.02 - ((y - 2003) / 9) * 0.22;
  return Math.max(0.72, 0.8 - (y - 2012) * 0.004);
}

function lmaAbsoluteCapHalfYear(year, rankTier) {
  const e = lmaEraFactor(year);
  const tierM = rankTier === 'mega' ? 1.0 : rankTier === 'large' ? 0.72 : 0.48;
  const v = 2.15e6 * (0.62 + 0.38 * e) * tierM;
  return Math.round(v / 5000) * 5000;
}

/**
 * Lease-style LMA fee (half-year dollars), rounded to nearest $1k.
 * Hybrid: (small fraction of market half-period pool) + (sublinear % of gross) × era,
 * then min of revenue %, EBITDA %, and absolute cap.
 */
function lmaComputeFeeRounded(halfPeriodMarketPool, grossRev, seedEbitda, rankTier, year, isFm) {
  const tier = rankTier || 'large';
  const kb = LMA_K_BASE[tier] ?? LMA_K_BASE.large;
  const sigM = isFm ? 1.06 : 1.0;
  const E = lmaEraFactor(year);
  const raw = (halfPeriodMarketPool * kb + grossRev * LMA_K_PERF * sigM) * E;
  const capRev = grossRev * 0.11;
  const capEbitda = seedEbitda > 0 ? seedEbitda * 0.28 : Number.POSITIVE_INFINITY;
  const absCap = lmaAbsoluteCapHalfYear(year, tier);
  let fee = Math.min(raw, capRev, capEbitda, absCap);
  if (fee < 0) fee = 0;
  if (isFm) {
    fee *= LMA_FM_FEE_SIGNAL_MULT;
    fee = Math.min(fee, capRev, capEbitda, absCap);
    fee = Math.max(fee, lmaFmMinimumFeeHalfPeriod(tier));
  }
  return Math.round(fee / 1000) * 1000;
}

function lmaHalfPeriodMarketPool(G) {
  const mktId = G.marketId || ACTIVE_MARKET || 'atlanta';
  const annual = marketAnnualBilling(G.year, mktId);
  const hsf = marketHalfSeasonFactor(G.year, G.period || 1);
  const adx = Math.max(0.75, G.adx || 1);
  return Math.round(annual * 0.5 * hsf * adx);
}
// LMA_FEE_MODEL_SYNC_END

/** Read-only: net cash effect from LMA fees this period (lessor inflows − lessee outflows). Solo / diagnostics. */
function playerLmaCashNetForSolo(G) {
  if (!G) return { lesseeFees: 0, lessorFees: 0, net: 0 };
  let lessee = 0;
  G.stations.filter(s => s.lmaLesseeId === 'player' && s._lmaStation).forEach(s => {
    lessee += lmaFeeForStation(s, G);
  });
  let lessor = 0;
  (G.ps || []).filter(s => s.lmaLessorId).forEach(s => {
    lessor += lmaFeeForStation(s, G);
  });
  return { lesseeFees: lessee, lessorFees: lessor, net: lessor - lessee };
}

function lmaFeeForStation(s, Gopt) {
  const Gg = Gopt || (typeof G !== 'undefined' ? G : null);
  const gross = (s._lmaGrossRev != null && s._lmaGrossRev !== undefined) ? s._lmaGrossRev : (s.fin?.rev || 0);
  let seedEbitda;
  if (s.lmaLessorId) seedEbitda = s._lmaSeedEbitda != null ? s._lmaSeedEbitda : 0;
  else seedEbitda = s.fin?.ebitda ?? 0;
  if (!Gg) {
    return Math.round(Math.min(gross * 0.08, gross * 0.11) / 1000) * 1000;
  }
  const mkt = MARKETS[Gg.marketId || ACTIVE_MARKET] || MARKETS.atlanta;
  const tier = mkt.rankTier || 'large';
  const pool = lmaHalfPeriodMarketPool(Gg);
  const isFm = (s.sig?.type === 'FM') || !!s.fmBooster;
  let fee = lmaComputeFeeRounded(pool, gross, seedEbitda, tier, Gg.year, isFm);
  // 1990–95: looser policy but deals were scrutinized — modest lessee-side premium (lessor payouts unchanged).
  if (!s.lmaLessorId && lmaRegulatoryEra(Gg.year) === 'transition') {
    fee = Math.round((fee * 1.1) / 1000) * 1000;
  }
  return fee;
}

/** Subtle LMA modal copy when fee is structurally low vs signal class (no economics effect). */
function lmaUiFeeDescriptor(s, Gg) {
  if (!Gg || !s) return '';
  const gross = s._lmaGrossRev != null && s._lmaGrossRev !== undefined ? s._lmaGrossRev : s.fin?.rev || 0;
  const sh = s.rat?.share != null ? s.rat.share : 0;
  const isFm = s.sig?.type === 'FM' || !!s.fmBooster;
  const mkt = MARKETS[Gg.marketId || ACTIVE_MARKET] || MARKETS.atlanta;
  const tier = mkt.rankTier || 'large';
  const fee = lmaFeeForStation(s, Gg);
  const fmFloor = lmaFmMinimumFeeHalfPeriod(tier);
  if (isFm && sh < 0.055 && fee <= fmFloor + 1500) {
    return '<div class="lma-meta" style="margin-top:4px;font-size:12px;color:var(--mut);font-style:italic">Soft book — fee sits on the FM dial-value floor (coverage still rents even when ratings are weak).</div>';
  } else if (isFm && sh < 0.045 && gross > 0 && fee < gross * 0.14) {
    return '<div class="lma-meta" style="margin-top:4px;font-size:12px;color:var(--mut);font-style:italic">Undervalued on billing vs signal — lease fee stays realistic for FM; upside if you lift revenue.</div>';
  } else if (!isFm && sh < 0.028 && gross > 0 && fee < gross * 0.06) {
    return '<div class="lma-meta" style="margin-top:4px;font-size:12px;color:var(--mut);font-style:italic">Low fee vs revenue — typical when AM share and billing are both soft.</div>';
  }
  return '';
}

function lmaCountsAgainstLimit(year) {
  // 1996 Telecom Act era onward: treat LMA operational control as counting toward ownership-style caps (simplified).
  return (year ?? 1970) >= 1996;
}

/** Regulatory era for LMA UI and AI — not the fee curve (see lmaEraFactor). */
function lmaRegulatoryEra(year) {
  const y = year ?? 1970;
  if (y < 1990) return 'pre1990';
  if (y < 1996) return 'transition';
  return 'postTelecom';
}

function lmaPlayerMaySignNewAgreements(G) {
  return lmaRegulatoryEra(G?.year) !== 'pre1990';
}

/** 1990–1995: cap concurrent LMA *lessee* deals (workaround era, not unlimited). */
const LMA_TRANSITION_MAX_LESSEE_OPS = 2;

function lmaPlayerLesseeOpCount(G) {
  return (G.stations || []).filter(s => s && s.lmaLesseeId === 'player' && s._lmaStation).length;
}

function lmaPlayerUnderTransitionLesseeCap(G) {
  if (lmaRegulatoryEra(G?.year) !== 'transition') return true;
  return lmaPlayerLesseeOpCount(G) < LMA_TRANSITION_MAX_LESSEE_OPS;
}

/** True when the player operates this station under an LMA (lessee) — not license owner; cannot “sell” the facility. */
function stationIsPlayerLmaLesseeOperation(s){
  return !!(s&&(s._lmaStation||s.lmaLesseeId==='player'));
}

/** Drop player-as-lessee LMA metadata (call when ending LMA or removing station from player portfolio). */
function clearPlayerLmaLesseeFields(s){
  if(!s)return;
  s.lmaLesseeId=null;
  s._lmaStation=false;
  delete s.lmaLicensorName;
  delete s._lmaFeeRate;
  delete s._lmaFeePaid;
  delete s._lmaGrossRev;
}

/** Saves: distress/bankruptcy used to clear isPlayer without stripping LMA flags — leaves phantom “player lessee” on AI stations. */
function repairOrphanPlayerLmaLesseeFlags(G){
  (G.stations||[]).forEach(s=>{
    if(!s||s._bpSlotDeferred)return;
    if(!s.isPlayer&&(s.lmaLesseeId==='player'||s._lmaStation))clearPlayerLmaLesseeFields(s);
  });
}

function playerCanEnterLMA(role, G) {
  // role: 'lessee' = player wants to operate another station
  // role: 'lessor' = player wants to lease out one of their own
  if (!lmaPlayerMaySignNewAgreements(G)) return false;
  if (role === 'lessee' && !lmaPlayerUnderTransitionLesseeCap(G)) return false;
  if (role === 'lessor') {
    // Must own at least 2 stations to lease one out (keep at least 1)
    const myStns = G.ps.filter(s => !s.lmaLessorId); // non-leased-out owned stations
    return myStns.length >= 2;
  }
  if (role === 'lessee') {
    // 1996+: LMA lessee ops count like ownership for cap checks. 1990–95: workaround (bypass).
    if (lmaCountsAgainstLimit(G.year)) {
      return fccCanAcquire('player','AM',G) || fccCanAcquire('player','FM',G);
    }
    return true; // 1990–1995: LMA can bypass strict cap (workaround era)
  }
  return false;
}

function openLMA() {
  rLMA();
  om('m-lma');
}

function rLMA() {
  const el = document.getElementById('lmab');
  if (!el) return;
  const year = G.year;
  const era = lmaRegulatoryEra(year);
  const countsAgainstLimit = lmaCountsAgainstLimit(year);
  const maySign = lmaPlayerMaySignNewAgreements(G);

  // Current active LMAs
  const activeLesseeStns = G.stations.filter(s => s.lmaLesseeId === 'player'); // player is lessee
  const activeLessorStns = G.ps.filter(s => s.lmaLessorId); // player is lessor (leased out)

  const lesseeTargets = maySign
    ? G.stations.filter(s => {
        if (s.isPlayer || s.isPublic || s.lmaLesseeId) return false;
        if (s.lmaLessorId) return false;
        const isWeak = s.rat.share < 0.04 && !s.corpOwner;
        const isCorpOffering = s.corpOwner && s._corpLMAOffer;
        return isWeak || isCorpOffering;
      })
    : [];

  const lessorTargets = maySign ? myPS().filter(s => !s.lmaLessorId && !s.lmaLesseeId) : [];
  const canLessor = maySign && lessorTargets.length >= 2;

  const pre1990CarryWarn =
    era === 'pre1990' && (activeLesseeStns.length || activeLessorStns.length)
      ? `<div style="background:rgba(240,180,88,.12);border:1px solid rgba(240,180,88,.35);padding:8px 12px;font-family:var(--ft);font-size:14px;color:var(--amb);margin-bottom:12px">⚠ Before 1990, full programmatic LMAs / time brokerage of this scope were not how the FCC treated control. End legacy agreements when practical — new LMAs cannot be signed this era.</div>`
      : '';

  let feeNote;
  if (era === 'pre1990') {
    feeNote = `<div style="background:rgba(90,180,255,.08);border:1px solid rgba(90,180,255,.25);padding:8px 12px;font-family:var(--ft);font-size:14px;color:var(--blu);margin-bottom:12px">📋 Pre-1990: new Local Marketing Agreements are unavailable. Operational control of another licensee without attribution was not the modern LMA practice.</div>`;
  } else if (era === 'transition') {
    feeNote = `<div style="background:rgba(90,180,255,.08);border:1px solid rgba(90,180,255,.25);padding:8px 12px;font-family:var(--ft);font-size:14px;color:var(--blu);margin-bottom:12px">📋 1990–1995: LMAs are a regulatory workaround — operational control without owning the license. They do not count toward your FCC cap here, but you can hold at most ${LMA_TRANSITION_MAX_LESSEE_OPS} concurrent operations as lessee. Fees run ~10% higher (deal scrutiny).</div>`;
  } else {
    feeNote = countsAgainstLimit
      ? `<div style="background:rgba(240,88,88,.10);border:1px solid rgba(240,88,88,.3);padding:8px 12px;font-family:var(--ft);font-size:14px;color:var(--red);margin-bottom:12px">⚠ Since 1996, LMAs count toward FCC-style ownership limits in this sim. Prefer outright acquisition when you can; use LMAs as a bridge or when caps block a buy.</div>`
      : '';
  }

  // Active LMAs section
  let activeHTML = '';
  if (activeLesseeStns.length || activeLessorStns.length) {
    const lesseeRows = activeLesseeStns.map(s => {
      const fee = lmaFeeForStation(s, G);
      const sigType = s.sig.type==='FM'&&!s.fmBooster?'FM':'AM';
      const canBuyLic = s._lmaStation && fccCanAcquire('player', sigType, G);
      const buyPrice = acqPrice(s, G);
      const buyOk = canBuyLic && G.cash >= buyPrice;
      const buyBtn = canBuyLic
        ? `<button type="button" class="abt g" style="font-size:14px;white-space:nowrap" onclick="purchaseLmaLicense('${s.id}')" ${buyOk?'':'disabled title="Insufficient cash"'}>🏢 BUY LICENSE ${f$(buyPrice)}</button>`
        : `<span style="font-size:13px;color:var(--mut);max-width:160px;text-align:right">Buy license when FCC caps allow an acquisition.</span>`;
      return `<div class="lma-row active-lma">
        <div>
          <div class="lma-badge lessee">YOU OPERATE</div>
          <div class="lma-call" style="color:${s.color||'var(--wht)'}">${s.callLetters}</div>
          <div class="lma-meta">${s.freq} · ${fmtLabel(s.format)} · Share: ${pct(s.rat.share)}</div>
          <div class="lma-terms">Fee to licensor: ${f$(fee)}/period · You keep the rest</div>
          ${lmaUiFeeDescriptor(s, G)}
          <div class="lma-meta" style="margin-top:4px;color:var(--mut)">Licensor: ${s.lmaLicensorName||'Independent Owner'}</div>
        </div>
        <div style="display:flex;flex-direction:column;gap:8px;align-items:flex-end;flex-shrink:0">
          ${buyBtn}
          <button type="button" class="abt" style="font-size:15px;color:var(--red);border-color:var(--red)" onclick="terminateLMA('${s.id}','lessee')">END LMA</button>
        </div>
      </div>`;
    }).join('');

    const lessorRows = activeLessorStns.map(s => {
      const fee = lmaFeeForStation(s, G);
      return `<div class="lma-row active-lma">
        <div>
          <div class="lma-badge lessor">YOU LICENSE OUT</div>
          <div class="lma-call" style="color:var(--wht)">${s.callLetters}</div>
          <div class="lma-meta">${s.freq} · ${fmtLabel(s.format)} · Share: ${pct(s.rat.share)}</div>
          <div class="lma-terms" style="color:var(--grn)">You receive: ${f$(fee)}/period guaranteed income</div>
          ${lmaUiFeeDescriptor(s, G)}
          <div class="lma-meta" style="margin-top:4px;color:var(--mut)">Operator: ${s.lmaOperatorName||'Third Party'} · You retain the license</div>
        </div>
        <button class="abt" style="font-size:15px;color:var(--red);border-color:var(--red)" onclick="terminateLMA('${s.id}','lessor')">RECLAIM</button>
      </div>`;
    }).join('');

    activeHTML = `<div class="ms2" style="margin-bottom:14px">
      <div class="msh" style="color:var(--grn)">ACTIVE LMAs</div>
      ${lesseeRows}${lessorRows}
    </div>`;
  }

  // Lessee options: stations you can take over
  let lesseeHTML = '';
  if (lesseeTargets.length) {
    const rows = lesseeTargets.map(s => {
      const fee = lmaFeeForStation(s, G);
      const netEst = Math.round((s.fin?.rev || 0) - fee);
      const canAfford = G.cash >= fee; // need first period's fee upfront
      const sigType = s.sig.type==='FM'||s.fmBooster ? 'FM' : 'AM';
      const limitOk = !countsAgainstLimit || fccCanAcquire('player', sigType, G);
      const atLesseeCap = era === 'transition' && !lmaPlayerUnderTransitionLesseeCap(G);
      const ok = canAfford && limitOk && !atLesseeCap;
      const corpTag = s.corpOwner ? `<span style="font-size:15px;color:${s.corpColor||'#9ca3af'};margin-left:6px">${s.corpName}</span>` : '';
      const blockReason = atLesseeCap ? 'EARLY-90S CAP' : !limitOk ? 'FCC LIMIT' : 'NO FUNDS';
      return `<div class="lma-row${ok?'':' nope'}" style="opacity:${ok?1:.4}">
        <div>
          <div class="lma-call" style="color:${s.color||'var(--wht)'}">${s.callLetters}${corpTag}</div>
          <div class="lma-meta">${s.freq} · ${signalPowerDisplayLabel(s.sig.pw)} · ${fmtLabel(s.format)} · Quality: ${Math.round(s.oq)}</div>
          <div class="lma-meta">Share: ${pct(s.rat.share)} · Revenue: ${f$(s.fin?.rev||0)}/period</div>
          <div class="lma-terms">Fee: ${f$(fee)}/period → Est. net to you: ${f$(netEst)}/period</div>
          ${lmaUiFeeDescriptor(s, G)}
        </div>
        <div style="display:flex;flex-direction:column;gap:6px;align-items:flex-end">
          <span style="font-family:var(--ft);font-size:15px;color:var(--mut)">First fee upfront</span>
          <span style="font-family:var(--fd);font-size:15px;color:${ok?'var(--amb)':'var(--red)'}">${f$(fee)}</span>
          ${ok ? `<button class="abt" style="font-size:15px" onclick="doLMALessee('${s.id}')">TAKE OVER →</button>` : `<span style="font-size:15px;color:var(--red)">${blockReason}</span>`}
        </div>
      </div>`;
    }).join('');
    lesseeHTML = `<div class="ms2" style="margin-bottom:14px">
      <div class="msh">STATIONS AVAILABLE TO OPERATE (YOU AS LESSEE)</div>
      <p class="di" style="font-size:14px">You program, hire talent, and keep revenue minus the fee. The licensor keeps the license.</p>
      ${rows}
    </div>`;
  } else {
    lesseeHTML = `<div class="ms2" style="margin-bottom:14px">
      <div class="msh">STATIONS AVAILABLE TO OPERATE</div>
      <p class="di" style="font-size:15px;color:var(--mut)">${maySign ? 'No stations currently available for LMA. Weak independents under ~4% share and corporate offers appear here when available.' : 'Not available before 1990 — the FCC did not permit this style of operational LMA. Use acquisitions and ordinary station operations.'}</p>
    </div>`;
  }

  // Lessor options: your stations you can lease out
  let lessorHTML = '';
  if (canLessor) {
    const rows = lessorTargets.map(s => {
      const fee = lmaFeeForStation(s, G);
      return `<div class="lma-row">
        <div>
          <div class="lma-call">${s.callLetters}</div>
          <div class="lma-meta">${s.freq} · ${fmtLabel(s.format)} · Share: ${pct(s.rat.share)}</div>
          <div class="lma-meta">Current rev: ${f$(s.fin?.rev||0)}/period</div>
          <div class="lma-terms" style="color:var(--grn)">You'd receive: ${f$(fee)}/period — guaranteed, no upkeep</div>
          ${lmaUiFeeDescriptor(s, G)}
        </div>
        <button class="abt" style="font-size:15px;background:rgba(82,227,110,.12);border-color:var(--grn);color:var(--grn)" onclick="doLMALessor('${s.id}')">LEASE OUT →</button>
      </div>`;
    }).join('');
    lessorHTML = `<div class="ms2">
      <div class="msh">YOUR STATIONS AVAILABLE TO LEASE OUT (YOU AS LESSOR)</div>
      <p class="di" style="font-size:14px">Lease a station you own to an operator. You collect a market- and era-scaled license fee (not a flat % of revenue). No upkeep costs. You keep the license and call letters. Useful when at your ownership cap.</p>
      ${rows}
    </div>`;
  } else {
    lessorHTML = `<div class="ms2">
      <div class="msh">LEASE OUT ONE OF YOUR STATIONS</div>
      <p class="di" style="font-size:15px;color:var(--mut)">${maySign ? 'You need at least 2 stations to lease one out — you must retain at least 1 licensed station.' : 'Leasing out operations in this form is not available before 1990.'}</p>
    </div>`;
  }

  let histNote;
  if (era === 'pre1990') {
    histNote = `<p class="di" style="font-size:15px;margin-bottom:14px">Strict ownership era: the FCC focused on <em>control</em>, not just paper ownership. Full programmatic / sales control of another licensee through an LMA is not modeled as available here.</p>`;
  } else if (era === 'transition') {
    histNote = `<p class="di" style="font-size:15px;margin-bottom:14px">1990–1995: LMAs spread as a <em>workaround</em> around ownership caps — operational control without buying the license. They should feel strategic and a bit fragile, not like ordinary expansion.</p>`;
  } else {
    histNote = `<p class="di" style="font-size:15px;margin-bottom:14px">Post–Telecom Act (1996+): caps eased and LMAs are treated as attributable in this sim — bridges to purchase, financing workarounds, or gap-fills when you cannot close an acquisition.</p>`;
  }

  el.innerHTML = pre1990CarryWarn + histNote + feeNote + activeHTML + lesseeHTML + lessorHTML +
    `<button class="cnl" onclick="cm('m-lma')">CLOSE</button>`;
}

function doLMALessee(sid) {
  const s = G.stations.find(st => st.id === sid);
  if (!s || s.isPlayer || s.lmaLesseeId) return;
  if (wlFreePostTrialSoloLimitsActive() && wlPlayerOperatedStationCount(G) >= 2) {
    showToast('You’ve hit the free-tier limit: two operated stations in this market (including LMA operation). Upgrade in Account for full access to more licenses and LMAs (Starter and Pro).', 'warn', 7800);
    return;
  }
  if (!lmaPlayerMaySignNewAgreements(G)) {
    showToast('Full operational LMAs are not available before 1990.', 'warn');
    return;
  }
  if (!playerCanEnterLMA('lessee', G)) {
    showToast('Cannot take this LMA (FCC limits, portfolio rules, or early‑90s concurrent LMA cap).', 'warn');
    return;
  }
  const fee = lmaFeeForStation(s, G);
  if (G.cash < fee) { alert('Need ' + f$(fee) + ' for first period fee.'); return; }
  G.cash -= fee;
  if (MP.mode==='live') { if(!G._playerCash) G._playerCash={}; G._playerCash[MP.playerId]=G.cash; MP.emit('player_cash_update',{playerId:MP.playerId,cash:G.cash}); }

  const lmaLicensorSnapshot=s.corpOwner?s.corpName:(rivalFictionalParentName(s,G)||'Independent');
  // Mark the station as LMA-operated by player
  s.lmaLesseeId = 'player';
  s._mpOwner = MP.mode==='live' ? MP.playerId : 0;
  s.isPlayer = true; // appears in player panel
  s._lmaStation = true; // distinguishes from owned stations
  applyDefaultBrandToPlayerStation(s);
  s.lmaLicensorName = lmaLicensorSnapshot;
  s._lmaFeeRate = s.fin.rev > 0 ? Math.round((fee / s.fin.rev) * 1000) / 1000 : 0;
  G.ps = G.stations.filter(st => st.isPlayer);

  G.news.unshift({v:'HIGH', t:`📝 LMA signed: ${s.callLetters} — you now program and operate this station. Fee: ${f$(fee)}/period to licensor.`, y:G.year, p:G.period, iy:true});
  MP.action('lma_lessee', {sid});
  cm('m-lma'); renderAll();
  queueAutoLogosForPlayerStations();
}

function doLMALessor(sid) {
  const s = G.stations.find(st => st.id === sid);
  if (!s || !s.isPlayer) return;
  if (!lmaPlayerMaySignNewAgreements(G)) {
    showToast('Leasing out operations in this form is not available before 1990.', 'warn');
    return;
  }
  if (!playerCanEnterLMA('lessor', G)) return;
  const myNonLeased = G.ps.filter(st => !st.lmaLessorId && !st._lmaStation);
  if (myNonLeased.length < 2) { alert('You must keep at least 1 station for yourself.'); return; }
  const fee = lmaFeeForStation(s, G);

  s.lmaLessorId = 'ai_operator'; // an AI entity operates it
  s._lmaStation = false;
  s._lmaStartPeriod = (G.turn||0); // track when LMA began for duration
  s._lmaDuration = 4;              // default: 4 periods (2 years), renewable
  s.lmaOperatorName = pick(['Broadcast Partners','Regional Radio Inc.','Metro Media Group','Sun Belt Broadcasting','Heritage Radio']);

  // AI operator picks a format — they won't duplicate the lessor's existing formats
  // (real LMA agreements routinely include non-compete clauses on format)
  const _myFormats = G.ps.filter(st=>st.id!==s.id).map(st=>st.format);
  const _availFmts = Object.keys(FM).filter(f=>
    !_myFormats.includes(f) && f!==s.format &&
    formatUnlockedForYear(f,G) && formatAllowedInMarket(f,G.marketId,G.year) &&
    !FM[f]?.public && !['FULL_SERVICE','PUBLIC_RADIO'].includes(f)
  );
  // Prefer formats with decent CPM that suit the signal type
  const _amFriendly=['NEWS_TALK','ALL_NEWS','SPORTS_TALK','COUNTRY','GOSPEL','ADULT_STANDARDS','OLDIES','CLASSIC_HITS','BROKERED_PROGRAMMING'];
  const _fmtPool = s.sig.type==='AM'
    ? _availFmts.filter(f=>_amFriendly.includes(f)).concat(_availFmts.filter(f=>!_amFriendly.includes(f)))
    : _availFmts;
  const _chosenFmt = _fmtPool.length ? _fmtPool[Math.floor(Math.random()*Math.min(3,_fmtPool.length))] : s.format;
  const _prevFmt = s.format;
  s.format = _chosenFmt;
  s.brand = gbBrandForStationReplace(s, _chosenFmt);
  s._formatAge = 0;
  // Give AI operator a fresh identity start
  s.identity = 0; s._identityPeak = 0;

  G.news.unshift({v:'MEDIUM', t:`📝 LMA signed: ${s.callLetters} leased to ${s.lmaOperatorName}. They'll program it as ${fmtLabel(_chosenFmt)}${_prevFmt!==_chosenFmt?' (reformatted from '+fmtLabel(_prevFmt)+')':''}. You receive ${f$(fee)}/period. Station stays under your license.`, y:G.year, p:G.period, iy:true});
  logHistory(s,'FORMAT',`LMA: leased to ${s.lmaOperatorName} — reformatted to ${fmtLabel(_chosenFmt)}`,G);
  MP.action('lma_lessor', {sid});
  cm('m-lma'); renderAll();
}

/** Buy out the license for a station you currently operate under LMA (same caps / pricing as open market acquisition). */
function purchaseLmaLicense(sid){
  const s=G.stations.find(st=>st.id===sid);
  if(!s||!s._lmaStation||s.lmaLesseeId!=='player')return;
  const sigType=s.sig.type==='FM'&&!s.fmBooster?'FM':'AM';
  if(!fccCanAcquire('player',sigType,G)){
    showToast('FCC ownership limits block buying this license right now.','warn');
    return;
  }
  const price=acqPrice(s,G);
  if(!Number.isFinite(price)||price<=0){
    showToast('Could not price this license purchase.','warn');
    return;
  }
  if(G.cash<price){
    showToast(`Need ${f$(price)} to buy the license (you have ${f$(G.cash)}).`,'warn');
    return;
  }
  openGameConfirm({
    title:'Buy license (end LMA)',
    message:`Buy ${callDisplay(s)} outright for ${f$(price)}? Your LMA ends and you own the facility — same as acquiring it from the open market, without breaking simulcasts first.`,
    confirmLabel:'Buy license',
  },ok=>{
    if(!ok)return;
    const st=G.stations.find(t=>t.id===sid);
    if(!st||!st._lmaStation||st.lmaLesseeId!=='player')return;
    const stSig=st.sig.type==='FM'&&!st.fmBooster?'FM':'AM';
    if(!fccCanAcquire('player',stSig,G)){showToast('FCC limits block this purchase.','warn');return;}
    const p2=acqPrice(st,G);
    if(G.cash<p2){showToast(`Need ${f$(p2)}.`,'warn');return;}
    G.cash-=p2;
    if(MP.mode==='live'){if(!G._playerCash)G._playerCash={};G._playerCash[MP.playerId]=G.cash;MP.emit('player_cash_update',{playerId:MP.playerId,cash:G.cash});}
    clearPlayerLmaLesseeFields(st);
    st.isPlayer=true;
    if(MP.mode==='live')st._mpOwner=MP.playerId;
    G.ps=G.stations.filter(x=>x.isPlayer);
    G.news.unshift({v:'HIGH',t:`You acquired the license for ${st.callLetters} — LMA concluded, you now own the facility.`,y:G.year,p:G.period,iy:true});
    logHistory(st,'LOGO',`Purchased license (ended LMA) — ${f$(p2)}`,G);
    if(MP.mode==='live')MP.action('lma_buy_license',{sid:st.id});
    autoSave();
    cm('m-lma');
    renderAll();
    showToast('License purchased — LMA ended.','info');
  });
}

function terminateLMA(sid, role) {
  const s = G.stations.find(st => st.id === sid);
  if (!s) return;
  if (role === 'lessee') {
    // End your operation of a station you don't own
    clearPlayerLmaLesseeFields(s);
    s.isPlayer = false;
    s._mpOwner = undefined;
    G.ps = G.stations.filter(st => st.isPlayer);
    G.news.unshift({v:'MEDIUM', t:`📝 LMA terminated: ${s.callLetters} returned to licensor.`, y:G.year, p:G.period, iy:true});
  } else {
    // Reclaim a station you leased out
    s.lmaLessorId = null;
    s.lmaOperatorName = null;
    G.news.unshift({v:'MEDIUM', t:`📝 LMA ended: ${s.callLetters} reclaimed from ${s.lmaOperatorName||'operator'}.`, y:G.year, p:G.period, iy:true});
  }
  MP.action('lma_terminate', {sid, role});
  cm('m-lma'); renderAll();
}

// LMA fee processing — called during revenue phase each period
function processLMAFees(G) {
  // Player as lessee: deduct fee from player cash
  G.stations.filter(s => s.lmaLesseeId === 'player' && s._lmaStation).forEach(s => {
    const fee = lmaFeeForStation(s, G);
    G.cash = (G.cash || 0) - fee;
    if (MP.mode==='live') { if(!G._playerCash) G._playerCash={}; G._playerCash[MP.playerId]=G.cash; }
    s._lmaFeePaid = fee;
  });

  // Player as lessor: add fee to player cash; check for expiration
  G.ps.filter(s => s.lmaLessorId).forEach(s => {
    const fee = lmaFeeForStation(s, G);
    G.cash = (G.cash || 0) + fee;
    if (MP.mode==='live') { if(!G._playerCash) G._playerCash={}; G._playerCash[MP.playerId]=G.cash; }
    s._lmaFeeReceived = fee;
    // Duration check: queue a renewal notice when the LMA term expires
    const periodsHeld = (G.turn||0) - (s._lmaStartPeriod||0);
    const duration = s._lmaDuration || 4;
    if(periodsHeld >= duration && !s._lmaRenewalPending){
      s._lmaRenewalPending = true;
      MILESTONE_Q.push({
        type:'info',
        title:'LMA EXPIRING',
        body:`<strong>${s.callLetters}</strong> — your LMA with ${s.lmaOperatorName||'the operator'} has run its term. You can renew for another 2 years or reclaim the station. You're currently collecting ${f$(fee)}/period in license fees.`,
        owner: s._mpOwner
      });
    }
  });
}

// Corp AI LMA offers — corps occasionally offer to lease a weak station to the player (era-gated)
function runCorpLMAOffers(G) {
  if (!G.corps || !lmaPlayerMaySignNewAgreements(G)) return;
  const era = lmaRegulatoryEra(G.year);
  G.corps.forEach(corp => {
    if (!corp.stations.length) return;
    const weakStns = corp.stations
      .map(id => G.stations.find(s => s.id === id))
      .filter(s => s && !s.isPlayer && !s.lmaLesseeId && s.rat.share < 0.025);
    let chance = era === 'transition' ? 0.26 : 0.12;
    if (era === 'postTelecom' && G.period === 2 && G.year >= 1996) {
      const amT = G.stations.some(st =>
        !st.isPlayer && !st.isPublic && !st.corpOwner && (st.sig.type === 'AM' || st.fmBooster) && fccCanAcquire(corp.id, 'AM', G));
      const fmT = G.stations.some(st =>
        !st.isPlayer && !st.isPublic && !st.corpOwner && st.sig.type === 'FM' && !st.fmBooster && fccCanAcquire(corp.id, 'FM', G));
      if (amT || fmT) chance *= 0.35;
    }
    weakStns.forEach(s => {
      if (!s._corpLMAOffer && Math.random() < chance) {
        s._corpLMAOffer = true;
        G.news.unshift({v:'MEDIUM',
          t:`📋 ${corp.name} is looking for an operator for ${s.callLetters} (${fmtLabel(s.format)}) — check LMA deals.`,
          y:G.year, p:G.period, iy:true});
      }
    });
  });
}

window._mpApply_lma_lessee = function({sid}) {
  if (!lmaPlayerMaySignNewAgreements(G) || !playerCanEnterLMA('lessee', G)) return;
  const s = G.stations.find(st=>st.id===sid); if(!s) return;
  s.lmaLesseeId='player'; s._lmaStation=true; s.isPlayer=true;
  applyDefaultBrandToPlayerStation(s);
  G.ps=G.stations.filter(st=>st.isPlayer); renderAll();
};
window._mpApply_lma_lessor = function({sid}) { renderAll(); };
window._mpApply_lma_terminate = function({sid,role}) {
  const s=G.stations.find(st=>st.id===sid); if(!s) return;
  if(role==='lessee'){clearPlayerLmaLesseeFields(s);s.isPlayer=false;s._mpOwner=undefined;}
  else{s.lmaLessorId=null;}
  G.ps=G.stations.filter(st=>st.isPlayer); renderAll();
};

// ── RANK MILESTONES ───────────────────────────────────────────────
const MILESTONE_Q=[];
function checkRankMilestones(G){
  // In MP, host runs this for ALL player stations and tags milestones with _mpOwner.
  // Simulcast AM/FM pairs use combined rank & share — one milestone per pair, not per leg.
  // MILESTONE_Q only receives milestones belonging to the local player.
  const combinedRows=buildCommercialCombinedRankRows(G);
  const seenPairs=new Set();
  G.ps.forEach(s=>{
    const partner=simulcastPartnerStation(s);
    if(partner){
      const pk=[s.id,partner.id].sort().join('|');
      if(seenPairs.has(pk))return;
      seenPairs.add(pk);
    }
    const cur=combinedMarketRankForStation(s, combinedRows);
    if(!cur)return;
    const prev=s._prevRank??null;
    const sh=milestoneRankSharePct(s);
    const labelHtml=milestoneRankLabelHtml(s);
    const sharePhrase=partner?'combined share':'total share';
    const isMyStation = MP.mode!=='live' || s._mpOwner===MP.playerId;
    if(prev===null){
      s._prevRank=cur;
      if(partner) partner._prevRank=cur;
      return;
    }
    const gained=cur<prev,lost=cur>prev;
    let m=null;
    if(cur===1&&prev>1)
      m={type:'gain',title:'NUMBER ONE',body:labelHtml+' is now the #1 station in the market — '+sh+' '+sharePhrase+'.',owner:s._mpOwner};
    else if(cur>1&&prev===1)
      m={type:'loss',title:'LOST #1',body:labelHtml+' has fallen from the top spot. Now #'+cur+' at '+sh+'.',owner:s._mpOwner};
    else if(gained&&cur<=5&&prev>5)
      m={type:'gain',title:'TOP 5',body:labelHtml+' breaks into the top 5 — now ranked #'+cur+' with '+sh+'.',owner:s._mpOwner};
    else if(lost&&cur>5&&prev<=5)
      m={type:'loss',title:'OUT OF TOP 5',body:labelHtml+' slips out of the top 5, now ranked #'+cur+'.',owner:s._mpOwner};
    else if(gained&&cur<=10&&prev>10)
      m={type:'gain',title:'TOP 10',body:labelHtml+' is now a top-10 station at rank #'+cur+'.',owner:s._mpOwner};
    else if(lost&&cur>10&&prev<=10)
      m={type:'loss',title:'OUT OF TOP 10',body:labelHtml+' has dropped out of the top 10, now ranked #'+cur+'.',owner:s._mpOwner};
    if(m&&isMyStation) MILESTONE_Q.push(m);
    s._prevRank=cur;
    if(partner) partner._prevRank=cur;
  });
}
function openPeriodNews(){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  const rows=G._lastTurnHeadlines||[];
  const yr=rows[0]?.y, per=rows[0]?.p;
  const sub=rows.length&&yr!=null&&per!=null
    ? `${yr} ${per===2?'FALL':'SPRING'} — everything that hit the wire last turn`
    : 'Advance a period to capture a headline recap.';
  const body=rows.length
    ? rows.map(n=>{
        const tag=n.v==='HIGH'?'●':n.v==='MEDIUM'?'◆':'○';
        const t=escHtmlForModal(n.t||'');
        return '<div style="margin-bottom:12px;padding-bottom:12px;border-bottom:1px solid var(--bdr)"><span style="color:var(--mut);font-size:13px;margin-right:8px;font-family:var(--fd)">'+tag+'</span><span style="color:var(--off);font-size:15px;font-family:var(--fm);line-height:1.45">'+t+'</span></div>';
      }).join('')
    : '<p class="di" style="color:var(--mut)">No snapshot yet. End a period — this panel lists every news line from that turn (same feed as the left column, without scrolling).</p>';
  document.getElementById('periodnewsb').innerHTML=
    '<p style="font-size:14px;color:var(--mut);margin:0 0 14px;line-height:1.4">'+escHtmlForModal(sub)+'</p>'+
    '<div style="max-height:58vh;overflow-y:auto">'+body+'</div>'+
    '<p style="font-size:13px;color:var(--mut);margin:14px 0 0;line-height:1.45">Matches the <strong>NEWS FEED</strong> for that period — useful when the ticker moved fast.</p>';
  om('m-period-news');
}
function flushMilestones(){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__){MILESTONE_Q.length=0;return;}
  if(!MILESTONE_Q.length)return;
  const m=MILESTONE_Q.shift();
  if(m.regulatory){
    const per=m.wasP===2?'Fall':'Spring';
    const h=escHtmlForModal(m.headline), b=escHtmlForModal(m.body);
    document.getElementById('milestoneb').innerHTML=
      '<div class="mh" style="background:rgba(245,166,35,.14);border-bottom:2px solid var(--amb)">'+
      '<span style="color:var(--amb);letter-spacing:3px;font-family:var(--fd)">📡 '+m.title+'</span></div>'+
      '<div style="padding:20px 16px">'+
      '<p style="font-family:var(--fd);color:var(--amb);font-size:18px;margin:0 0 12px;line-height:1.35">'+h+'</p>'+
      '<p class="di" style="margin:0 0 14px">'+b+'</p>'+
      '<div style="padding:14px;background:var(--crd);border-radius:8px;border:1px solid var(--bdh)">'+
      '<div style="font-size:11px;color:var(--mut);letter-spacing:0.18em;margin-bottom:8px">NEW LIMITS IN YOUR MARKET</div>'+
      '<p style="margin:0;font-size:16px;color:var(--off);font-family:var(--fm)"><strong>'+escHtmlForModal(m.capLine)+'</strong></p>'+
      '<p style="margin:10px 0 0;font-size:14px;color:var(--mut);line-height:1.5">'+m.capExplain+'</p></div>'+
      '<p style="font-size:15px;color:var(--mut);margin:14px 0 0">'+m.wasY+' · '+per+'</p>'+
      '<button class="cfm" onclick="cm(\'m-milestone\');setTimeout(flushMilestones,300)">'+(MILESTONE_Q.length?'NEXT →':'CLOSE')+'</button>'+
      '</div>';
    om('m-milestone');
    return;
  }
  const isGain=m.type==='gain';
  const col=isGain?'var(--grn)':'var(--red)';
  const bg=isGain?'rgba(82,227,110,.10)':'rgba(240,88,88,.10)';
  const icon=isGain?'📈':'📉';
  document.getElementById('milestoneb').innerHTML=
    '<div class="mh" style="background:'+bg+';border-bottom:1px solid '+col+'">'+
    '<span style="color:'+col+';letter-spacing:2px">'+icon+' '+m.title+'</span></div>'+
    '<div style="padding:20px 16px">'+
    '<p class="di">'+m.body+'</p>'+
    '<p style="font-size:15px;color:var(--mut);margin:10px 0">'+G.year+' · Period '+G.period+'</p>'+
    '<button class="cfm" onclick="cm(\'m-milestone\');setTimeout(flushMilestones,300)">'+(MILESTONE_Q.length?'NEXT →':'CLOSE')+'</button>'+
    '</div>';
  om('m-milestone');
}

// ── STATION CARD: admin actions (card + m-stadmin modal) ─────────
function wlGetStationPillContext(opId) {
  const myStations = MP.mode==='live' ? G.ps.filter(s => s._mpOwner === MP.playerId) : G.ps;
  const renderedPlayerSimPairKeys = new Set();
  for (let s of myStations) {
    if (!s) continue;
    const partner = simulcastPartnerStation(s);
    const isPlayerPair = partner && myStations.some(st => st.id === partner.id);
    if (isPlayerPair && partner) {
      const anchor = simulcastPairStationCardAnchor(s, partner);
      if (s.id !== anchor.id) continue;
      const pairKey = s.id <= partner.id ? s.id + '\x1e' + partner.id : partner.id + '\x1e' + s.id;
      if (renderedPlayerSimPairKeys.has(pairKey)) continue;
      renderedPlayerSimPairKeys.add(pairKey);
    }
    const op = simulcastOperationalSource(s);
    if (!op || op.id !== opId) continue;
    return {
      s,
      partner,
      isPlayerPair: !!isPlayerPair,
      junior: isPlayerPair && partner ? partner : null,
      op,
    };
  }
  return null;
}
function wlBuildStationCardAdminActionGrid(ctx) {
  const {s, op, junior} = ctx;
  const scActEmpty = '<div class="sc-act-empty" aria-hidden="true"></div>';
  const pack2 = btns => {
    const ar = btns.filter(x => x && String(x).trim() !== '');
    if (!ar.length) return '';
    const cells = [];
    for (let i = 0; i < ar.length; i += 2) {
      cells.push(ar[i]);
      cells.push(i + 1 < ar.length ? ar[i + 1] : scActEmpty);
    }
    return '<div class="sc-act">' + cells.join('') + '</div>';
  };
  const simBtn = junior
    ? `<button class="abt" style="border-color:rgba(255,255,255,.15)" onclick="openSim('${s.id}')">◈ Break simulcast</button>`
    : `<button class="abt b" onclick="openSim('${s.id}')">◈ Simulcast this station</button>`;
  const streamBtn =
    '<button class="abt ' + (op.stream?.active ? 'g active' : G.year >= 2005 ? 'b' : '') + `" onclick="openStream('${op.id}')"` +
    (G.year < 2005 ? ' style="opacity:.30;cursor:default"' : '') +
    ' title="Digital: streaming + on-demand reach (unlocks 2005+)">' +
    (op.stream?.active ? '📶 Digital ✓' : '📶 Add digital') +
    '</button>';
  const fmBtn = st => {
    if (!st) return '';
    if (st.simulcastWith && !st.fmBooster) {
      const partner0 = st.simulcastWith ? G.stations.find(x => x.id === st.simulcastWith) : null;
      const fmLeg = partner0 && (partner0.sig.type === 'FM' && !partner0.fmBooster) ? partner0 : st.sig.type === 'FM' && !st.fmBooster ? st : null;
      const fmLbl = fmLeg ? callDisplay(fmLeg) : 'FM';
      return `<button class="abt g" onclick="openMigrate('${st.id}')">📡 Move format to ${fmLbl}</button>`;
    }
    if (st.fmBooster) return `<button class="abt g active" onclick="openFmBooster('${st.id}')">📡 Translator ${callDisplay(st)} ✓</button>`;
    if (st.sig.type === 'AM' && G.year >= 2009) return `<button class="abt b" onclick="openFmBooster('${st.id}')">📡 FM translator ${callDisplay(st)}</button>`;
    if (st.sig.type === 'AM') return '<button class="abt" style="opacity:.28;cursor:default;font-size:14px" title="AM FM translators unlock in 2009 (FCC AM Revitalization). Use Simulcast or a full FM license before then.">📡 FM translator</button>';
    return '<button class="abt" style="opacity:.25;cursor:default;font-size:14px">📡 FM translator</button>';
  };
  const fmMigrateAnchor = junior ? simulcastOperationalSource(s) : s;
  const fmUniq = [];
  const _m1 = fmBtn(fmMigrateAnchor);
  if (_m1) fmUniq.push(_m1);
  const legLbl = st => (junior ? st.callLetters + '-' + st.sig.type : callDisplay(st));
  const histArr = junior
    ? [
        `<button class="abt" onclick="openHistory('${s.id}')">📋 History ${legLbl(s)}</button>`,
        `<button class="abt" onclick="openHistory('${junior.id}')">📋 History ${legLbl(junior)}</button>`,
      ]
    : [`<button class="abt" onclick="openHistory('${s.id}')">📋 History ${legLbl(s)}</button>`];
  const mkSellBtn = st => {
    if (!st || stationIsPlayerLmaLesseeOperation(st)) return '';
    return `<button class="abt g" onclick="openSell('${st.id}')">💰 Sell ${legLbl(st)}</button>`;
  };
  const sellArr = junior ? [mkSellBtn(s), mkSellBtn(junior)].filter(Boolean) : [mkSellBtn(s)].filter(Boolean);
  const swapBtn = `<button class="abt" onclick="openSwapSignal('${op.id}')">⇄ Swap signal</button>`;
  const adminBtns = [...histArr, swapBtn, ...fmUniq, ...sellArr, streamBtn, simBtn];
  return pack2(adminBtns);
}
function openStationAdmin(sid) {
  const opId = String(sid);
  const ctx = wlGetStationPillContext(opId);
  if (!ctx) {
    showToast('Could not find station for admin.', 'info');
    return;
  }
  const b = document.getElementById('stadmb');
  if (!b) return;
  b.innerHTML =
    '<p class="di"><strong>Administration & structure</strong> — ' +
    callDisplay(ctx.op) +
    (ctx.junior ? ' (simulcast pair: ' + callDisplay(ctx.s) + ' + ' + callDisplay(ctx.junior) + ')' : '') +
    '</p>' +
    '<div class="msh" style="margin-top:0">ACTIONS</div>' +
    wlBuildStationCardAdminActionGrid(ctx) +
    '<p class="di" style="margin-top:12px">These actions open the same screens as elsewhere. Close a sub-screen to return here.</p>' +
    '<button class="cnl" onclick="cm(\'m-stadmin\')">CLOSE</button>';
  const mh = document.getElementById('m-stadmin')?.querySelector?.('.mh span');
  if (mh) mh.textContent = 'STATION ADMIN — ' + callDisplay(ctx.op);
  om('m-stadmin');
}
window.openStationAdmin = openStationAdmin;

// ── SALES FORCE (merged with spot load) ──────────────────────────
let SALES_PICK=null; // { sid: string, level: number } pending selection in #m-sales
function openSales(sid){
  sid=ensureOpsSourceSid(sid);
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  const mh=document.querySelector('#m-sales .mh span');
  if(mh)mh.textContent='SALES';
  const cur=s.salesForce?.level||0;
  if(!SALES_PICK||SALES_PICK.sid!==sid) SALES_PICK={sid,level:cur};
  const picked=Number.isFinite(SALES_PICK.level)?SALES_PICK.level:cur;
  const _cr=buildCommercialCombinedRankRows(G);
  const rank=combinedMarketRankForStation(s,_cr);
  const rows=SF_LEVELS.map(sf=>{
    const isCur=sf.id===cur;
    const isPick=sf.id===picked;
    const estRevGain=sf.id>cur?Math.round(s.fin.rev*(sf.sellBonus-(SF_LEVELS[cur].sellBonus||0))*0.6):0;
    const netPeriod=Math.round(estRevGain-(sf.cost-(SF_LEVELS[cur].cost||0))/2);
    const nc=netPeriod>0?'var(--grn)':netPeriod<0?'var(--red)':'var(--mut)';
    const oc=isCur?'':`onclick="pickSalesLevel('${sid}',${sf.id})"`;
    const ch=sf.cost>0?'<span class="sf-cost">'+f$(sf.cost/2)+'/period</span>':'<span class="sf-cost" style="color:var(--mut)">free</span>';
    const gh=sf.id>cur?'<div class="sf-gain">Est. lift: <strong style="color:var(--grn)">+'+f$(estRevGain)+'</strong> · Net: <strong style="color:'+nc+'">'+(netPeriod>=0?'+':'')+f$(netPeriod)+'</strong>/period</div>':'';
    return '<div class="sf-row'+(isCur?' sf-cur':'')+(isPick&&!isCur?' sf-pick':'')+'" '+oc+'>'+'<div class="sf-top"><span class="sf-l">'+sf.l+'</span>'+(isCur?'<span class="sf-badge">CURRENT</span>':'')+(isPick&&!isCur?'<span class="sf-badge" style="background:rgba(82,227,110,.14);border-color:rgba(82,227,110,.35);color:var(--grn)">SELECTED</span>':'')+ch+'</div>'+'<div class="sf-desc">'+sf.desc+'</div>'+gh+'</div>';
  }).join('');
  // Cluster demo breadth note for the sales modal
  const _sDemoBand = f => {
    const yFmts=['TOP40','ALT_ROCK','RHYTHMIC','HOT_AC','URBAN_CONTEMP'];
    const oFmts=['NEWS_TALK','ALL_NEWS','SPORTS_TALK','BEAUTIFUL_MUSIC','ADULT_STANDARDS','GOSPEL','PODCAST_TALK'];
    return yFmts.includes(f)?'Youth (12–34)':oFmts.includes(f)?'Older (35+)':'Mid (25–54)';
  };
  const _clusterStns = myPS();
  const _bandMap = {};
  _clusterStns.forEach(st => { const b=_sDemoBand(st.format); if(!_bandMap[b])_bandMap[b]=[]; _bandMap[b].push(st.callLetters); });
  const _bandCount = Object.keys(_bandMap).length;
  const _breadthEra = G.year >= 1996 ? 1.0 : G.year >= 1990 ? Math.min(1,(G.year-1990)/6) : 0;
  const _breadthBonus = _bandCount>=3?0.08:_bandCount===2?0.04:0;
  const _breadthActive = _breadthBonus > 0 && _breadthEra > 0 && G.year >= 1990;
  const _breadthNote = _breadthActive
    ? `<div class="ibox" style="border-color:var(--grn);margin-bottom:8px"><strong style="color:var(--grn)">◆ CLUSTER DEMO COVERAGE: +${Math.round(_breadthBonus*_breadthEra*100)}% SELLOUT BONUS</strong><br><span style="font-size:14px;color:var(--off)">Ad agencies pay a premium when you can reach younger, middle and older demos across one company&apos;s stations. Having stations with ratings across different age demographics can unlock these sellout bonuses.</span></div>`
    : _bandCount < 2 && G.year >= 1990
      ? `<div class="ibox" style="font-size:14px;color:var(--mut)">Ad agencies pay a premium when you can reach younger, middle and older demos across one company&apos;s stations — add formats that cover different age demographics to unlock sellout bonuses.</div>`
      : '';
  const norm0 = FM[canonicalHitsFormatKey(s.format)]?.sp || 14;
  SS = { sid, val: s.ops.spots };
  const spotBlock =
    '<div class="bm-section-h" style="margin-top:14px">SPOT LOAD (COMMERCIAL INVENTORY)</div>' +
    '<p class="di" style="margin-top:4px">More spots means more revenue, but more minutes of commercials usually hurt TSL (time spent listening) and can bring down ratings.</p>' +
    '<p class="di" style="margin-top:6px">The normal for this format is <strong>' +
    norm0 +
    ' min/hr</strong>.</p>' +
    '<div class="ibox" id="wl-ft-tut-spot-block" style="margin-bottom:8px;box-sizing:border-box">' +
    '<div class="slsec">' +
    '<div class="sll"><span>COMMERCIAL MINUTES / HOUR</span><strong id="sp-val">' +
    s.ops.spots +
    ' min/hr</strong></div>' +
    '<input type="range" min="6" max="22" value="' +
    s.ops.spots +
    '" oninput="updSpots(\'' +
    s.id +
    '\',this.value)">' +
    '<div class="sln2" id="sp-note"></div></div>' +
    '<p class="di" style="margin:10px 0 0;font-size:14px"><strong>Current:</strong> ' +
    s.ops.spots +
    ' min/hr · ' +
    Math.round(s.ops.sell * 100) +
    '% sellout = ' +
    f$(s.fin.rev) +
    '/period</p>' +
    '<button class="cfm wl-commit-btn wl-commit-btn--synced" id="sp-commit-btn" onclick="doSpots()">SET SPOT LOAD</button></div>';
  document.getElementById('salesb').innerHTML =
    '<p class="di"><strong>' +
    s.callLetters +
    '</strong> · Rank #' +
    rank +
    ' of ' +
    _cr.length +
    ' · ' +
    Math.round(s.ops.sell * 100) +
    '% sellout</p>' +
    spotBlock +
    _breadthNote +
    '<div class="ms2" id="wl-tu-tr-sales-team"><div class="bm-section-h">SALES TEAM</div>' +
    '<p class="di" style="margin-top:4px;margin-bottom:12px">Add people to your sales team to boost revenue.</p>' +
    rows +
    '</div>' +
    '<div class="ibox" style="font-size:15px">Changes to spot load and sales team take effect next period.</div>' +
    `<button class="cfm wl-commit-btn" style="margin-top:10px" onclick="commitSalesPick('${sid}')" ${picked===cur?'disabled style="opacity:.45;pointer-events:none"':''}>APPLY SALES TEAM</button>` +
    '<button class="cnl" onclick="cm(\'m-sales\')">CLOSE</button>';
  updSpots(sid, s.ops.spots);
  refreshSpotCommitStandalone();
  om('m-sales');
  wlFtTutorialNotifySalesOpen();
  /* Turnaround tutorial: opening Sales via a spotlight should clear the map highlight immediately. */
  if(isTutorialTurnaroundScen()&&G?.tutorialMode&&MP.mode!=='live'){
    requestAnimationFrame(()=>tutorialTurnaroundCoachAfterRender());
  }
}
function pickSalesLevel(sid,level){
  sid=ensureOpsSourceSid(sid);
  if(!SALES_PICK||SALES_PICK.sid!==sid) SALES_PICK={sid,level};
  SALES_PICK.level=level;
  openSales(sid);
}
function commitSalesPick(sid){
  sid=ensureOpsSourceSid(sid);
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  const cur=s.salesForce?.level||0;
  const picked=SALES_PICK&&SALES_PICK.sid===sid?SALES_PICK.level:cur;
  if(picked==null||picked===cur)return;
  doSales(sid,picked);
}
function doSales(sid,level){
  sid=ensureOpsSourceSid(sid);
  const s=G.stations.find(st=>st.id===sid);if(!s)return;
  const prev=s.salesForce?.level||0;
  s.salesForce={level,periodsHeld:0};
  const sf=SF_LEVELS[level];
  G.news.unshift({v:'LOW',t:'Sales team at '+s.callLetters+' updated to: '+sf.l+'. Sellout ceiling '+(level>prev?'raised':'lowered')+' next period.',y:G.year,p:G.period});
  MP.action('sales',{sid,level});
  cm('m-sales',{wlTutorialSuppress:true});
  wlFtTutorialTryAdvanceAfterSalesClosed();
  renderAll();
}

/** Solo dev-only: true when cash-bridge audit logging is active (no gameplay changes). */
function wlCashBridgeAuditActive(){
  return typeof globalThis!=='undefined'&&G&&MP&&MP.mode!=='live'&&(
    !!globalThis.__WL_CASH_BRIDGE_AUDIT__||G._traceCashBridge===true
  );
}
function wlCashBridgeAuditCash(){
  return G.cash||0;
}
function wlCashBridgeAuditPush(label,extra){
  if(!wlCashBridgeAuditActive())return;
  if(!G._cashBridgeTurnSteps)G._cashBridgeTurnSteps=[];
  const row=Object.assign({label,cash:wlCashBridgeAuditCash()},extra||{});
  G._cashBridgeTurnSteps.push(row);
}
/**
 * Records one turn row on globalThis.__WL_CASH_BRIDGE_AUDIT_ROWS__ (solo headless / audit runs).
 * Identity: cash_after ≈ cash_before + early_pipeline_delta + lma_net + ebitda − interest + pressure_delta
 */
function wlCashBridgeAuditEmitTurnRow(ctx){
  if(!wlCashBridgeAuditActive())return;
  const wasYear=ctx.wasYear,wasPeriod=ctx.wasPeriod,profit=ctx.profit,cashBefore=ctx.cashBefore;
  const steps=G._cashBridgeTurnSteps||[];
  const beforeLMA=steps.find(s=>s.label==='AFTER_REV_AND_AI_BEFORE_LMA');
  const earlyPipelineDelta=beforeLMA?((beforeLMA.cash||0)-(cashBefore||0)):0;
  const afterLMAStep=steps.find(s=>s.label==='AFTER_LMA');
  const lma=afterLMAStep
    ?{lesseeFees:afterLMAStep.lmaLesseeFees||0,lessorFees:afterLMAStep.lmaLessorFees||0,net:afterLMAStep.lmaNet!=null?afterLMAStep.lmaNet:((afterLMAStep.lmaLessorFees||0)-(afterLMAStep.lmaLesseeFees||0))}
    :(G._cashBridgeLmaSnapshot||(typeof playerLmaCashNetForSolo==='function'?playerLmaCashNetForSolo(G):{lesseeFees:0,lessorFees:0,net:0}));
  const ps=myPS();
  let portfolioTalent=0,portfolioFixed=0,portfolioEffPromo=0,portfolioEffProg=0,portfolioSynd=0;
  const tRev=ps.reduce((s,st)=>{
    const f=st.fin||{};
    portfolioTalent+=f.tal||0;
    portfolioFixed+=f.fix||0;
    portfolioEffPromo+=f.effPromo||0;
    portfolioEffProg+=f.effProg||0;
    portfolioSynd+=f.syndicationRights||0;
    return s+(f.rev||0);
  },0);
  const tCost=ps.reduce((s,st)=>s+(st.fin?.cost||0),0);
  const loanInt=G._lastLoanInterestCharge||0;
  const pressureD=G._lastPressureCashDelta||0;
  const cashAfterRollover=ctx.cashAfterRollover!=null?ctx.cashAfterRollover:wlCashBridgeAuditCash();
  const expected=
    (cashBefore||0)+earlyPipelineDelta+(lma.net||0)+profit-loanInt+pressureD;
  const delta=cashAfterRollover-expected;
  const debtAfter=typeof debtPrincipalForPid==='function'?debtPrincipalForPid(G,loanPidForGame()):0;
  const debtBefore=G._cashBridgeDebtBeforeAdvTurn!=null?G._cashBridgeDebtBeforeAdvTurn:debtAfter;
  const debtPrincipalDelta=debtAfter-debtBefore;
  const advTurnNetCashChange=cashAfterRollover-(cashBefore||0);
  const modal=G._cashBridgeModalSnapshot||{};
  const modalCash=modal.modalCashOnHand;
  const mkt=G.marketId||'atlanta';
  const name=(typeof G.companyName==='string'&&G.companyName.trim())?G.companyName.trim():'Player';
  const row={
    scenarioId:G._cashBridgeScenarioId||'',
    marketId:mkt,
    marketLabel:(MARKETS[mkt]||MARKETS.atlanta)?.label||mkt,
    year:wasYear,
    period:wasPeriod,
    season:wasPeriod===2?'FALL':'SPRING',
    playerOrGroupName:name,
    cash_before_advance:cashBefore,
    early_pipeline_cash_delta:earlyPipelineDelta,
    total_station_revenue:tRev,
    total_station_operating_cost:tCost,
    total_station_ebitda:profit,
    portfolio_talent_cost:portfolioTalent,
    portfolio_fixed_cost:portfolioFixed,
    portfolio_eff_promo:portfolioEffPromo,
    portfolio_eff_prog:portfolioEffProg,
    portfolio_promo_prog_total:portfolioEffPromo+portfolioEffProg,
    portfolio_syndication_rights:portfolioSynd,
    lma_cash_in:lma.lessorFees,
    lma_cash_out:lma.lesseeFees,
    lma_net:lma.net,
    loan_interest:loanInt,
    loan_interest_cash_out:loanInt,
    debt_principal_start:debtBefore,
    debt_principal_end:debtAfter,
    debt_principal_delta:debtPrincipalDelta,
    new_borrowing_principal_increase:debtPrincipalDelta>0?debtPrincipalDelta:0,
    debt_principal_paid:0,
    acquisitions_or_station_purchase_cost:0,
    station_sale_or_distress_cash_from_pressure:pressureD>0?pressureD:0,
    capex_or_upgrade_costs:0,
    talent_signing_or_buyout_in_rollover:0,
    pressure_net_cash_delta:pressureD,
    cash_after_all_rollover_steps:cashAfterRollover,
    computed_expected_cash_after:expected,
    adv_turn_net_cash_change:advTurnNetCashChange,
    cash_bridge_residual:delta,
    delta,
    modal_net_ebitda:modal.modalNetEbitda,
    modal_cash_on_hand:modalCash,
    modal_loan_interest:modal.modalLoanInterest,
    modal_debt_principal_outstanding:modal.modalDebtPrincipalOutstanding,
    modal_total_revenue:modal.modalTotalRevenue,
    modal_total_operating_cost:modal.modalTotalOperatingCost,
    steps:steps.slice(),
    anomaly_large_delta:Math.abs(delta)>1,
    anomaly_modal_cash_mismatch:modalCash!=null&&Math.abs(modalCash-cashAfterRollover)>1,
    anomaly_modal_ebitda_mismatch:modal.modalNetEbitda!=null&&modal.modalNetEbitda!==profit,
  };
  row.anomaly_reconcile_fail=Math.abs(delta)>1;
  globalThis.__WL_CASH_BRIDGE_AUDIT_ROWS__=globalThis.__WL_CASH_BRIDGE_AUDIT_ROWS__||[];
  globalThis.__WL_CASH_BRIDGE_AUDIT_ROWS__.push(row);
  if(G._traceCashBridge){
    try{G._lastSoloCashBridge=JSON.parse(JSON.stringify(row));}catch(_e){G._lastSoloCashBridge=row;}
  }
}

function advTurn(mpCoalesceSeq){
  if(!G)return;
  const btn=document.getElementById('abtn');
  btn.disabled=true;btn.textContent='⟳ PROCESSING...';
  setTimeout(()=>{
    try{
      // Drop stale advTurn if a newer run_advturn superseded this one (duplicate handlers / double server signal).
      if (mpCoalesceSeq != null && mpCoalesceSeq !== MP._advTurnReceiveSeq) {
        if (btn) { btn.disabled = false; btn.textContent = '▶ NEXT PERIOD'; }
        MP.renderStatus();
        return;
      }
      if(wlCashBridgeAuditActive()){
        G._cashBridgeTurnSteps=[];
        G._cashBridgeCashBefore=wlCashBridgeAuditCash();
        G._cashBridgeDebtBeforeAdvTurn=typeof debtPrincipalForPid==='function'?debtPrincipalForPid(G,loanPidForGame()):0;
        wlCashBridgeAuditPush('BEFORE_ADVANCE',{year:G.year,period:G.period});
      }
      // Solo: snapshot wallet before revenue phase — franchise/sports resolution & other pre-seedRev hooks can move cash;
      // finHistory + harness verify use this with EBITDA/LMA/interest/pressure for a closed cash identity.
      if(MP.mode!=='live') G._advTurnCashStartOfTurn=G.cash||0;
      G._fccRegulatoryThisTurn=[];
      normalizeSimulcastLinksInPlace(G);
      enforceFmNonDupConstraints(G);
      finalizeTalentBenchEndOfTurn(G);
      const tutSolo=isTutorialTurnaroundScen()&&MP.mode!=='live'&&(G.tutorialAct|0)<8;
      const simQuiet=tutSolo||!!G._wlHarnessDeterministic;
      if(!simQuiet)processAtlanta1970DeferredLaunches(G);
      if(!simQuiet)processMegaMarketFragmentationLaunches(G);
      const ev=simQuiet?[]:[...chkEv(G),...applyDriftInflections(G),...pledgeDriveCheck(G),...runMarketAttrition(G)];
    corporateDecay(G);
    if(!simQuiet)runCorpLMAOffers(G);
    if(!simQuiet)talentEvents(G);
    const troubleActs=simQuiet?[]:triggerTalentTrouble(G);
    troubleActs.forEach(a=>G.news.unshift({...a,y:G.year,p:G.period}));
    const franchiseTroubleActs=!G.pendingDecisionEvent&&!simQuiet?triggerFranchiseTrouble(G):[];
    franchiseTroubleActs.forEach(a=>G.news.unshift({...a,y:G.year,p:G.period}));
    if(!simQuiet)rivalReformat(G);
    const sportsActs=simQuiet?[]:(runSportsEvents(G)||[]);
    const franchiseActs=simQuiet?[]:(runFranchiseEvents(G)||[]);
    sportsActs.forEach(a=>G.news.unshift({...a,y:G.year,p:G.period}));
    franchiseActs.forEach(a=>G.news.unshift({...a,y:G.year,p:G.period}));
    recalc(G.stations,G);
    snapMarketRankBookDisplay(G);
    unshiftRatingsDigest(G);
    // Snapshot ranks BEFORE checkRankMilestones updates _prevRank,
    // so the MP broadcast block can build per-player milestones accurately.
    const _rankSnap={};
    if(MP.mode==='live'){
      const _combinedRows=buildCommercialCombinedRankRows(G);
      G.ps.forEach(s=>{ _rankSnap[s.id]={prev:s._prevRank??null, cur:combinedMarketRankForStation(s,_combinedRows)}; });
    }
    checkRankMilestones(G);
    const acts=simQuiet?[]:(runAI(G)||[]);
    aiRivalPersistTurnSnapshot(G);
    seedRev(G.stations,G);
    updateAllStationsBudgetStress(G);
    runAIVirtualLoanRepay(G);
    updateAiRivalNegEbitdaStreaks(G);
    // Post-revenue consolidation uses current-period fin.rev for deal pricing; news merged below like runAI acts.
    const consolidationActs=simQuiet?[]:runConsolidation(G);
    const indieAcqActs=simQuiet?[]:runIndependentAcquisitions(G);
    if(wlCashBridgeAuditActive())wlCashBridgeAuditPush('AFTER_REV_AND_AI_BEFORE_LMA',{});
    if(MP.mode!=='live'){
      G._advTurnEarlyPipelineCashDelta=(G.cash||0)-(G._advTurnCashStartOfTurn||0);
    }
    processLMAFees(G);
    if(wlCashBridgeAuditActive()){
      const _lma=playerLmaCashNetForSolo(G);
      G._cashBridgeLmaSnapshot=_lma;
      wlCashBridgeAuditPush('AFTER_LMA',{lmaLesseeFees:_lma.lesseeFees,lmaLessorFees:_lma.lessorFees,lmaNet:_lma.net});
    }
    // MP: credit each player's cash independently from their own stations
    if (MP.mode === 'live') {
      if (!G._playerCash) G._playerCash = {};
      const allOwners = [...new Set(G.ps.map(s => s._mpOwner).filter(id => id !== undefined))];
      allOwners.forEach(pid => {
        const pProfit = G.ps.filter(s => s._mpOwner === pid).reduce((s,st) => s + st.fin.ebitda, 0);
        G._playerCash[pid] = (G._playerCash[pid] || 0) + pProfit;
      });
      G.cash = G._playerCash[MP.playerId] || 0;
    }
    const profit = myPS().reduce((s,st) => s + st.fin.ebitda, 0);
    if (MP.mode !== 'live') G.cash += profit;
    if(wlCashBridgeAuditActive())wlCashBridgeAuditPush('AFTER_EBITDA',{profit});
    // Score tracking
    // UNDERDOG VP: apply once at game start (first period only)
    if(MP.mode==='live'&&G._underdogVP&&!G._underdogVPApplied){
      const myUnderdogBonus=G._underdogVP[MP.playerId]||0;
      if(myUnderdogBonus>0){
        G.score.vp=(G.score.vp||0)+myUnderdogBonus;
        G.news.unshift({v:'HIGH',t:`🏆 Underdog bonus: +${myUnderdogBonus} VP for taking on a difficult starting position.`,y:G.year,p:G.period,iy:true});
        G._underdogVPApplied=true;
      }
    }
    if(!G.score.isSandbox){
      const bestShare=Math.max(0,...myPS().map(s=>s.rat.share));
      G.score.shareHistory.push(bestShare);
      const totalRev=myPS().reduce((s,st)=>s+st.fin.rev,0);
      if(totalRev>G.score.peakRevenue)G.score.peakRevenue=totalRev;
    }
    // MP: track score per player so end-game comparison works (host tracks ALL players)
    if(MP.mode==='live'){
      if(!G._playerScore)G._playerScore={};
      const _allOwners=[...new Set(G.ps.map(s=>s._mpOwner).filter(id=>id!==undefined))];
      _allOwners.forEach(pid=>{
        if(!G._playerScore[pid])G._playerScore[pid]={shareHistory:[],peakRevenue:0,cash:0};
        const _ps=G._playerScore[pid];
        const _pStns=G.ps.filter(s=>s._mpOwner===pid);
        const _pBestShare=Math.max(0,..._pStns.map(s=>s.rat.share));
        _ps.shareHistory.push(_pBestShare);
        const _pRev=_pStns.reduce((s,st)=>s+st.fin.rev,0);
        if(_pRev>_ps.peakRevenue)_ps.peakRevenue=_pRev;
        _ps.cash=G._playerCash[pid]||0;
      });
    }
    // Ranker snapshot (numeric year/period so JSON saves match entryTurn lookups reliably)
    const snap={year:Number(G.year),period:Number(G.period),label:`${G.year} ${PERIODS[G.period-1]}`,shares:{}};
    G.stations.forEach(s=>{ if(!s||s._bpSlotDeferred||!s.id)return; snap.shares[s.id]=s.rat.share; });
    G.rankerHistory.push(snap);
    acts.forEach(a=>G.news.unshift({...a,y:G.year,p:G.period}));
    consolidationActs.forEach(a=>G.news.unshift({...a,y:G.year,p:G.period}));
    indieAcqActs.forEach(a=>G.news.unshift({...a,y:G.year,p:G.period}));
    ev.forEach(e=>{
      const body=e.d!=null&&String(e.d).trim()!==''?String(e.d):'';
      G.news.unshift({v:'HIGH',t:body?`📡 ${e.t}: ${body}`:`📡 ${e.t}`,y:e.y,p:e.p});
    });
    injectTradeNewsForeshadow(G);
    // Seasonal market note — brief context at the top of the feed each period
    const nextPeriodName=G.period===2?'FALL':'SPRING'; // period hasn't advanced yet
    const nextIsElection=G.period===2&&G.year%2===0;
    const seasonNote=G.period===2
      ?`📈 Fall ad market: peak season. Revenue runs ~12% above annual average.${nextIsElection?' Political buys boosting News/Talk and Sports.':''}`
      :`📉 Spring ad market: lean season. Revenue runs ~12% below annual average. Plan cash flow accordingly.`;
    G.news.unshift({v:'LOW',t:seasonNote,y:G.year,p:G.period});
    if(G.news.length>50)G.news=G.news.slice(0,50);
    updateLoanNegEbitdaStreaks(G);
    applyLoanInterest();
    if(wlCashBridgeAuditActive()){
      wlCashBridgeAuditPush('AFTER_INTEREST',{loanInterest:G._lastLoanInterestCharge||0});
    }
    // Ad market recovery: recessions cause permanent hits in the current model,
    // but real markets recover. Drift adx back toward baseline at 2.5%/period.
    // This means a -0.10 shock fully recovers in ~4 periods (2 years) — realistic.
    // Baseline is 1.0 + Atlanta bonus (0.02). Never recovers past 1.15 (secular ceiling).
    const adxBaseline=(MARKETS[G.marketId||'atlanta']?.adxBonus||0)+1.0;
    G.adx=Math.min(1.15, G.adx+(adxBaseline-G.adx)*0.025);
    G.ps.forEach(s=>{
      // Spot load above format norm hurts talent morale
      const fmtNorm=FM[canonicalHitsFormatKey(s.format)]?.sp||14;
      if(s.ops.spots>fmtNorm*1.15){
        const overload=(s.ops.spots/fmtNorm)-1.15;
        Object.values(s.prog).forEach(sd=>{
          if(sd?.talent)sd.talent.morale=Math.max(20,sd.talent.morale-Math.round(overload*10));
        });
      }
    });
    precomputeVoiceTrackingCompanyLoad(G);
    G.stations.forEach(s=>decay(s,G.year,G.period));
    updateSuperstars(G);
    const _cashBeforePressure=G.cash;
    const alerts=checkPressure(G);
    if(G)G._lastPressureCashDelta=(G.cash||0)-(_cashBeforePressure||0);
    if(wlCashBridgeAuditActive()){
      wlCashBridgeAuditPush('AFTER_PRESSURE',{pressureCashDelta:G._lastPressureCashDelta||0});
    }
    // Advance clock before showSum so wasYear/wasPeriod are available to pass in
    const wasYear=G.year,wasPeriod=G.period;
    recordCompanyFinHistory(G, wasYear, wasPeriod, profit);
    recordStationFinHistory(G, wasYear, wasPeriod);
    /* GM Mode: evaluation layer only — reads finHistory + franchise snapshots; does not alter sim math. */
    if(typeof wlGmMode!=='undefined'&&wlGmMode.onPeriodClose)wlGmMode.onPeriodClose(G,wasYear,wasPeriod);
    try{
      if(typeof wlCampaignOnPeriodClose==='function')wlCampaignOnPeriodClose(G,wasYear,wasPeriod);
    }catch(_e){}
    G._lastTurnHeadlines=(G.news||[]).filter(n=>n&&n.y===wasYear&&n.p===wasPeriod);
    if(wlCashBridgeAuditActive()){
      const _ps=myPS();
      const _tRev=_ps.reduce((s,st)=>s+(st.fin?.rev||0),0);
      const _tCost=_ps.reduce((s,st)=>s+(st.fin?.cost||0),0);
      const _myInt=G._lastLoanInterestCharge||0;
      const _debt=debtPrincipalForPid(G,loanPidForGame());
      G._cashBridgeModalSnapshot={
        displayYear:wasYear,
        displayPeriod:wasPeriod,
        modalNetEbitda:profit,
        modalTotalRevenue:_tRev,
        modalTotalOperatingCost:_tCost,
        modalLoanInterest:_myInt,
        modalDebtPrincipalOutstanding:_debt,
        modalCashOnHand:mpMyCashOnHand(),
      };
    }
    showSum(profit,ev,acts,alerts,wasYear,wasPeriod,{sportsActs,franchiseActs});
    let _cbaCashAfterRollover;
    if(wlCashBridgeAuditActive()){
      wlCashBridgeAuditPush('AFTER_SHOWSUM_MODAL_FIELDS_CAPTURED',{note:'G.cash unchanged'});
      _cbaCashAfterRollover=wlCashBridgeAuditCash();
    }
    // Multiplayer: campaign ends after Fall 2025 — build scores while G.year is still 2025 (playerScoreCalc weights)
    if(MP.mode==='live'&&!G.continuesBeyondEnd&&wasYear===2025&&wasPeriod===2){
      G.mpPhase='endgame';
      G._mpFinalResults=buildMpFall2025EndgameResults();
      G._mpShowEndgameAfterSumClose=true;
    }
    if(wlCashBridgeAuditActive())wlCashBridgeAuditPush('FINAL_CASH_PRE_CLOCK',{});
    if(G.period===1){G.period=2;}else{G.period=1;G.year++;}
    if(G.year>wasYear&&!G._hitsChrTransitionNewsShown&&hitsLineageUsesEarlyTop40Branding(wasYear)&&!hitsLineageUsesEarlyTop40Branding(G.year)){
      const mktLab=MARKETS[G.marketId||'atlanta']?.label||'The market';
      G.news.unshift({v:'MEDIUM',t:`📡 ${mktLab}: Top 40 gives way to CHR — Contemporary Hit Radio — as the hits lineage is billed for the FM era.`,y:G.year,p:G.period});
      G._hitsChrTransitionNewsShown=true;
    }
    G.turn=(G.turn||0)+1;
    tutorialTurnaroundOnAdvTurnComplete();
    if(!simQuiet)maybeRollStationListingOfferForPlayer(G);
    if(wlCashBridgeAuditActive()){
      wlCashBridgeAuditPush('FINAL_CASH_AFTER_CLOCK',{year:G.year,period:G.period});
      wlCashBridgeAuditEmitTurnRow({
        wasYear,
        wasPeriod,
        profit,
        cashBefore:G._cashBridgeCashBefore,
        cashAfterRollover:_cbaCashAfterRollover,
      });
      const _rows=globalThis.__WL_CASH_BRIDGE_AUDIT_ROWS__;
      if(_rows&&_rows.length){
        const _last=_rows[_rows.length-1];
        _last.cash_after_clock_advance=wlCashBridgeAuditCash();
        _last.anomaly_modal_cash_mismatch=_last.modal_cash_on_hand!=null&&Math.abs(_last.modal_cash_on_hand-_last.cash_after_all_rollover_steps)>1;
      }
    }
    // BP-slot entrants scheduled for the new calendar period appear as soon as the clock advances
    // (start-of-turn processing still runs for launches tied to the period being simulated).
    if(!simQuiet)processAtlanta1970DeferredLaunches(G);
    if(!simQuiet)processMegaMarketFragmentationLaunches(G);
    // Keep G.fmp in sync with smoothstep curve (used by UI display and legacy references)
    G.fmp=effectiveFmpForMarket(G.year,G.marketId||ACTIVE_MARKET);
    // Decade grade at end of fall of decade-end year
    const startYr=G.sc.startYear||1970;
    const decadeEnd=[1979,1989,1999,2009,2019,2020].filter(y=>y>startYr);
    if(decadeEnd.includes(wasYear)&&wasPeriod===2){
      const sc=scoreCalc(G);
      G.score.decadeScores[wasYear]=sc;
      // MP: store per-player decade score for ALL players (host is authoritative)
      if(MP.mode==='live'){
        if(!G._playerScore)G._playerScore={};
        const _dcOwners=[...new Set(G.ps.map(s=>s._mpOwner).filter(id=>id!==undefined))];
        _dcOwners.forEach(pid=>{
          if(!G._playerScore[pid])G._playerScore[pid]={shareHistory:[],peakRevenue:0,cash:0};
          if(!G._playerScore[pid].decadeScores)G._playerScore[pid].decadeScores={};
          const _pidSc=playerScoreCalc(pid);
          G._playerScore[pid].decadeScores[wasYear]=_pidSc;
          G._playerScore[pid].totalVP=Object.values(G._playerScore[pid].decadeScores).reduce((s,d)=>s+(d.vp||0),0);
        });
      }
      if(wasYear===2020){G.score.isSandbox=true;}
      // In MP each client shows their own score, not the host's shared scoreCalc
      const _gradeScForDisplay = (MP.mode==='live') ? playerScoreCalc(MP.playerId) : sc;
      const trialSignupEnd=MP.mode!=='live'&&G.wlSignupTrial&&!G._wlTrialEndModalShown&&wasYear===2020&&wasPeriod===2;
      if(trialSignupEnd)setTimeout(()=>wlShowTrialSignupCompleteModal(_gradeScForDisplay),1600);
      else setTimeout(()=>showGrade(wasYear,_gradeScForDisplay),1400);
    }
    autoSave();
    renderAll();
    try{
      if(MP.mode!=='live'&&typeof wlCampaignAfterRenderAll==='function')wlCampaignAfterRenderAll(G);
    }catch(_e){}
    queuePlayerTalentPortraits();
    queueAutoLogosForPlayerStations();
    // MP: if host, broadcast new state to all clients
    if (MP.mode === 'live' && MP.isHost) {
      const _dcYear = decadeEnd.includes(wasYear) && wasPeriod===2 ? wasYear : null;
      // Build per-player milestones from the pre-checkRankMilestones snapshot
      const _allMs = [];
      const _msSeenPairs=new Set();
      G.ps.forEach(s=>{
        const partner=simulcastPartnerStation(s);
        if(partner){
          const pk=[s.id,partner.id].sort().join('|');
          if(_msSeenPairs.has(pk))return;
          _msSeenPairs.add(pk);
        }
        const snap=_rankSnap[s.id]; if(!snap||snap.prev===null||snap.cur==null) return;
        const prev=snap.prev, cur=snap.cur;
        const gained=cur<prev, lost=cur>prev;
        const sh=milestoneRankSharePct(s);
        const owner=MP.players?.find(p=>p.playerId===s._mpOwner)?.name||'';
        const pfx=owner?`${owner}'s `:'';
        const op=simulcastOperationalSource(s);
        const labelHtml=milestoneRankLabelHtml(s);
        const fmtSeg=` (${pfx}${fmtLabel(op.format)})`;
        let m=null;
        if(cur===1&&prev>1) m={type:'gain',title:'NUMBER ONE',body:`${labelHtml}${fmtSeg} is now #1 in the market — ${sh} share.`,owner:s._mpOwner};
        else if(cur>1&&prev===1) m={type:'loss',title:'LOST #1',body:`${labelHtml}${fmtSeg} has fallen from #1. Now #${cur} at ${sh}.`,owner:s._mpOwner};
        else if(gained&&cur<=5&&prev>5) m={type:'gain',title:'TOP 5',body:`${labelHtml}${fmtSeg} breaks into the top 5 — ranked #${cur} with ${sh}.`,owner:s._mpOwner};
        else if(lost&&cur>5&&prev<=5) m={type:'loss',title:'OUT OF TOP 5',body:`${labelHtml}${fmtSeg} slips out of the top 5.`,owner:s._mpOwner};
        else if(gained&&cur<=10&&prev>10) m={type:'gain',title:'TOP 10',body:`${labelHtml}${fmtSeg} enters the top 10 at #${cur}.`,owner:s._mpOwner};
        else if(lost&&cur>10&&prev<=10) m={type:'loss',title:'OUT OF TOP 10',body:`${labelHtml}${fmtSeg} has dropped out of the top 10.`,owner:s._mpOwner};
        if(m) _allMs.push(m);
      });
      mpBroadcastState(_dcYear, { profit, ev, acts, alerts, wasYear, wasPeriod, milestones:_allMs, fccRegulatory:G._fccRegulatoryThisTurn||[], sportsActs, franchiseActs });
      MP.renderStatus();
    } else {
      btn.disabled=false;btn.textContent='▶ NEXT PERIOD';
    }
    if(MILESTONE_Q.length)setTimeout(flushMilestones,900);
    }catch(err){
      console.error('advTurn error:',err);
      btn.disabled=false;btn.textContent='▶ NEXT PERIOD';
    }
  },450);
}

// ── MP FALL 2025 ENDGAME (multiplayer campaign finale) ───────────
function mpEndgameFrozen(){
  return MP.mode==='live'&&G&&G.mpPhase==='endgame'&&!G.continuesBeyondEnd;
}
/** Composite ranking for MP finale — tiebreak: VP → score/100 → cash. */
function buildMpFall2025EndgameResults(){
  const allPids=[...new Set(G.ps.map(s=>s._mpOwner).filter(id=>id!==undefined))].sort((a,b)=>a-b);
  const players=allPids.map(pid=>{
    const sc=playerScoreCalc(pid);
    const ps=G._playerScore?.[pid]||{};
    const totalVP=ps.totalVP||Object.values(ps.decadeScores||{}).reduce((s,d)=>s+(d.vp||0),0);
    const cash=G._playerCash?.[pid]||0;
    const stns=G.ps.filter(s=>s._mpOwner===pid);
    const stationCount=stns.length;
    const totalRev=stns.reduce((s,st)=>s+(st.fin?.rev||0),0);
    const estValue=Math.round(stns.reduce((s,st)=>s+Math.max(0,(st.fin?.rev||0))*8,0));
    const name=(MP.players||[]).find(p=>p.playerId===pid)?.name||`Player ${pid+1}`;
    const finalScore=totalVP*10000+Math.round(sc.total)*100+Math.floor(cash/1000);
    return {pid,name,finalScore,totalVP,score100:sc.total,cash,stationCount,totalRev,estValue};
  });
  players.sort((a,b)=>b.finalScore-a.finalScore||b.totalVP-a.totalVP||b.cash-a.cash||b.score100-a.score100);
  const top=players[0]?.finalScore;
  const winnerPids=players.filter(p=>p.finalScore===top).map(p=>p.pid);
  const coWinners=winnerPids.length>1;
  return {year:2025,players,winnerPids,coWinners,topScore:top};
}
function showMpEndgameModal(){
  if(MP.mode!=='live'||!G._mpFinalResults)return;
  const r=G._mpFinalResults;
  const lateDual=typeof buildMpLateEraFinaleHtml==='function'?buildMpLateEraFinaleHtml(G):'';
  const winNames=r.winnerPids.map(pid=>(MP.players||[]).find(p=>p.playerId===pid)?.name||`Player ${pid+1}`).join(' · ');
  const rows=r.players.map((p,i)=>{
    const isW=r.winnerPids.includes(p.pid);
    return`<div class="mp-endgame-row" style="display:flex;align-items:center;gap:12px;padding:12px 14px;border-bottom:1px solid rgba(255,255,255,.08);${isW?'background:rgba(212,175,55,.09)':''}">
      <div style="font-family:var(--fd);font-size:22px;color:${isW?'var(--amb)':'var(--mut)'};width:32px">${i+1}</div>
      <div style="flex:1;min-width:0">
        <div style="font-family:var(--ft);font-size:15px;letter-spacing:.12em;color:${isW?'var(--wht)':'var(--off)'}">${p.name.toUpperCase()}</div>
        <div style="font-family:var(--ft);font-size:14px;color:var(--mut);margin-top:4px">${f$(p.cash)} cash · ${p.stationCount} station${p.stationCount===1?'':'s'} · ${f$(p.totalRev)}/pd revenue · ~${f$(p.estValue)} est. value</div>
      </div>
      <div style="text-align:right">
        <div style="font-family:var(--fd);font-size:24px;color:${isW?'var(--amb)':'var(--off)'}">${p.finalScore}</div>
        <div style="font-family:var(--ft);font-size:12px;color:var(--mut)">FINAL SCORE</div>
        <div style="font-family:var(--ft);font-size:13px;color:var(--mut);margin-top:2px">${p.totalVP} VP · ${p.score100}/100</div>
      </div>
    </div>`;
  }).join('');
  const winLine=r.coWinners
    ?`<div class="mp-endgame-winner" style="text-align:center;padding:16px 12px 8px;font-family:var(--fd);font-size:22px;color:var(--amb);text-shadow:0 0 24px rgba(212,175,55,.35)">🏆 CO-WINNERS: ${winNames}</div>`
    :`<div class="mp-endgame-winner" style="text-align:center;padding:16px 12px 8px;font-family:var(--fd);font-size:24px;color:var(--amb);text-shadow:0 0 28px rgba(212,175,55,.4)">🏆 WINNER: ${winNames}</div>`;
  const el=document.getElementById('mp-endgame-body');
  if(el) el.innerHTML=`<p class="di" style="font-size:15px;color:var(--mut);margin:0 0 14px 0;line-height:1.5">Fall 2025 ends the competitive campaign. Final score weights victory points, performance index, and cash. You may continue in sandbox after this screen.</p>${winLine}${lateDual}<div style="margin-top:8px;border:1px solid rgba(212,175,55,.25);border-radius:6px;overflow:hidden">${rows}</div>`;
  document.body.classList.add('mp-endgame');
  om('m-mp-endgame');
}
function mpContinueBeyondEndgame(){
  if(MP.mode!=='live'||!G)return;
  if(G.mpPhase!=='endgame')return;
  G.continuesBeyondEnd=true;
  G.mpPhase='playing';
  G._mpShowEndgameAfterSumClose=false;
  cm('m-mp-endgame');
  document.body.classList.remove('mp-endgame');
  renderAll();
  MP.action('mp_continue',{});
}
window._mpApply_mp_continue=function(){
  if(!G)return;
  G.continuesBeyondEnd=true;
  G.mpPhase='playing';
  G._mpShowEndgameAfterSumClose=false;
  cm('m-mp-endgame');
  document.body.classList.remove('mp-endgame');
  renderAll();
  MP.renderStatus();
};

// ── MP END-GAME COMPARISON ───────────────────────────────────────
function mpEndGameHTML(){
  if(MP.mode!=='live'||!G._playerScore)return '';
  const allPids=[...new Set(G.ps.map(s=>s._mpOwner).filter(id=>id!==undefined))];
  if(allPids.length<2)return '';

  // Build result rows per player
  const rows=allPids.map(pid=>{
    const pName=MP.players.find(p=>p.playerId===pid)?.name||`Player ${pid+1}`;
    const pColor=['#f5a623','#60a5fa','#34d399','#f87171'][pid%4];
    const ps=G._playerScore[pid]||{};
    const totalVP=ps.totalVP||Object.values(ps.decadeScores||{}).reduce((s,d)=>s+(d.vp||0),0)||0;
    const latestSc=Object.values(ps.decadeScores||{}).slice(-1)[0]||{};
    const cash=G._playerCash?.[pid]||0;
    const isMe=pid===MP.playerId;
    return {pid,pName,pColor,totalVP,score:latestSc.total||0,cash,isMe};
  }).sort((a,b)=>b.totalVP-a.totalVP||(b.score-a.score)||(b.cash-a.cash));

  const winner=rows[0];
  const iWon=winner.pid===MP.playerId;

  const rowsHTML=rows.map((r,i)=>`
    <div style="display:flex;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid var(--brdr)">
      <div style="font-size:20px;font-family:var(--fd);color:${i===0?'var(--amb)':'var(--mut)'};width:24px">${i===0?'🏆':`#${i+1}`}</div>
      <div style="flex:1">
        <div style="color:${r.pColor};font-family:var(--ft);font-size:14px;letter-spacing:.08em">${r.pName.toUpperCase()}${r.isMe?' <span style="color:var(--mut)">(YOU)</span>':''}</div>
        <div style="color:var(--mut);font-size:14px;margin-top:2px">${r.score}/100 · ${f$(r.cash)} cash</div>
      </div>
      <div style="text-align:right">
        <div style="font-size:22px;font-family:var(--fd);color:${i===0?'var(--amb)':'var(--off)'}">${r.totalVP}</div>
        <div style="font-size:15px;color:var(--mut);font-family:var(--ft)">VP</div>
      </div>
    </div>`).join('');

  return `<div class="ms2" style="border:2px solid ${iWon?'var(--grn)':'var(--red)'};margin-top:12px">
    <div class="msh" style="color:${iWon?'var(--grn)':'var(--red)'}">
      ${iWon?'🏆 VICTORY — YOU WIN!':'DEFEAT — BETTER LUCK NEXT TIME'}
    </div>
    <div style="color:var(--mut);font-size:15px;margin-bottom:8px">
      ${iWon?`Congratulations — you outplayed ${winner.pid!==MP.playerId?rows.find(r=>r.pid!==MP.playerId)?.pName:'your opponent'} over 50 years of Atlanta radio.`
            :`${winner.pName} dominated the Atlanta market. Strong performance, but they edged you out.`}
    </div>
    ${rowsHTML}
    <div style="font-size:15px;color:var(--mut);margin-top:8px;font-family:var(--ft)">TIEBREAKER: VP → SCORE → CASH ON HAND</div>
  </div>`;
}

// ── DECADE GRADE ─────────────────────────────────────────────────
function showGrade(decadeYear,sc){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  const grade=gradeFromScore(sc.total);
  const isFinal=decadeYear===2020;
  const startYr=G.sc.startYear||1970;
  const title=pick(GRADE_TITLES[grade]||GRADE_TITLES.C);
  document.getElementById('gradet').textContent=isFinal?`FINAL SCORE — ${startYr}–2020`:`${DECADE_NAMES[decadeYear]||decadeYear} — REPORT CARD`;
  document.getElementById('gradeb').innerHTML=`
    <div class="grade-hero">
      <div class="grade-letter ${grade}">${grade}</div>
      <div class="grade-title">${title.toUpperCase()}</div>
      <div class="grade-sub">${DECADE_NAMES[decadeYear]||decadeYear} complete. Score: ${sc.total}/100</div>
    </div>
    <div class="score-bars">
      <div class="score-bar-row"><span class="score-bar-lbl">MARKET SHARE</span><div class="score-bar-bg"><div class="score-bar-fill" style="width:${sc.shareScore}%"></div></div><span class="score-bar-val">${sc.shareScore}</span></div>
      <div class="score-bar-row"><span class="score-bar-lbl">CASH GROWTH</span><div class="score-bar-bg"><div class="score-bar-fill" style="width:${sc.cashScore}%"></div></div><span class="score-bar-val">${sc.cashScore}</span></div>
      <div class="score-bar-row"><span class="score-bar-lbl">PEAK REVENUE</span><div class="score-bar-bg"><div class="score-bar-fill" style="width:${sc.peakScore}%"></div></div><span class="score-bar-val">${sc.peakScore}</span></div>
      ${sc.streamScore>0?`<div class="score-bar-row"><span class="score-bar-lbl">DIGITAL</span><div class="score-bar-bg"><div class="score-bar-fill stream" style="width:${sc.streamScore}%"></div></div><span class="score-bar-val">${sc.streamScore}</span></div>`:''}
      ${sc.identityScore>0?`<div class="score-bar-row"><span class="score-bar-lbl">COMMUNITY</span><div class="score-bar-bg"><div class="score-bar-fill" style="width:${sc.identityScore}%;background:var(--grn)"></div></div><span class="score-bar-val">${sc.identityScore}</span></div>`:''}
    </div>
    <div class="ms2"><div class="msh">BREAKDOWN</div>
      <div class="sr"><span class="lb">Avg Best Station Share</span><span class="vl amb">${pct(sc.shareAvg)}</span></div>
      <div class="sr"><span class="lb">Peak Period Revenue</span><span class="vl amb">${f$(sc.peakRevenue||G.score.peakRevenue)}</span></div>
      <div class="sr"><span class="lb">Cash on Hand</span><span class="vl ${(MP.mode==='live'?G._playerCash?.[MP.playerId]:G.cash)||G.cash >= G.sc.cash?'pos':'neg'}">${f$((MP.mode==='live'&&G._playerCash?.[MP.playerId])||G.cash)}</span></div>
      ${sc.debtPenalty>0?`<div class="sr"><span class="lb" style="color:var(--red)">Outstanding Loan Penalty</span><span class="vl neg">−${sc.debtPenalty} pts</span></div>`:''}
      ${sc.streamScore>0?`<div class="sr"><span class="lb">Digital score</span><span class="vl ${sc.streamScore>=60?'pos':'neg'}">${sc.streamScore}/100</span></div>`:''}
    </div>
    <div class="ms2" style="border:2px solid var(--amb);margin-top:12px">
      <div class="msh" style="color:var(--amb)">VICTORY POINTS — ${DECADE_NAMES[decadeYear]||decadeYear}</div>
      <div class="sr"><span class="lb" style="font-size:16px">Points This Decade</span><span class="vl amb" style="font-size:22px;font-family:var(--fd)">${sc.vp} / ${sc.maxVP} VP</span></div>
      <div class="sr"><span class="lb">Cumulative Total</span><span class="vl" style="font-size:16px">${(MP.mode==='live'?Object.values(G._playerScore?.[MP.playerId]?.decadeScores||{}).reduce((s,d)=>s+(d.vp||0),0):Object.values(G.score.decadeScores).reduce((s,d)=>s+(d.vp||0),0))} VP</span></div>
    </div>
    ${isFinal?`<div class="sandbox-cta"><strong>SANDBOX MODE UNLOCKED.</strong> Score locked: ${startYr}–2020 campaign complete. Keep playing into the 2020s and beyond.</div>`:`<div class="sandbox-cta"><strong>KEEP GOING.</strong> Score builds through ${decadeYear+1}. Each decade gets its own grade.</div>`}
    ${isFinal&&MP.mode==='live'?mpEndGameHTML():''}
    <button class="cfm" onclick="cm('m-grade')">${isFinal?'CONTINUE INTO SANDBOX →':'CONTINUE TO '+(decadeYear+1)+' →'}</button>
    ${isFinal?`<button class="cnl" style="width:100%;margin-top:8px" onclick="cm('m-grade');openScenSelect(null)">🎮 PLAY AGAIN — NEW SCENARIO</button>`:''}`;
  om('m-grade');
}

// ── RANKER ────────────────────────────────────────────────────────
/** Owner column: company name (solo), MP lobby names, corporate groups, public, or AI licensee. */
function stationOwnerLabelForRanker(s){
  if(!s||s._bpSlotDeferred)return '';
  if(s.corpOwner&&!s.isPlayer){
    return (typeof s.corpName==='string'&&s.corpName.trim())
      ?s.corpName.trim()
      :((CORPS.find(c=>c.id===s.corpOwner)||{}).name||'Corporate');
  }
  if(s.isPublic)return 'Public';
  if(s.isPlayer){
    if(MP.mode==='live'){
      const pid=s._mpOwner;
      if(pid===undefined||pid===null)return '';
      return (MP.players||[]).find(p=>p.playerId===pid)?.name||`Player ${Number(pid)+1}`;
    }
    const cn=(typeof G.companyName==='string'&&G.companyName.trim())?G.companyName.trim():'';
    return cn||'You';
  }
  const fic=rivalFictionalParentName(s,G);
  return fic||'Independent';
}
/** Build CSV-safe cell (RFC-style quoting). */
function wlCsvEscapeCell(val){
  const s=String(val??'');
  if(/[",\n\r]/.test(s))return '"'+s.replace(/"/g,'""')+'"';
  return s;
}
/**
 * First rankerHistory column index for a station's entry turn (solo/MP saves may stringify year/period in JSON).
 * Returns -1 if unknown — caller should not blank pre-entry cells in that case.
 */
function rankerHistoryColumnIndexForEntryTurn(h, entry){
  if(!h||!h.length||!entry)return -1;
  const ey=Number(entry.year), ep=Number(entry.period);
  if(!Number.isFinite(ey)||!Number.isFinite(ep))return -1;
  return h.findIndex(hh=>Number(hh.year)===ey&&Number(hh.period)===ep);
}
/** Download market ranker share history as CSV (all stations × periods). */
function exportRankerHistoryCsv(){
  if(typeof globalThis!=='undefined'&&globalThis.__WL_HEADLESS__)return;
  const h=G.rankerHistory;
  if(!h||!h.length){
    showToast('No share history to export yet.','warn');
    return;
  }
  const rowObjs=buildSimulcastCombinedRankRows(G.stations);
  const cityRaw=(G.city||MARKETS[G.marketId||'atlanta']?.label||'market').replace(/[\\/:*?"<>|]+/g,'');
  const periodCols=h.map(c=>c.label||`${c.year}`);
  const header=['Station','Owner','Format','Freq'].concat(periodCols);
  const lines=[header.map(wlCsvEscapeCell).join(',')];
  rowObjs.forEach(row=>{
    const s=row.pair?row.lead:row.st;
    const op=simulcastOperationalSource(s);
    const stationLabel=row.pair?`${callDisplay(row.lead)} + ${callDisplay(row.rcv)}`:callDisplay(s);
    const freq=row.pair?`${row.lead.freq} + ${row.rcv.freq}`:String(s.freq??'');
    const owner=stationOwnerLabelForRanker(row.pair?row.lead:s);
    const fmt=fmtLabel(op.format);
    const entry=row.pair?row.lead.entryTurn:s.entryTurn;
    const shareCells=h.map(c=>{
      if(entry){
        const entryIdx=rankerHistoryColumnIndexForEntryTurn(h, entry);
        if(entryIdx>=0&&h.indexOf(c)<entryIdx)return '';
      }
      const v=row.pair?(c.shares[row.lead.id]||0)+(c.shares[row.rcv.id]||0):(c.shares[s.id]||0);
      if(!v)return '';
      return (v*100).toFixed(2);
    });
    lines.push([stationLabel,owner,fmt,freq,...shareCells].map(wlCsvEscapeCell).join(','));
  });
  const bom='\ufeff';
  const blob=new Blob([bom+lines.join('\n')],{type:'text/csv;charset=utf-8'});
  const safeCity=cityRaw.replace(/\s+/g,'-');
  const fn=`airwave-ranker-${safeCity}-${G.year}-P${G.period}.csv`;
  wlDownloadBlobToFile(blob,fn);
  showToast('Share history downloaded (CSV).','info');
}
function openRanker(){
  const rkTitle=document.getElementById('m-rk-title');
  if(rkTitle){
    const lbl=(G.city||MARKETS[G.marketId||'atlanta']?.label||'').toUpperCase();
    rkTitle.textContent=lbl?`MARKET RANKER — ${lbl}`:'MARKET RANKER';
  }
  const wrapEl=document.getElementById('rkwrap');
  const h=G&&Array.isArray(G.rankerHistory)?G.rankerHistory:[];
  if(!h.length){
    if(wrapEl)wrapEl.innerHTML='<p class="di" style="padding:20px">No share history yet. Advance at least one period.</p>';
    return;
  }
  const nPersist=h.length;
  const cols=h.map(c=>({year:c.year,period:c.period,label:c.label,shares:{...c.shares}}));
  const idxCur=h.findIndex(c=>Number(c.year)===Number(G.year)&&Number(c.period)===Number(G.period));
  if(idxCur>=0){
    refreshRankerSnapSharesFromStations(cols[idxCur],G.stations);
  }
  const rowObjs=buildSimulcastCombinedRankRows(G.stations);
  // Column headers — completed books only (no "pre-book/live" overlay column).
  const thd=cols.map((c,i)=>{
    const isR=i===cols.length-1;
    const amb=isR?';color:var(--amb)':'';
    const p3=(c.label.split(' ')[1]||'');
    return `<th style="min-width:54px;text-align:center${amb}"><span style="font-size:15px">${c.year}</span><br><span style="font-size:15px;color:var(--mut)">${p3}</span></th>`;
  }).join('');
  const rows=rowObjs.map(row=>{
    const s=row.pair?row.lead:row.st;
    const isP=row.pair?(mpIsMe(row.lead)||mpIsMe(row.rcv)):mpIsMe(s);
    const entry=row.pair?row.lead.entryTurn:s.entryTurn;
    const cells=cols.map((c,colIdx)=>{
      if(entry){
        const entryIdx=rankerHistoryColumnIndexForEntryTurn(h, entry);
        if(entryIdx>=0&&colIdx<entryIdx&&colIdx<nPersist)return '<td class="stc" style="position:static"></td>';
      }
      const v=row.pair?(c.shares[row.lead.id]||0)+(c.shares[row.rcv.id]||0):(c.shares[s.id]||0);
      if(!v)return '<td>—</td>';
      const pv=(v*100).toFixed(1);
      const cls=v>=.08?'rcv hi':v>=.02?'rcv':v<.005?'rcv lo':'rcv';
      return `<td><span class="${cls}">${pv}</span></td>`;
    }).join('');
    const pubBadge=s.isPublic?'<span style="font-size:13px;background:#1e3a5f;color:#7dd3fc;padding:1px 5px;border-radius:2px;margin-left:4px;font-family:var(--ft)">NPR</span>':'';
    const corpBadge=s.corpOwner&&!s.isPlayer?`<span style="font-size:13px;background:${s.corpColor||'#374151'};color:#fff;padding:1px 5px;border-radius:2px;font-family:var(--ft)">${(s.corpName||'CORP').split(' ')[0]}</span>`:'';
    const intelAttr=!s.isPublic?` onclick="showCompIntel('${s.id}')" style="cursor:pointer" title="${isP?'Open station intel':'View competitor intel'}"`:'';
    const simB=row.pair?'<span style="color:var(--blu);font-size:14px"> ◈</span>':(stationHasSimulcastLeg(s,G)?'<span style="color:var(--blu);font-size:14px"> ◈</span>':'');
    const op=simulcastOperationalSource(s);
    const fmtLbl=fmtLabel(op.format);
    const callLine=row.pair?`${callDisplay(row.lead)} + ${callDisplay(row.rcv)}`:callDisplay(s);
    const freqLine=row.pair?`${row.lead.freq} + ${row.rcv.freq}`:s.freq;
    const lineColor=row.pair?row.lead.color:s.color;
    const ownerNm=stationOwnerLabelForRanker(row.pair?row.lead:s);
    const lineCallFreq=`<div style="display:flex;align-items:center;flex-wrap:wrap;gap:6px;row-gap:2px;min-width:0"><span class="rc" style="color:${lineColor};font-family:var(--fd);flex-shrink:0">${callLine}</span>${simB}${pubBadge}${corpBadge}<span style="color:var(--mut);flex-shrink:0">·</span><span style="color:var(--wht);flex-shrink:0">${freqLine}</span></div>`;
    const lineFmt=`<div class="rf" style="font-size:15px;line-height:1.3;min-width:0;max-width:100%;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${fmtLbl.replace(/"/g,'&quot;')}">${fmtLbl}</div>`;
    const lineOwner=ownerNm
      ?`<div style="font-size:13px;color:var(--mut);font-family:var(--ft);line-height:1.3;margin-top:2px;min-width:0;max-width:100%;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${ownerNm.replace(/"/g,'&quot;')}">${ownerNm}</div>`
      :'';
    const stationCell=`<div style="display:flex;flex-direction:column;gap:0;min-width:0;flex:1;overflow:hidden">${lineCallFreq}${lineOwner}</div>`;
    const rkCls=`${isP?'rky':s.isPlayer?'rkp2':s.isPublic?'rkp':''}`;
    const rkLogo=cosmeticLogoThumbHtmlForStation(s,{compact:true,stopPropagation:true,title:'View logo'});
    return `<tr class="${rkCls}">
      <td class="stc"${intelAttr}><div style="display:flex;align-items:flex-start;gap:8px;min-width:0;max-width:min(420px,50vw);overflow:hidden">${rkLogo}${stationCell}</div></td>
      <td class="stc-fmt"${intelAttr} style="text-align:left;vertical-align:top">${lineFmt}</td>
      ${cells}
    </tr>`;
  }).join('');
  const wrap=document.getElementById('rkwrap');
  wrap.innerHTML=`<table class="rkt rkt--fmtcol"><thead><tr><th class="sth">STATION</th><th class="sth-fmt" title="On-air format">Format</th>${thd}</tr></thead><tbody>${rows}</tbody></table>
    <div style="margin-top:18px;padding-top:14px;border-top:1px solid var(--bdr)">
      <div style="font-family:var(--ft);font-size:14px;color:var(--mut);letter-spacing:2px;margin-bottom:10px">MARKET TALENT <span style="font-size:12px;color:var(--mut);font-weight:400">(quality · all stations)</span></div>
      <div style="max-height:min(38vh,320px);overflow-y:auto;padding-right:4px">${htmlMarketTalentRankerList()}</div>
    </div>`;
  const legEl=document.getElementById('rk-legend');
  if(legEl){
    legEl.style.display='flex';
    legEl.style.flexDirection='column';
    legEl.style.alignItems='flex-end';
    legEl.style.marginTop='12px';
    legEl.innerHTML=`<div style="width:100%;text-align:right"><button type="button" class="abt g" onclick="exportRankerHistoryCsv()">Export share history (CSV)</button></div>`;
  }
  // Scroll to most recent (rightmost) column
  setTimeout(()=>{wrap.scrollLeft=wrap.scrollWidth;},60);
  if(isTutorialTurnaroundScen()&&G?.tutorialMode&&MP.mode!=='live'&&(G.tutorialAct|0)===7&&(G._tutorialAct7Phase|0)===3){
    G._tutorialAct7Phase=4;
    G._tutorialRankerCoachDismissed=false;
    requestAnimationFrame(()=>tutorialTurnaroundCoachAfterRender());
  }
}

// ── COMPETITOR INTEL ──────────────────────────────────────────────
/** Band + power + frequency for intel UI — never emits "undefined" (dial is on `s.freq`; `s.sig.freq` is optional). */
function inferBandFromDialStr(raw){
  if(raw==null||raw==='')return'';
  const n=parseFloat(String(raw).replace(/[^\d.]/g,''));
  if(Number.isNaN(n))return'';
  if(n>=88&&n<=108)return'FM';
  if(n>=0.52&&n<=1.71)return'AM';
  return'';
}
function signalLineForIntel(s){
  if(!s)return'Unknown frequency';
  const sig=s.sig||{};
  const raw=(s.freq!=null&&s.freq!=='')?String(s.freq).trim():((sig.freq!=null&&sig.freq!=='')?String(sig.freq).trim():'');
  const freq=raw||'Unknown frequency';
  let band=sig.type==='FM'?'FM':sig.type==='AM'?'AM':(sig.type?String(sig.type).trim():'');
  if(!band)band=inferBandFromDialStr(raw);
  if(!band)band='AM/FM';
  const pw=sig.pw!=null&&sig.pw!==''?signalPowerDisplayLabel(sig.pw):'';
  const parts=[band];
  if(pw)parts.push(pw);
  parts.push(freq);
  return parts.join(' · ');
}
/** Compact dial + band for Brand & Promotion (simulcast legs). */
function stationDialAndBandForMarketing(s){
  if(!s)return'';
  const sig=s.sig||{};
  const raw=(s.freq!=null&&s.freq!=='')?String(s.freq).trim():((sig.freq!=null&&sig.freq!=='')?String(sig.freq).trim():'');
  const band=sig.type==='FM'||s.fmBooster?'FM':sig.type==='AM'?'AM':inferBandFromDialStr(raw)||'';
  if(raw&&band)return `${raw} ${band}`;
  return raw||'—';
}
/** Station logo thumb — AI raster if present, else deterministic SVG. */
function cosmeticLogoThumbHtmlForStation(s, opts){
  opts=opts||{};
  const op=simulcastOperationalSource(s);
  if(!op)return '';
  const id=op.id;
  let cls='sc-logo-thumb';
  if(opts.compact)cls+=' sc-logo-thumb--compact';
  if(opts.larger)cls+=' sc-logo-thumb--larger';
  const sp=opts.stopPropagation?'event.stopPropagation();':'';
  const title=(opts.title!=null&&opts.title!=='')?opts.title:'View full size';
  let inner='';
  if(op.cosmeticLogoUrl){
    const src=wlGameMediaAbsUrl(op.cosmeticLogoUrl+(op.cosmeticLogoV?'?v='+op.cosmeticLogoV:''));
    inner=`<img alt="Station logo" src="${src}" draggable="false">`;
  }else{
    const svg=wlProceduralLogoSvgString(op);
    if(svg)inner=`<div class="sc-logo-thumb-svgwrap">${svg}</div>`;
  }
  if(!inner)return '';
  return `<div class="${cls}" role="button" tabindex="0" title="${title.replace(/"/g,'&quot;')}" onclick="${sp}wlOpenLogoModal('${id}')" onkeydown="if(event.key==='Enter'||event.key===' '){event.preventDefault();${sp}wlOpenLogoModal('${id}');}">${inner}</div>`;
}
function showCompIntel(sid){
  const s=G.stations.find(st=>st.id===sid);
  if(!s)return;
  const op=simulcastOperationalSource(s);
  const fmd=FM[canonicalHitsFormatKey(op.format)]||{};
  const isOwn=s.isPlayer&&mpIsMe(s);
  const isHumanRival=MP.mode==='live'&&s.isPlayer&&!isOwn;
  const bookIntel=isOwn||isHumanRival;
  const pr=bookIntel?stationCardDisplayCp(s):s.cp;

  // Revenue: fuzzy for AI competitors only; exact for your stations and other humans (MP shared sim).
  const estRev=(isOwn||isHumanRival)?(s.fin?.rev||0):(s.fin?.rev||0)*(0.85+Math.random()*0.30);
  const trend=!pr?'—':pr.col?'⬇⬇ COLLAPSING':pr.under?'⬇ DECLINING':pr.sur?'⬆ SURGING':'→ STABLE';
  const trendColor=!pr?'var(--mut)':pr.col?'var(--red)':pr.under?'var(--amb)':pr.sur?'var(--grn)':'var(--off)';

  // Format strategy: show drift direction if driftable, else "holding position"
  const dr=getDrift(op);
  let strategyLine='';
  if(dr&&dr.cfg){
    const val=dr.val||0;
    const poleAName=dr.cfg.poleA?.name||'Conservative';
    const poleBName=dr.cfg.poleB?.name||'Aggressive';
    const abs=Math.abs(val);
    if(abs<15){
      strategyLine=`<span style="color:var(--off)">Holding center — no strong lean</span>`;
    } else {
      const pole=val>50?poleBName:poleAName;
      const strength=abs>=75?'strongly leaning':abs>=50?'leaning':'slightly leaning';
      strategyLine=`<span style="color:var(--amb)">${strength} toward <strong>${pole}</strong></span>`;
    }
  } else {
    strategyLine=`<span style="color:var(--mut)">Standard format — no positioning drift</span>`;
  }

  // Top demographic
  const topCoh=COH.reduce((best,c)=>{
    const sh=s.rat.cur[c]?.share||0;
    return sh>(s.rat.cur[best]?.share||0)?c:best;
  },COH[0]);
  const cohLabels={'12-17':'Teens (12–17)','18-24':'Young Adults (18–24)','25-34':'Adults 25–34','35-49':'Adults 35–49','50-64':'Adults 50–64','65+':'Seniors 65+'};

  // Competition: who's competing for same listeners
  const competitors=(FMT_COMPETITION[op.format]||[]);
  const sameFormat=G.stations.filter(o=>o.id!==sid&&competitors.includes(o.format));
  const compText=sameFormat.length
    ?sameFormat.map(o=>`<span style="color:${o.isPlayer?'var(--amb)':'var(--mut)'}">${o.callLetters}</span>`).join(', ')
    :'None in direct competition';

  // Quality indicators — fuzzy/rounded
  const qLevel=op.oq>=80?'Excellent':op.oq>=65?'Good':op.oq>=45?'Average':op.oq>=30?'Below Average':'Weak';
  const qColor=op.oq>=80?'var(--grn)':op.oq>=65?'var(--grn)':op.oq>=45?'var(--amb)':'var(--red)';

  const corpLine=s.corpOwner
    ?`<div class="sr"><span class="lb">Ownership</span><span class="vl" style="color:${s.corpColor||'#9ca3af'}">${s.corpName||'Corporate'}</span></div>`
    :`<div class="sr"><span class="lb">Ownership</span><span class="vl" style="color:var(--mut)">${rivalOwnershipLabel(s,G,isOwn)}</span></div>`;

  document.getElementById('ci-title').textContent=`${s.callLetters} — ${isOwn?'STATION INTEL':'COMPETITOR INTEL'}`;
  const intelStory=!isOwn?competitorIntelStoryLine(s):'';
  const ciLogo=cosmeticLogoThumbHtmlForStation(s,{larger:true});
  const ciHead=ciLogo?`<div style="display:flex;align-items:flex-start;gap:14px;margin-bottom:14px">
      ${ciLogo}
      <div style="flex:1;min-width:0;font-size:15px;color:var(--off);line-height:1.5">
        ${(typeof op.brand==='string'&&op.brand.trim())?`<span style="color:var(--wht);font-family:var(--fd);letter-spacing:1px;font-size:17px">&quot;${op.brand.trim()}&quot;</span><br>`:''}
        <span style="color:var(--mut)">${fmd.l||op.format}</span><span style="color:var(--mut)"> · </span><span style="color:var(--wht)">${signalLineForIntel(s)}</span>
      </div>
    </div>`:'';
  document.getElementById('ci-body').innerHTML=`
    ${ciHead}
    <div class="ibox" style="margin-bottom:14px">
      ${isOwn
        ?`<strong style="color:var(--grn)">Your station</strong> — Revenue and share below are from your books and ratings (no masking).`
        :isHumanRival
          ?`<strong style="color:var(--off)">Human opponent</strong> — Revenue, share, and talent pay match the shared game state (same sim you both play).`
          :`<strong style="color:var(--amb)">⚠ Trade Publication Estimates</strong> — Revenue figures are approximate. Share data is from Arbitron ratings.`}
    </div>
    <div class="ms2">
      <div class="msh">STATION PROFILE</div>
      <div class="sr"><span class="lb">Format</span><span class="vl">${fmd.l||op.format}</span></div>
      <div class="sr"><span class="lb">Signal</span><span class="vl">${signalLineForIntel(s)}</span></div>
      ${corpLine}
      <div class="sr"><span class="lb">On-Air Quality</span><span class="vl" style="color:${qColor}">${qLevel}</span></div>
    </div>
    <div class="ms2" style="margin-top:12px">
      <div class="msh">RATINGS & REVENUE</div>
      <div class="sr"><span class="lb">Overall Share</span><span class="vl amb">${pct(bookIntel?stationCardDisplayShare01(s):s.rat.share)}</span></div>
      <div class="sr"><span class="lb">AQH Listeners</span><span class="vl">${s.rat.aqh.toLocaleString()}</span></div>
      <div class="sr"><span class="lb">Trend</span><span class="vl" style="color:${trendColor}">${trend}</span></div>
      ${intelStory?`<div class="sr"><span class="lb">Likely story</span><span class="vl" style="font-size:14px;color:var(--mut);line-height:1.45">${intelStory}</span></div>`:''}
      <div class="sr"><span class="lb">${isOwn||isHumanRival?'Revenue / Period':'Est. Revenue / Period'}</span><span class="vl">${f$((isOwn||isHumanRival)?Math.round((s.fin?.rev||0)/50000)*50000:Math.round(estRev/50000)*50000)}</span></div>
      <div class="sr"><span class="lb">Core Demographic</span><span class="vl">${cohLabels[topCoh]||topCoh}</span></div>
    </div>
    <div class="ms2" style="margin-top:12px">
      <div class="msh">FORMAT POSITIONING</div>
      <div class="sr"><span class="lb">Drift</span><span class="vl">${strategyLine}</span></div>
      <div class="sr"><span class="lb">Direct Competition</span><span class="vl" style="font-size:14px">${compText}</span></div>
    </div>
    <div class="ms2" style="margin-top:12px">
      <div class="msh">COMPETITIVE POSTURE</div>
      <div class="sr"><span class="lb">Management Style</span><span class="vl">${s.pers?.l||'Unknown'}</span></div>
      <div class="sr"><span class="lb">Programming Investment</span><span class="vl" style="color:${(s.pers?.pi||0)>=0.07?'var(--grn)':(s.pers?.pi||0)>=0.04?'var(--amb)':'var(--mut)'}">
        ${(s.pers?.pi||0)>=0.07?'Heavy investor':((s.pers?.pi||0)>=0.04?'Moderate investment':'Minimal — coasting')}</span></div>
      <div class="sr"><span class="lb">Promotion Activity</span><span class="vl">${s.ops?.promo>20000?'Active campaigns':s.ops?.promo>5000?'Occasional':'Passive'}</span></div>
      <div class="sr"><span class="lb">Talent Retention</span><span class="vl">${(s.pers?.tr||0)>=0.75?'Locks in talent':((s.pers?.tr||0)>=0.55?'Standard contracts':'High turnover')}</span></div>
    </div>
    <div class="ms2" style="margin-top:12px">
      <div class="msh">ON-AIR TALENT ROSTER</div>
      ${htmlOnAirTalentRoster(s)}
    </div>
    ${(s._history||[]).length?`
    <div class="ms2" style="margin-top:12px">
      <div class="msh">STATION HISTORY <span style="color:var(--mut);font-size:13px;font-weight:400">(format, brand name, hires & departures, positioning, milestones)</span></div>
      ${renderHistoryRows(s._history||[], !isOwn)}
    </div>`:''}
  `;
  om('m-ci');
}

